-- Poems batch 419
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-1543','河南府张鼎勘头巾・金菊香','孙仲章','元','元曲','yuanqu','','[]','你道是安排着公吏唬他谁？(旦做揭囚帽科，云)嗨原来不是他。',119,'元曲/yuanqu.json','["你道是安排着公吏唬他谁？(旦做揭囚帽科，云)嗨原来不是他。", "(正末唱)则被这卖草的庄家瞒过了你。", "(丑云)哥哥，合酪熟了么？(张千云)早哩，早哩。", "(正末唱)若不是张孔目使些见识，怎能勾详察出虚实，(带云)王小二早无事了也。", "险些儿王小二一身亏。"]'),
('yuanqu-1544','河南府张鼎勘头巾・浪里来煞','孙仲章','元','元曲','yuanqu','','[]','合立通德政碑，减了些不平气。',59,'元曲/yuanqu.json','["合立通德政碑，减了些不平气。", "为头儿对府尹说详细，只教他欠身的立起银交椅。", "惊杀了两行公吏，凭时节须奏与圣人知。", "(众下)。"]'),
('yuanqu-1545','河南府张鼎勘头巾・双调/新水令','孙仲章','元','元曲','yuanqu','','[]','他痴心儿指望结姻缘，全不肯敬大尊养真修炼。',51,'元曲/yuanqu.json','["他痴心儿指望结姻缘，全不肯敬大尊养真修炼。", "那里也清闲真道本，无事散神仙。", "今日个枷锁身缠，落可便死无怨。"]'),
('yuanqu-1546','河南府张鼎勘头巾・乔牌儿','孙仲章','元','元曲','yuanqu','','[]','小人呵，非浪言，这公事何难辨。',31,'元曲/yuanqu.json','["小人呵，非浪言，这公事何难辨。", "把从头罪犯供明遍，请大人自发遣。"]'),
('yuanqu-1547','河南府张鼎勘头巾・雁儿落','孙仲章','元','元曲','yuanqu','','[]','眼见得一行人都在前，整整的三日内成招卷。',34,'元曲/yuanqu.json','["眼见得一行人都在前，整整的三日内成招卷。", "真不真看便知，赏不赏凭尊便。"]'),
('yuanqu-1548','河南府张鼎勘头巾・得胜令','孙仲章','元','元曲','yuanqu','','[]','呀，也只为人命事关天，因此上不厌细穷研。',70,'元曲/yuanqu.json','["呀，也只为人命事关天，因此上不厌细穷研。", "那一个漏网的何侥幸，那一个无辜的实可怜。", "我可也非专，只要他一点真情见，端的个无偏，恰便似一轮明镜悬。"]'),
('yuanqu-1549','河南府张鼎勘头巾・川拨棹','孙仲章','元','元曲','yuanqu','','[]','你、你、你，敢昧神天，将平人招罪愆。',51,'元曲/yuanqu.json','["你、你、你，敢昧神天，将平人招罪愆。", "还待要摆袖揎拳，假泼佯颠，一昧胡缠。", "谁知道到咱案前，有神通怎施展。"]'),
('yuanqu-1550','河南府张鼎勘头巾・七兄弟','孙仲章','元','元曲','yuanqu','','[]','仲先，向前，读文卷，明明是因奸杀死刘平远。',40,'元曲/yuanqu.json','["仲先，向前，读文卷，明明是因奸杀死刘平远。", "回头儿观觑女蝉娟，早唬的来胆破心惊战。"]'),
('yuanqu-1551','河南府张鼎勘头巾・梅花酒','孙仲章','元','元曲','yuanqu','','[]','这都是你弄威权，待积趱家缘，广置庄田，盛买丝绵，因此上葫芦提逞机变。',55,'元曲/yuanqu.json','["这都是你弄威权，待积趱家缘，广置庄田，盛买丝绵，因此上葫芦提逞机变。", "强打挣做质辨，护奸贼坏良善，臭名儿怎揩免。"]'),
('yuanqu-1552','河南府张鼎勘头巾・收江南','孙仲章','元','元曲','yuanqu','','[]','呀，现放着雪花银两是赃钱，把你个好心田翻做了恶心田。',248,'元曲/yuanqu.json','["呀，现放着雪花银两是赃钱，把你个好心田翻做了恶心田。", "今日个勘头巾分解这场冤。", "(府尹云)此一场冤事，多亏你问出。", "奏知圣人，加官赐赏，不负你之功也。", "(正末云)小人怎敢望赏。", "(唱)也只要全大人体面，方才得公平正直万民传。", "(府尹云)这桩事我尽知了也。", "一行人听我下断：奸夫淫妇市曹申明正典刑，将刘员外家私给付王小二管业。", "赵令史枉法成狱，杖一百流口外为民。", "老夫罚俸三个月，给赏张鼎。", "还再具表申奏叙功。", "加张鼎县令之职。", "(词云)则为荒淫妇恋色倾夫主，贪财汉枉法害平人。", "我秉正直再理旧文案。", "显的你清廉吏张鼎勘头巾。"]'),
('yuanqu-1553','中吕・满庭芳','谢应芳','元','元曲','yuanqu','','[]','神仙有无？安居华屋，即是蓬壶。',122,'元曲/yuanqu.json','["神仙有无？安居华屋，即是蓬壶。", "榴花也学红裙舞，燕雀喧呼。", "水晶盘馔供麟脯，珊瑚钩帘卷虾须。", "吹龙笛，击鼍鼓，年年初度，长日尽欢娱。", "横山翠屏，藏龙古井，走马长汀。", "四时花竹多风景，胜似丹青。", "好儿郎天生宁馨，好时节日见升平。", "氛埃静，年年寿星，光照望云亭。"]'),
('yuanqu-1554','杨氏女杀狗劝夫・仙吕/赏花时','萧德祥','元','元曲','yuanqu','','[]','知他是谁好游闲谁不良，谁起风波谁要强，瞒不过邻里众街坊。',78,'元曲/yuanqu.json','["知他是谁好游闲谁不良，谁起风波谁要强，瞒不过邻里众街坊。", "(孙大云)你是我的兄弟，你敢妆幺放党，不伏我打哩！(正末唱)俺哥哥道我妆幺放党，平白地揣与个罪名当。"]'),
('yuanqu-1555','杨氏女杀狗劝夫・幺篇','萧德祥','元','元曲','yuanqu','','[]','这的是自有傍人说短长，铜斗个家私你独自掌，咱须是一父母又不是两爷娘。',210,'元曲/yuanqu.json','["这的是自有傍人说短长，铜斗个家私你独自掌，咱须是一父母又不是两爷娘。", "(云)虫儿打街上过来，众人都道孙大郎与孙二似一个印合脱下来的。", "(柳、胡云)这厮胡说。", "你和俺哥哥一个印合里脱下来的，怎么你这般穷好嘴脸？(正末唱)怕不一般的俺模样，哥哥比兄弟多一片家狠心肠。", "(下)(孙大云)你两个兄弟少罪。", "(柳、胡做醉科，云)俺两个定害哥哥，改日再谢。", "(下)(旦云)员外，明日是清明节令，俺收拾下祭礼，请小叔叔一同上坟去咱。", "(同孙大下)。"]'),
('yuanqu-1556','杨氏女杀狗劝夫・仙吕/点绛唇','萧德祥','元','元曲','yuanqu','','[]','从亡化了双亲，便思营运。',31,'元曲/yuanqu.json','["从亡化了双亲，便思营运。", "寻资本，怎得分文？落可便刮土儿收拾尽。"]'),
('yuanqu-1557','杨氏女杀狗劝夫・混江龙','萧德祥','元','元曲','yuanqu','','[]','莫不是姓孙的无分？却将这精银响钞与了别人。',93,'元曲/yuanqu.json','["莫不是姓孙的无分？却将这精银响钞与了别人。", "教兄弟有家难奔，无处栖身。", "把我赶在破瓦窑中捱冻馁，教人道披着蒲席说家门。", "也不是我特故地把哥哥来恨，他、他、他不思忖一爷娘骨肉，却和我做日月参辰。"]'),
('yuanqu-1558','杨氏女杀狗劝夫・油葫芦','萧德祥','元','元曲','yuanqu','','[]','他骂道孙二穷厮煞是村，便待要赶出门，则着我自敦自逊自伤神。',112,'元曲/yuanqu.json','["他骂道孙二穷厮煞是村，便待要赶出门，则着我自敦自逊自伤神。", "现如今爹爹奶奶都亡尽，但愿得哥哥嫂嫂休嗔忿。", "为甚么单骂着我？你敢是错怨了人。", "(孙大云)我和你有甚么情分，你来见我？(正末唱)既是哥哥与兄弟无情分，却怎生等我上新坟？。"]'),
('yuanqu-1559','杨氏女杀狗劝夫・天下乐','萧德祥','元','元曲','yuanqu','','[]','哎，俺亲的元来则是亲，(云)嫂嫂，我不过去也，则怕哥哥打我。',84,'元曲/yuanqu.json','["哎，俺亲的元来则是亲，(云)嫂嫂，我不过去也，则怕哥哥打我。", "(唱)我为什么抽也波身，却倒褪，其实当不过那百般的心性狠。", "谁想他赤的金，白的银？但得俺哥哥欢喜呵便是十万分。"]'),
('yuanqu-1560','杨氏女杀狗劝夫・那吒令','萧德祥','元','元曲','yuanqu','','[]','哥哥道是不亲，我须是姓孙；哥哥道是不亲，孙虫儿上坟；哥哥道是不亲，这两个是甚人？(孙大云)这两个是我死生交的兄弟也，比你？(正末唱)哥哥你自忖量，你自评论，您直',204,'元曲/yuanqu.json','["哥哥道是不亲，我须是姓孙；哥哥道是不亲，孙虫儿上坟；哥哥道是不亲，这两个是甚人？(孙大云)这两个是我死生交的兄弟也，比你？(正末唱)哥哥你自忖量，你自评论，您直恁般爱富嫌贫。", "(孙大云)你这一万年不得长进的人！(柳、胡云)哥哥，这等人不长进，则待馋处着嘴，懒处着身，不拈了他去，待做甚么？(孙大云)小的每，拈这厮出去！兄弟每把盏，则管吃酒，不要采他。", "(正末云)你看他两个贼子帮着俺哥哥吃酒，好不快活也！(唱)。"]'),
('yuanqu-1561','杨氏女杀狗劝夫・鹊踏枝','萧德祥','元','元曲','yuanqu','','[]','他两个把盏儿吞，直吃的醉醺醺。',174,'元曲/yuanqu.json','["他两个把盏儿吞，直吃的醉醺醺。", "(孙大云)兄弟，好酒也。", "(柳、胡云)好酒！您兄弟都吃醉了也。", "(正末唱)吃的来东倒西歪，尽盘将军。", "(柳、胡做使酒科，云)孙二，我尽盘将军，是吃你的？没廉耻穷叫化弟子孩儿，今日俺家员外上坟，特特请我两个来，这所在只有我坐处，可有你站处？要你管我？(正末云)这里正是你家的。", "(唱)今日个到坟堂中来厮认，是你甚么娘祖代宗亲？。"]'),
('yuanqu-1562','杨氏女杀狗劝夫・寄生草','萧德祥','元','元曲','yuanqu','','[]','哥哥，我又不是庶出逃生子，须是你同胞共乳亲。',161,'元曲/yuanqu.json','["哥哥，我又不是庶出逃生子，须是你同胞共乳亲。", "俺哥哥出门来宾客相随趁，俺哥哥还家来侍女忙扶进，你兄弟破窑中忍冷耽愁闷；俺哥哥富家山野有人瞅，你兄弟贫居闹市无人问。", "(孙大云)我酒醉了也。", "有我两个兄弟扶的我家去。", "你这穷厮还敢无礼！你坟上来，拷折你两肷骨；到我家里来，我打你二百棍！(柳、胡云)如何？这所在那里有你来？(正末唱)。"]'),
('yuanqu-1563','杨氏女杀狗劝夫・金盏儿','萧德祥','元','元曲','yuanqu','','[]','我坟前去那场恨，还家去怒生嗔。',164,'元曲/yuanqu.json','["我坟前去那场恨，还家去怒生嗔。", "只待要各支支拷二百粗荆棍，咬牙根做出那恶精神。", "我待坟前去要敲折我两肷骨，还家去又要打断我脊梁筋。", "天那！我正是成人不自在，自在不成人。", "(云)哥哥将兄弟不认，信着两个贼子，打了我这一顿。", "我不敢到坟上添土去，我则往坟外拜一拜罢。", "祖宗少怪，孙虫儿无甚，只烧的一陌儿纸，一瓶儿酒，祭奠祖宗咱。", "(做拜科，唱)。"]'),
('yuanqu-1564','杨氏女杀狗劝夫・后庭花','萧德祥','元','元曲','yuanqu','','[]','这村醪酒刚半盆，纸钱儿值几文。',143,'元曲/yuanqu.json','["这村醪酒刚半盆，纸钱儿值几文。", "不是我将父母相拖逗，也是你歹孩儿穷孝顺。", "(孙大云)兄弟每慢慢的把盏者。", "将羊背子来做按酒快活吃。", "(柳、胡云)快些碎羊背子来吃，来吃！(正末唱)他那厢吃的醉醺醺，我这里嘴骨都喑喑的纳闷。", "哎！孙虫儿来上坟，几番家桃李春。", "他那厢笑呷呷倒玉樽，我这里哭啼啼谁动问？。"]'),
('yuanqu-1565','杨氏女杀狗劝夫・柳叶儿','萧德祥','元','元曲','yuanqu','','[]','难道我孙虫儿与他来不亲不近？见一阵儿旋风儿绕定荒坟，来时节旋的慢去时节旋的紧。',76,'元曲/yuanqu.json','["难道我孙虫儿与他来不亲不近？见一阵儿旋风儿绕定荒坟，来时节旋的慢去时节旋的紧。", "为甚么小的儿多贫困，大的儿有金银？爹爹奶奶呵，你可怎生来做的个一视同仁？。"]'),
('yuanqu-1566','杨氏女杀狗劝夫・赚煞','萧德祥','元','元曲','yuanqu','','[]','你便骂我一千场，便拷我三十顿，我则索狼吃幞头心儿自忍。',111,'元曲/yuanqu.json','["你便骂我一千场，便拷我三十顿，我则索狼吃幞头心儿自忍。", "若不是死了俺娘亲和父亲，这家私和你匹半停分。", "豹子的孟尝君，畅好是食客填门，可怎生把亲兄弟如同陌路人？哥哥，你有金有银，闪的我无投来无奔，则向这破窑中和月待黄昏。", "(下)。"]'),
('yuanqu-1567','杨氏女杀狗劝夫・正宫/端正好','萧德祥','元','元曲','yuanqu','','[]','黑黯黯冻云垂，疏刺剌寒风起，遍长空六出花飞。',41,'元曲/yuanqu.json','["黑黯黯冻云垂，疏刺剌寒风起，遍长空六出花飞。", "不停闲雪儿紧风儿急，这场冷着我无存济。"]'),
('yuanqu-1568','杨氏女杀狗劝夫・滚绣球','萧德祥','元','元曲','yuanqu','','[]','有那等富汉每，他道是压瘴气，下的是国家祥瑞，怎知俺穷汉每少衣无食。',136,'元曲/yuanqu.json','["有那等富汉每，他道是压瘴气，下的是国家祥瑞，怎知俺穷汉每少衣无食。", "我则见满天里飞磨旗，半空里下炮石，俺须是死无个葬身之地。", "只落得抱双肩紧把头低。", "我如今冒他大雪窑中去，抵多少袖得春风马上归，冻的我脚步儿难移。", "(云)嗨！那富汉每下着雪他倒欢喜，却不知俺穷汉每好苦楚也。", "(唱)。"]'),
('yuanqu-1569','杨氏女杀狗劝夫・倘秀才','萧德祥','元','元曲','yuanqu','','[]','有等人道宜扫雪烹茶在读书舍里，又道是宜羊羔烂醉在销金帐底，不知道他陶学士风流可也胜如党太尉？谁说起，寒江上一蓑归，那渔翁的冻馁。',64,'元曲/yuanqu.json','["有等人道宜扫雪烹茶在读书舍里，又道是宜羊羔烂醉在销金帐底，不知道他陶学士风流可也胜如党太尉？谁说起，寒江上一蓑归，那渔翁的冻馁。"]'),
('yuanqu-1570','杨氏女杀狗劝夫・滚绣球','萧德祥','元','元曲','yuanqu','','[]','似这雪呵教买臣懒负薪，似这雪呵教韩信怎乞食，似这雪呵郑孔目怎生迭配，晋孙康难点检书集。',126,'元曲/yuanqu.json','["似这雪呵教买臣懒负薪，似这雪呵教韩信怎乞食，似这雪呵郑孔目怎生迭配，晋孙康难点检书集。", "似这雪呵韩退之蓝关外马不前，孟浩然灞陵桥驴怎骑。", "似这雪呵教冻苏秦走投无计，王子猷也索访戴空回。", "似这雪呵汉袁安高眠竟日柴门闭，吕蒙正拨尽寒炉一夜灰，教穷汉海不死何为？。"]'),
('yuanqu-1571','杨氏女杀狗劝夫・呆骨朵','萧德祥','元','元曲','yuanqu','','[]','见哥哥迎着风冒着雪倒在当街睡，我只怕钟声尽被那巡夜的凌逼。',125,'元曲/yuanqu.json','["见哥哥迎着风冒着雪倒在当街睡，我只怕钟声尽被那巡夜的凌逼。", "虽然是背巷里悄促促没个行人，只怕雪地里冷冰冰冻坏了你。", "为甚么这头巾上泥来污？(云)哥哥，你上坟处也曾说来，(唱)却不道花压帽檐低，满身上雪渐消，(云)哥哥，你可又说来，(唱)这的是酒淹衫袖湿。"]'),
('yuanqu-1572','杨氏女杀狗劝夫・倘秀才','萧德祥','元','元曲','yuanqu','','[]','自古道胶漆的雷陈也不似你这般合意，鸡黍的范张也不似你这般为嘴。',66,'元曲/yuanqu.json','["自古道胶漆的雷陈也不似你这般合意，鸡黍的范张也不似你这般为嘴。", "你两个若没俺哥哥怕不饿杀你这颓。", "你两个撮捧着吃的醉如泥，却撇他在这里。"]'),
('yuanqu-1573','杨氏女杀狗劝夫・货郎儿','萧德祥','元','元曲','yuanqu','','[]','他道俺哥哥十分家沉醉，且吃些儿热汤热水。',80,'元曲/yuanqu.json','["他道俺哥哥十分家沉醉，且吃些儿热汤热水。", "俺哥哥直睡到红日三竿未起，可怎生近新来偏恁觉来疾？(孙大做醒科，云)好睡也。", "(正末唱)他酩子里纽回胭颈，没揣地转过身体。"]'),
('yuanqu-1574','杨氏女杀狗劝夫・脱布衫','萧德祥','元','元曲','yuanqu','','[]','我坐则坐战兢兢的，(孙大做起科，云)是甚么人吃我面哩？(正末唱)他醉则醉气丕丕的。',65,'元曲/yuanqu.json','["我坐则坐战兢兢的，(孙大做起科，云)是甚么人吃我面哩？(正末唱)他醉则醉气丕丕的。", "我这里低着头沉吟了半晌，他那里不转睛瞅了我一会。"]'),
('yuanqu-1575','杨氏女杀狗劝夫・太平令','萧德祥','元','元曲','yuanqu','','[]','吃的是亲嫂嫂的酒食，更过如吕太后的筵席。',128,'元曲/yuanqu.json','["吃的是亲嫂嫂的酒食，更过如吕太后的筵席。", "(云)嫂嫂，哥哥觉来了也，你说一句儿。", "(旦云)我且不说，看他怎的！(正末唱)嫂嫂，俺哥哥觉来你支持，\"我也不是个善的\"，唬得我一个脸描不的画不的，一双箸拿不的放不的，一口面吐不的咽不的，我便有万口舌头教我说个甚的？。"]'),
('yuanqu-1576','杨氏女杀狗劝夫・伴读书','萧德祥','元','元曲','yuanqu','','[]','白茫茫雪迷了人踪迹，昏惨惨雪闭了天和地。',65,'元曲/yuanqu.json','["白茫茫雪迷了人踪迹，昏惨惨雪闭了天和地。", "寒森森冻的我还窑内，滴溜溜绊我个合扑地。", "黑喽喽是谁人带酒醺醺醉，我、我、我定睛的觑个真实。"]'),
('yuanqu-1577','杨氏女杀狗劝夫・笑和尚','萧德祥','元','元曲','yuanqu','','[]','吓得我悠悠的魂魄飞，不寻思当街上正是哥哥睡。',152,'元曲/yuanqu.json','["吓得我悠悠的魂魄飞，不寻思当街上正是哥哥睡。", "直背的到家来不得口好气息，倒吃顿泼拳捶。", "哥哥也你瞒天地昧神祗，(做拜天科，云)今日打兄弟，明日骂兄弟，(唱)这的也是孙虫儿罪！(孙大云)这穷厮，你要拜死我哩！(打科，云)小的每将孙二拿到檐下大雪里跪着！(梅香作批末跪科)(正末云)哥哥，你好下的冻杀你兄弟也！。"]'),
('yuanqu-1578','杨氏女杀狗劝夫・叨叨令','萧德祥','元','元曲','yuanqu','','[]','则被这吸里忽刺的朔风儿那里好笃簌簌避，又被这失留屑历的雪片儿偏向我密蒙蒙坠，将这领希留合刺的布衫儿扯得来乱纷纷碎，将这双乞留曲律的胳膝儿罚他去直僵僵跪。',115,'元曲/yuanqu.json','["则被这吸里忽刺的朔风儿那里好笃簌簌避，又被这失留屑历的雪片儿偏向我密蒙蒙坠，将这领希留合刺的布衫儿扯得来乱纷纷碎，将这双乞留曲律的胳膝儿罚他去直僵僵跪。", "兀的不冻杀人也么哥！兀的不冻杀人也么哥！越惹他必丢匹搭的响骂儿这一场扑腾腾气。"]'),
('yuanqu-1579','杨氏女杀狗劝夫・耍孩儿','萧德祥','元','元曲','yuanqu','','[]','我怎生来不称俺哥哥意，嫂嫂也我也不曾犯十恶五逆。',100,'元曲/yuanqu.json','["我怎生来不称俺哥哥意，嫂嫂也我也不曾犯十恶五逆。", "这一个家缘儿都被你收拾，我挂口儿不曾口店题。", "现如今他强咱弱将咱打，可不道人善人欺天不欺，也是我自买到他憔悴，天那！我本是声冤叫屈，他听的又道我说是谈非。"]'),
('yuanqu-1580','杨氏女杀狗劝夫・二煞','萧德祥','元','元曲','yuanqu','','[]','我衷肠除告天，奈天高又不知，只落得捶胸跌足空流泪。',77,'元曲/yuanqu.json','["我衷肠除告天，奈天高又不知，只落得捶胸跌足空流泪。", "我过一冬两三层单布权遮冷，捱一日十二个时辰常忍饥，哥哥行并不敢半句儿求于济，他见我早揎拳捋袖，努目撑眉。"]'),
('yuanqu-1581','杨氏女杀狗劝夫・四煞','萧德祥','元','元曲','yuanqu','','[]','你不是我呵你明日怎觑人？你不是我呵你今朝做醉鬼。',86,'元曲/yuanqu.json','["你不是我呵你明日怎觑人？你不是我呵你今朝做醉鬼。", "被闲人剥了你新衣袂，洞房中把嫂嫂闲愁杀，巡铺坦把哥哥高吊起，冻的你刚存这一口儿气，怎不寻那两个无徒说话，只管把你兄弟禁持？。"]'),
('yuanqu-1582','杨氏女杀狗劝夫・煞尾','萧德祥','元','元曲','yuanqu','','[]','你无过是胸腰上撞我几头，脖项上打我几捶，忍下的就将我冻剥剥跪在檐前地。',57,'元曲/yuanqu.json','["你无过是胸腰上撞我几头，脖项上打我几捶，忍下的就将我冻剥剥跪在檐前地。", "嫂嫂也这须是我压背他来家可也落得的。", "(下)。"]'),
('yuanqu-1583','杨氏女杀狗劝夫・南吕/一枝花','萧德祥','元','元曲','yuanqu','','[]','稀剌剌草户扃，破杀杀砖窑静。',79,'元曲/yuanqu.json','["稀剌剌草户扃，破杀杀砖窑静。", "俺这里春光元不到，人迹罕曾经。", "万籁无声，是甚么响息飒惊咱醒？透着些影依微何处灯，(做听科)却原来是伴独坐皓月澄澄，搅孤眠西风泠泠。"]'),
('yuanqu-1584','杨氏女杀狗劝夫・梁州第七','萧德祥','元','元曲','yuanqu','','[]','我如今穷范丹无钱怎了，便教他赛陈抟也有梦难成。',341,'元曲/yuanqu.json','["我如今穷范丹无钱怎了，便教他赛陈抟也有梦难成。", "积渐的害得忧成病。", "一递里暗昏昏眼前花发，一递里古鲁鲁肚里雷鸣。", "这孙虫儿一身忍饿，教孙大郎万代留名。", "我和你本-个父养娘生，又不是蜾赢螟蛉。", "怎么无半年欺负了我五场十场，我每日家嗟叹了千声万声，那一夜不哭到二更三更。", "(孙大同旦上，云)大嫂，你去叫门，我有甚脸儿见兄弟那。", "(旦云)你不叫，我叫门咱。", "(叫科，云)孙二，开门来！(正末唱)是谁人叫门那声？(旦云)快些！(正末唱)这声音不似个男儿应。", "(旦云)孙二，你开门咱，是你嫂嫂叫门哩！(正末唱)元来我嫂嫂门前等，他是个妇人家无烛从来不夜行，我出门去审问个分明。", "(云)嫂嫂，更深半夜，你一个妇人家，这早晚天道，也不是你来的时候。", "(旦云)不妨，我是你亲嫂嫂，怕做甚么？(正末云)我孙虫儿呵，(唱)。"]'),
('yuanqu-1585','杨氏女杀狗劝夫・隔尾','萧德祥','元','元曲','yuanqu','','[]','我常时有命如无命，怎好又厮罗惹无情做有情。',141,'元曲/yuanqu.json','["我常时有命如无命，怎好又厮罗惹无情做有情。", "(云)不争我开门去，教嫂嫂入来，这礼上就不是了。", "教俺哥哥知道又是打。", "(旦云)孙二快开门，你哥哥有事着我叫你来。", "(正末唱)俺哥哥便今日有事呵明日旋折证，嫂嫂你这搭儿莫不错行。", "(旦云)我不是错行哩。", "(正末唱)前者得过承，是我那滴水檐前受了的冷。"]'),
('yuanqu-1586','杨氏女杀狗劝夫・骂玉郎','萧德祥','元','元曲','yuanqu','','[]','你怀中倚恃着财丰盛，动不动和人争，不登登按不住杀人性。',44,'元曲/yuanqu.json','["你怀中倚恃着财丰盛，动不动和人争，不登登按不住杀人性。", "若是被告发，被擒拿，怕不要偿命？。"]'),
('yuanqu-1587','杨氏女杀狗劝夫・采茶歌','萧德祥','元','元曲','yuanqu','','[]','嫂嫂呵可不你知情，哥哥呵可不你当刑？(云)哥哥嫂嫂，你两口儿怕么？(孙大云)可知怕哩。',123,'元曲/yuanqu.json','["嫂嫂呵可不你知情，哥哥呵可不你当刑？(云)哥哥嫂嫂，你两口儿怕么？(孙大云)可知怕哩。", "(正末云)要饶么？(孙大云)可知要饶哩。", "(正末云)哥哥嫂嫂，休惊莫怕，我逗你耍哩！(唱)我替你把死尸骸送出汴梁城，随他拖到官中加拷打，我也拚的把杀人公事独招承。"]'),
('yuanqu-1588','杨氏女杀狗劝夫・牧羊关','萧德祥','元','元曲','yuanqu','','[]','恰便似醉汉当街上睡，死狗儿般门外停。',122,'元曲/yuanqu.json','["恰便似醉汉当街上睡，死狗儿般门外停。", "(云)嫂嫂，则怕天明了，待我背他出去。", "(做背科，唱)我背则背手似捞铃，怎么的口边头拔了七八根家狗毛，脸儿上拿了三四个狗毛。", "这厮死时节定触犯了刀砧杀，醉时节敢透入在喂猪坑。", "既不沙怎闻不的十分臭，当不的他一阵腥。"]'),
('yuanqu-1589','杨氏女杀狗劝夫・幺篇','萧德祥','元','元曲','yuanqu','','[]','这等人是狗相识，这等人有甚么狗弟兄。',95,'元曲/yuanqu.json','["这等人是狗相识，这等人有甚么狗弟兄。", "这等人狗年间发迹来峥嵘。", "这等人脱的是狗气狗声，这等人使的是狗心狗行。", "有甚么狗肚肠般能报主，有甚么狗衣饭泼前程？是一个啜狗尾的乔男女，是一个拖狗皮的贼丑生。"]'),
('yuanqu-1590','杨氏女杀狗劝夫・煞尾','萧德祥','元','元曲','yuanqu','','[]','那的是添茶添酒的枯干井，那的是填帛填金的没底坑。',187,'元曲/yuanqu.json','["那的是添茶添酒的枯干井，那的是填帛填金的没底坑。", "你觑当着这说谎精，那虚脾，那浅情；那过后，那光景；胡支吾，假奉承。", "他装厮趁，他装厮挺。", "吃饭处，白厮捱，买酒处，白厮逞；做事处，干厮哄；爱女处，干厮迎。", "(孙大云)从今以后，我再也不睬那两个贼子了。", "(旦云)我记的古诗有云：荆树有花兄弟乐，员外这个才是。", "(正末唱)嫂嫂，你说甚的田氏三荆？只怕你跳出七代先灵也将他来劝不省。", "(同下)。"]'),
('yuanqu-1591','杨氏女杀狗劝夫・中吕/粉蝶儿','萧德祥','元','元曲','yuanqu','','[]','没半盏茶时，求和到两回三次。',61,'元曲/yuanqu.json','["没半盏茶时，求和到两回三次。", "你枉做个顶天立地的男儿，教那厮越妆模越作势，尽场儿调刺。", "他道你怕见官司，拿着个天大来杀人公事。"]'),
('yuanqu-1592','杨氏女杀狗劝夫・红绣鞋','萧德祥','元','元曲','yuanqu','','[]','那告状人指陈事实，都是些扶同捏合的虚词。',125,'元曲/yuanqu.json','["那告状人指陈事实，都是些扶同捏合的虚词。", "现如今告状的全不似古贤师，这般家闲雕刺。", "他待放着暗刀儿，在、在、在我根前怎的使？(柳、胡云)这就是孙员外的亲兄弟，他两个合谋杀人哩。", "(孤云)你怎生谋杀了人？你与我从实招来！(正末云)相公听小人说一遍咱。", "(唱)。"]'),
('yuanqu-1593','杨氏女杀狗劝夫・石榴花','萧德祥','元','元曲','yuanqu','','[]','他两个是汴梁城里谎乔厮，与孙员外甚宗支？只待要兴心啜赚俺泼家私，每日家哄的去花街酒肆，品竹调丝。',89,'元曲/yuanqu.json','["他两个是汴梁城里谎乔厮，与孙员外甚宗支？只待要兴心啜赚俺泼家私，每日家哄的去花街酒肆，品竹调丝。", "被咱家说破他行上，因此上索垢寻疵。", "他道俺哥哥公门踪迹何曾至，平空的揣与这个罪名儿。"]'),
('yuanqu-1594','杨氏女杀狗劝夫・斗鹌鹑','萧德祥','元','元曲','yuanqu','','[]','他、他、他似这般钻懒帮闲，便是他封妻荫子。',77,'元曲/yuanqu.json','["他、他、他似这般钻懒帮闲，便是他封妻荫子。", "他讲不得《毛诗》，念不得《孟子》，无非是温习下坑人状本儿，动不动掐人的嗓子。", "哎，这好歹斗的书生，好放刁的贼子！。"]'),
('yuanqu-1595','杨氏女杀狗劝夫・上小楼','萧德祥','元','元曲','yuanqu','','[]','我说的丁一确二，你说的巴三览四。',73,'元曲/yuanqu.json','["我说的丁一确二，你说的巴三览四。", "使不着你癞骨顽皮，逞的精神，说的强词，公厅上捱杖子，胡攀乱指。", "(云)到这里只有个法子，(唱)哎，使不的你咬文嚼字。"]'),
('yuanqu-1596','杨氏女杀狗劝夫・幺篇','萧德祥','元','元曲','yuanqu','','[]','活时节一处活，死时节一处死。',649,'元曲/yuanqu.json','["活时节一处活，死时节一处死。", "咱两个协罗嘶钻、尾毛厮结、打会官司。", "一任你百样儿，伶牙俐齿，怎知大人行会断的正没头公事。", "(孤云)这桩事不打不招。", "左右，拿这大的下去。", "好生打着。", "(孙大云)小的是个知法度的，怎敢杀人？(正末云)不干俺哥哥的事，这件事都是小人做来。", "(孤云)既是他认了，左右，拿小的下去打着者。", "(旦冲上，云)相公停嗔息怒，暂罢虎狼之威。", "这件事也不干孙大事，也不干孙二事，都是小媳妇儿做下来的。", "(孤云)兀那妇人！这件事你说的是呵，我与你问个妇人有事，罪坐夫男，拣一个轻省的罪名与他；若说的不是呵，我就活活的敲死了也。", "(旦云)相公，从来人命关天关地，岂可没个尸亲来告，要这两个光棍与他索命？只因俺这孙家，汴京居住，长的孙大，叫做孙荣；次的孙二，叫做孙华。", "本是共乳同胞的亲兄弟，自小里父母早亡。", "这孙大恃强，将孙二赶在城南破瓦窑中居住，每日着这两个帮闲钻懒，搬的俺兄弟不和。", "这两个教孙大无般不作，无般不为，破坏了俺家私。", "孙大但见兄弟，便是打骂，妾身每每劝他，只是不省。", "妾身曾发下一个大愿，要得孙大与孙二两个相和了时，许烧十年夜香。", "偶然这一晚烧香中间，看见一只犬打香卓根前过来，妾身问知此犬是隔壁王婆家的。", "妾身就他家里，与了五百个钱，买将来到家，将此犬剁了头尾，穿了人衣帽，撇在后门首。", "孙大带酒还家来见了。", "问妾身道：后门口是谁杀了一个人，你可知么？妾身回言不知道。", "当夜教孙大唤柳隆卿、胡子转替背出去，两个百般推辞，只不肯来。", "我到窑中唤的孙二来，教他背将出去，埋在汴河堤上。", "怕相公不信，现放着王婆是个证见。"]'),
('yuanqu-1597','杨氏女杀狗劝夫・十二月','萧德祥','元','元曲','yuanqu','','[]','这公事非同造次，望相公台鉴寻思。',50,'元曲/yuanqu.json','["这公事非同造次，望相公台鉴寻思。", "俺哥哥花枝般媳妇，掌着那铜斗家私。", "这便是情由终始，有甚的过犯公私？。"]'),
('yuanqu-1598','杨氏女杀狗劝夫・尧民歌','萧德祥','元','元曲','yuanqu','','[]','就官厅上拖出那狗皮儿，这的是俺嫂嫂暗把计谋施。',69,'元曲/yuanqu.json','["就官厅上拖出那狗皮儿，这的是俺嫂嫂暗把计谋施。", "劝哥哥放开怀抱莫嗟咨，那王婆须是俺的正名师。", "相公阿你恩也波慈，从来不受私，早分解了这跷蹊事。"]'),
('yuanqu-1599','杨氏女杀狗劝夫・尾煞','萧德祥','元','元曲','yuanqu','','[]','俺如今剔下子这骨和筋，割掉了这肉共脂。',46,'元曲/yuanqu.json','["俺如今剔下子这骨和筋，割掉了这肉共脂。", "则着他背狗皮号令在长街市，也等那一辈儿狗党狐朋做样子。"]'),
('yuanqu-1600','立成汤伊尹耕莘・仙吕/赏花时','郑光祖','元','元曲','yuanqu','','[]','今日个奉敕亲蒙圣帝差，(东华仙云)降生人间，辅佐于清朝，尔为仕途良相也。',149,'元曲/yuanqu.json','["今日个奉敕亲蒙圣帝差，(东华仙云)降生人间，辅佐于清朝，尔为仕途良相也。", "(正末唱)待教我谪降尘寰做将相才。", "(东华仙云)则今日离了紫府仙班，便索长行也。", "(正末唱)拜辞了玉阙共金阶，离了这仙坛世界。", "(东华仙云)上帝着你出离仙骨，托化凡胎，为世间辅弼之臣也。", "(正末唱)待教我出仙骨我今日去托凡胎。", "(下)。"]'),
('yuanqu-1601','立成汤伊尹耕莘・仙吕/点绛唇','郑光祖','元','元曲','yuanqu','','[]','混元始宇宙洪荒，二仪四象。',31,'元曲/yuanqu.json','["混元始宇宙洪荒，二仪四象。", "天差降，五帝三皇，安排定百二山河壮。"]'),
('yuanqu-1602','立成汤伊尹耕莘・混江龙','郑光祖','元','元曲','yuanqu','','[]','把乾坤开创，教民耕种定纲常。',71,'元曲/yuanqu.json','["把乾坤开创，教民耕种定纲常。", "疏河源功高大禹，行庠序重德尧王。", "那其间尧用一夔兴礼乐，公孙甲子论阴阳。", "端的便察地理占天象，留心于社稷，运用于穹苍。"]'),
('yuanqu-1603','立成汤伊尹耕莘・油葫芦','郑光祖','元','元曲','yuanqu','','[]','想当日至德仁明掌万邦，用贤良定四方。',77,'元曲/yuanqu.json','["想当日至德仁明掌万邦，用贤良定四方。", "用天之道理之常，弘敷五典无偏党。", "劳心尽思行温让，致令的四时和雨露均，八方宁士庶康，人心悦天意同和畅，因此上万国尽来降。"]'),
('yuanqu-1604','立成汤伊尹耕莘・天下乐','郑光祖','元','元曲','yuanqu','','[]','那其间四野桑麻禾稼穰，百姓每讴歌将天祭享。',53,'元曲/yuanqu.json','["那其间四野桑麻禾稼穰，百姓每讴歌将天祭享。", "军无战争民户昌，顺民心减税科，应天心绝逸荒，端的是普天下尊圣皇。"]'),
('yuanqu-1605','立成汤伊尹耕莘・醉中天','郑光祖','元','元曲','yuanqu','','[]','他每都争急言情状，语句意慌张。',142,'元曲/yuanqu.json','["他每都争急言情状，语句意慌张。", "(伴哥云)老员外，一个小小婴孩，在多年的空桑树里头里。", "(正末唱)他道是年小孩童在古树里藏。", "(王留云)特来报与老员外知道，并不虚言。", "(正末唱)更说道并不言虚诳。", "我这里心中暗想，今日个事从天降。", "(伴哥云)谁敢不报与老员外知道。", "(正末唱)一一的诉真情细说行藏。"]'),
('yuanqu-1606','立成汤伊尹耕莘・金盏儿','郑光祖','元','元曲','yuanqu','','[]','你看他青渗渗秀眉长，高耸耸俊鼻梁。',67,'元曲/yuanqu.json','["你看他青渗渗秀眉长，高耸耸俊鼻梁。", "拳挛着手脚精神爽，潜形古树在村庄。", "生的来清奇面似雪，肤体白如霜。", "却怎么不教存画阁，莫不他举意隐空桑。"]'),
('yuanqu-1607','立成汤伊尹耕莘・醉中天','郑光祖','元','元曲','yuanqu','','[]','他生的神彩非凡像，美貌更端详。',144,'元曲/yuanqu.json','["他生的神彩非凡像，美貌更端详。", "莫不是谪降天宫坠下方？不由我心欢畅。", "(李老人云)此子生的眉清目朗也。", "(正末唱)真乃是眉清目朗，可怎生流落在村庄深巷？他那里叫吖吖两泪成行。", "(云)王留、伴哥，好好的抱到家中，便寻觅奶母，好生将养着，也是好的勾当。", "(李老人云)此子若长成，必然贵重也。", "(正末唱)。"]'),
('yuanqu-1608','立成汤伊尹耕莘・尾声','郑光祖','元','元曲','yuanqu','','[]','你与我诚心儿好温存，用意相将傍。',99,'元曲/yuanqu.json','["你与我诚心儿好温存，用意相将傍。", "看寒暑温凉作养，乳哺依时要忖量，另立所避风寒大厦高堂。", "莫张荒，等的他那气血方刚，那其间着志求贤将师道访，习练的才高智广，文强武壮，恁时节扶持王业尽忠良。", "(同老人下)。"]'),
('yuanqu-1609','立成汤伊尹耕莘・中吕/粉蝶儿','郑光祖','元','元曲','yuanqu','','[]','想当日挚逝封尧，善能行圣人之道，以全图禹任皋陶。',55,'元曲/yuanqu.json','["想当日挚逝封尧，善能行圣人之道，以全图禹任皋陶。", "他每都应天心，行正法，将黎民抚教。", "自履癸临朝，运糟粕信从贪暴。"]'),
('yuanqu-1610','立成汤伊尹耕莘・醉春风','郑光祖','元','元曲','yuanqu','','[]','可怜见致涂炭庶和民，适灾危禽共鸟。',50,'元曲/yuanqu.json','["可怜见致涂炭庶和民，适灾危禽共鸟。", "见如今天乙修德有谁如，端实是少，少。", "上应天心，外施仁义，内存纯孝。"]'),
('yuanqu-1611','立成汤伊尹耕莘・迎仙客','郑光祖','元','元曲','yuanqu','','[]','我则待习农务耕绿野，趁农时效锄刨。',125,'元曲/yuanqu.json','["我则待习农务耕绿野，趁农时效锄刨。", "(余章云)似这等不肯进身，哥哥高见为何？(正末唱)这的是老生涯养拙一世了。", "(余章云)似此可是怎生也？(正末唱)一任待卧烟霞，眠绿草，醒来时浊酒相邀。", "(余章云)哥哥差矣。", "似此怎么了得身事也。", "(正末唱)这的是伊尹穷安乐。"]'),
('yuanqu-1612','立成汤伊尹耕莘・斗鹌鹑','郑光祖','元','元曲','yuanqu','','[]','着我受束带朝章，怎发付这儒冠布袄？(汝方云)更有驷马高车，请升车到朝中，加升官职也。',95,'元曲/yuanqu.json','["着我受束带朝章，怎发付这儒冠布袄？(汝方云)更有驷马高车，请升车到朝中，加升官职也。", "(正末唱)摆列下驷马高车，奉天建爵。", "又不曾燮理阴阳将鼎鼐调，退夷狄边塞遥。", "拜辞了草舍茅庵，受用的兰堂画阁。"]'),
('yuanqu-1613','立成汤伊尹耕莘・上小楼','郑光祖','元','元曲','yuanqu','','[]','我无那擎天动作，又无那惊人才调。',141,'元曲/yuanqu.json','["我无那擎天动作，又无那惊人才调。", "(汝方云)据贤士经济之才，俊伟之器，堪为将相也。", "(正末唱)我不会辨别星斗，嗅土闻风，云雾低高。", "(汝方云)贤士疾忙而起，贤臣遇明主而出。", "正谓此也。", "(正末唱)止不过播种耕耘，力习农务，攻锄田稻。", "(汝方云)见有丹诏敕文在此。", "(正末唱)怎消的紫泥宣一封丹诏。"]'),
('yuanqu-1614','立成汤伊尹耕莘・幺篇','郑光祖','元','元曲','yuanqu','','[]','你着我忙除了儒士冠，疾脱了粗布袍。',170,'元曲/yuanqu.json','["你着我忙除了儒士冠，疾脱了粗布袍。", "(汝方云)左右伺候，头答摆的齐整者！贤士请登程途。", "(正末唱)他将水罐银瓶，伞盖头答，摆列周遭。", "(汝方云)贤士，你穿用紫袍金带，骑坐着那白马红缨，端的是显威严也。", "(正末唱)你道是白马红缨，紫袍金带，施威显耀。", "(汝方云)贤士为官，贤士的妻房情受五花官诰，为贤德夫人也。", "(正末云)荆布之妇。", "(唱)怎消受五花官诰。"]'),
('yuanqu-1615','立成汤伊尹耕莘・耍孩儿','郑光祖','元','元曲','yuanqu','','[]','看一番揩磨日月兴宗庙，拣士马驱兵战讨。',96,'元曲/yuanqu.json','["看一番揩磨日月兴宗庙，拣士马驱兵战讨。", "经纶天地定皇朝，保持的社稷坚牢。", "凋和那盐梅燮理阴阳顺，致令的天地和同风雨调。", "休想我污婪矫权狡，托赖着一人有庆，稳情取万姓歌谣。", "(云)大人，俺去来。", "(唱)。"]'),
('yuanqu-1616','立成汤伊尹耕莘・尾声','郑光祖','元','元曲','yuanqu','','[]','慑伏的四夷朝帝京，八蛮贺圣朝。',32,'元曲/yuanqu.json','["慑伏的四夷朝帝京，八蛮贺圣朝。", "遍乾坤丰稔黎民乐太平表。", "(同下)。"]'),
('yuanqu-1617','立成汤伊尹耕莘・正宫/端正好','郑光祖','元','元曲','yuanqu','','[]','再不见青霭霭柳阴浓，高耸耸山叠翠。',46,'元曲/yuanqu.json','["再不见青霭霭柳阴浓，高耸耸山叠翠。", "乐耕锄拽耙扶犁，我如今受皇宣着我居官位，端的也衣紫身荣贵。"]'),
('yuanqu-1618','立成汤伊尹耕莘・滚绣球','郑光祖','元','元曲','yuanqu','','[]','我则见头答左右随，公人前后围。',115,'元曲/yuanqu.json','["我则见头答左右随，公人前后围。", "慢腾腾缓行着骏骑，喜孜孜列鼎而食。", "辅佐的中华社稷安，揩磨的乾坤日月辉。", "展经纶补完天地，尽忠减心若金石。", "(汝方云)聘贤士入朝，可也不轻也。", "(正末唱)凭着这两支手掌扶王业，稳情着百二山河壮帝基，四海传檄。"]'),
('yuanqu-1619','立成汤伊尹耕莘・倘秀才','郑光祖','元','元曲','yuanqu','','[]','我本是田野中愚浊村鄙。',275,'元曲/yuanqu.json','["我本是田野中愚浊村鄙。", "(仲虺云)特请贤士辅于公子，着贤士权临八府，印掌三台，为柱石之臣也。", "(正末唱)怎做的相府内贤良宰职。", "(方伯云)据贤士之才德，堪可为国家柱石也。", "(正末唱)道我是立地擎天大柱石。", "(汝方云)因贤士超越今古，智识高明，特赐象简紫衣，则是着贤士尽忠诚辅弼也。", "(正末唱)则这白象简，紫罗衣。", "(方伯云)全凭你高才大手，安邦定国也。", "(正末唱)待教我安邦定国。", "(汝方云)贤士，今欲兴师，未彻兵家用事，贤士展神鬼不测之机，兴一旅之师，辅佐公子，以成大事。", "(正末云)小生是一扶犁叟，岂知兵家之事也！(仲虺云)论贤士之智能，觑夏桀有何难哉！(正末唱)。"]'),
('yuanqu-1620','立成汤伊尹耕莘・滚绣球','郑光祖','元','元曲','yuanqu','','[]','止不过乐山林景色奇，向桑麻禾稼畦。',247,'元曲/yuanqu.json','["止不过乐山林景色奇，向桑麻禾稼畦。", "(方伯云)休谦辞，久已知贤士之能，胸怀妙用，腹隐神机也。", "(正末唱)你着我帅军卒运谋施智。", "(方伯云)贤士，用人之际，正当展布大才也。", "(正末唱)你着我定乾坤施展兵机。", "(方伯云)俺这里有军兵百万，安下营寨，枪林剑洞，如铁桶相似，则是少个运谋的人，全凭贤士为之也。", "(正末唱)你道是齐臻臻的摆开阵势，明晃晃列着剑戟，闹垓垓密排着军队，映穹苍号带旌旗。", "(仲虺云)贤士，他那里兵势可也不小，亦有定计铺谋的将帅。", "(正末唱)者莫他坐中设下千条计，岂不闻阃外将军八面威，智勇无及。"]'),
('yuanqu-1621','立成汤伊尹耕莘・呆骨朵','郑光祖','元','元曲','yuanqu','','[]','向垓心战讨驱征骑，喊声高戈甲排齐。',94,'元曲/yuanqu.json','["向垓心战讨驱征骑，喊声高戈甲排齐。", "(方伯云)怎生下寨安营，排兵布阵，贤士必有奇正方略也。", "(正末唱)我与你兵列八方，军分四壁，依地势排军队，觑方位安形势，这的是行兵立阵谋，先识那临敌攻战机。"]'),
('yuanqu-1622','立成汤伊尹耕莘・脱布衫','郑光祖','元','元曲','yuanqu','','[]','统雄兵劈面相持，驱貔虎扯鼓夺旗。',32,'元曲/yuanqu.json','["统雄兵劈面相持，驱貔虎扯鼓夺旗。", "恶狠狠扬威显武，气昂昂奋扬威势。"]'),
('yuanqu-1623','立成汤伊尹耕莘・梁州','郑光祖','元','元曲','yuanqu','','[]','阵列八门生最奇，为将须知。',33,'元曲/yuanqu.json','["阵列八门生最奇，为将须知。", "军卒未饭帅休食，以此能伏制，甘苦共同宜。"]'),
('yuanqu-1624','立成汤伊尹耕莘・幺篇','郑光祖','元','元曲','yuanqu','','[]','怒无加责欢无会，士无衣将与重衣。',141,'元曲/yuanqu.json','["怒无加责欢无会，士无衣将与重衣。", "这的是恤士功，安心计。", "能明此义，万众总归依。", "(方伯云)到来日某同贤士亲临战阵，与他交锋，务要剪伐大夏也。", "(正末云)论公子如此大德，将士效力，小生少助微智，临阵自有奇谋，量他到的那里也！(汝方云)此一去必然成功，皆赖贤士之能也。", "(正末云)放心。", "(唱)。"]'),
('yuanqu-1625','立成汤伊尹耕莘・尾声','郑光祖','元','元曲','yuanqu','','[]','到来日安营下寨施才智，布阵排兵显武威。',458,'元曲/yuanqu.json','["到来日安营下寨施才智，布阵排兵显武威。", "骨刺剌列绣旗，闹垓垓战马嘶。", "舍死忘生恶战敌，定乱除危攻夏畿。", "辅佐坚心立帝基，肱股忠良四海知。", "龙虎风云同际会，严定这一统乾坤万万里。", "(下)(方伯云)贤士去了也。", "(汝方云)他此去小歇小歇。", "(方伯云)人马已点就了也，左右，与我唤将费昌来者。", "(卒子云)理会的。", "(做唤科，云)费昌安在？(外扮费昌上，云)胆气冲冲智有余，过人骁勇有谁知。", "文雄武壮能攻守，定乱除危大丈夫。", "某乃费昌是也，公子部下都护将军。", "今因大夏失政兴兵，与公子拒敌，公子令汝方将玉帛征聘了伊尹来。", "正在帅府戟门听令，公子呼唤，须索走一遭去。", "可早来到也。", "小校报复去，道有费昌来了也。", "(卒子云)理会的。", "(报科，云)喏！报的方伯得知，有费将军来了也。", "(方伯云)着他过来。", "(卒子云)理会的，过去。", "(费昌见科，云)公子呼唤小将，那厢使用？(方伯云)费昌，如今夏国兴兵，与某争战，你统大兵前去拒敌。", "某新聘了伊尹贤士来，听他军前支拨。", "剪大夏，伐履癸，不可怠慢，小心奋勇，则要成功，不可怠忽。", "(费昌云)得令！统领大势人马，与他拒敌，走一遭去。"]'),
('yuanqu-1626','立成汤伊尹耕莘・仙吕/赏花时','郑光祖','元','元曲','yuanqu','','[]','俺这里耀武扬威胆气雄，勒马横枪豪气冲。',89,'元曲/yuanqu.json','["俺这里耀武扬威胆气雄，勒马横枪豪气冲。", "(躲入巢云)赶的慌怎么了？(费昌赶科，云)那里去！(陶去南云)不好了，赶的我马不停蹄，我死也！(正末唱)凭着我方略立奇功，使不着你军雄将勇。"]'),
('yuanqu-1627','立成汤伊尹耕莘・雁儿落','郑光祖','元','元曲','yuanqu','','[]','你道是立江山真肱股。',93,'元曲/yuanqu.json','["你道是立江山真肱股。", "(殿头官云)论你之功，如擎天玉柱，架海金梁也。", "(正末唱)又道我扶社稷为梁柱。", "(殿头官云)为臣者尽忠良于国，堪比良金美玉也。", "(正末唱)你道我尽忠心如美金，布德政如白玉。"]'),
('yuanqu-1628','立成汤伊尹耕莘・得胜令','郑光祖','元','元曲','yuanqu','','[]','呀！你道我战讨善机谋。',385,'元曲/yuanqu.json','["呀！你道我战讨善机谋。", "(殿头官云)真个是剑呼风雨降，笔走鬼神惊，识尽军机枢要也。", "(正末唱)你道我笔下见赢输。", "(殿头官云)马到处剪除暴夏。", "(正末唱)你道我剪除残暴夏。", "(殿头官云)一阵成功，辅天乙位，都于毫邑也。", "(正末唱)你道我平扶立帝都。", "(殿头官云)论功行赏，图形麟阁。", "标入功劳簿，遗芳万年。", "美哉伊尹也！(正末唱)这功绩纤需，要将我标入功劳簿。", "论谋略荒疏，怎消的凌烟阁上图。", "(殿头官云)你众官望阙跪者，听圣人之命；都只为夏履癸不道无仁，发顽狠暴虐黎民。", "是处处人心嗟怨，使鸟兽不得安存。", "方伯怒起兵征讨，聘伊尹运智行军。", "四下里攻围鏖战，仗神机得胜全赢。", "收取了州城国邑，散仓粮府库金银。", "放履癸鸣条修德，明正典责罚奸人。", "今日个论功行赏，赐官爵以励忠臣。", "伊尹升太师左相，仲虺升太师右丞，汝方与进阶二品，费昌为天下总兵。", "赐重爵身登八位，列簪缨光显门庭。", "论功次加官赐赏，一齐的拜谢天恩。"]'),
('yuanqu-1629','般涉调・耍孩儿咏鼓','睢玄明','元','元曲','yuanqu','','[]','乐官行径咱参破，全仗着声名过活。',77,'元曲/yuanqu.json','["乐官行径咱参破，全仗着声名过活。", "且图时下养皮囊，隐居在安乐之窝。", "咚咚的打得我难存济，紧紧的棚扒的我没奈何。", "习下这等乔功课，搬得人赏心乐事，我正是鼓腹讴歌。"]'),
('yuanqu-1630','五煞・开山时挂些纸钱，庆棚时得些赏贺，争构阑把我来妆标垛。有我时','睢玄明','元','元曲','yuanqu','','[]','满棚和气登时起，一分提钱分外多。',36,'元曲/yuanqu.json','["满棚和气登时起，一分提钱分外多。", "若有闲些儿个了，除是扑煞点砌，按住开呵。"]'),
('yuanqu-1631','四・专觑着古弄的说出了，村末的收外科，但有些决撒我早随声和。做院','睢玄明','元','元曲','yuanqu','','[]','本把我拾掇尽，赴村戏将咱来擂一和。',36,'元曲/yuanqu.json','["本把我拾掇尽，赴村戏将咱来擂一和。", "五音内咱须大，我教人人喜悦，个个脾和。"]'),
('yuanqu-1632','三・迎宣诏将我身上掩，接高官回把我背上驮，棚角头软索是我随身祸。','睢玄明','元','元曲','yuanqu','','[]','一声声怨气都言尽，一棒棒冤仇即渐多。',40,'元曲/yuanqu.json','["一声声怨气都言尽，一棒棒冤仇即渐多。", "肚皮里常饥饿，论着您腔新谱旧，显我恨满言多。"]'),
('yuanqu-1633','二・这厮则嫌乐器低，却不道本事捋，曾听的子弟每街头上有几篇新曲相','睢玄明','元','元曲','yuanqu','','[]','撺，不是两片顽皮吃甚么？但唆着招子都走过。',67,'元曲/yuanqu.json','["撺，不是两片顽皮吃甚么？但唆着招子都走过。", "排场上表子偷睛望，恨不得街上行人将手拖。", "但场户阑珊了些儿个，恨不得添五千串拍板，一万面铜锣。"]'),
('yuanqu-1634','尾・把我似救月般响起来打蝗虫似哄不合，不信那看官每不耳喧邻家每不','睢玄明','元','元曲','yuanqu','','[]','恼聒。',107,'元曲/yuanqu.json','["恼聒。", "从早晨间直点到斋时М，子被这淡厮全家擂煞我。", "咏西湖钱唐自古繁华地，有百处天生景致。", "幽微尽在浙江西，惟西湖山水希奇。", "水澄清玻璃万顷欺蓬岛，山峻峭蓝翠千层胜武夷。", "山水共谁相类？山旖旎妖妍如西子，水回环妩媚似杨妃。"]'),
('yuanqu-1635','九煞・遇清明赏禁烟，艳阳天丽日迟，倾城士庶同游戏。绣帘彩结香车稳，','睢玄明','元','元曲','yuanqu','','[]','玉勒金鞍宝马嘶。',31,'元曲/yuanqu.json','["玉勒金鞍宝马嘶。", "骋豪富夸荣贵，恣艳冶王孙士女，逞风流翠绕珠围。"]'),
('yuanqu-1636','八・闲嬉游父老每多，恐韶光暗里催，怕春归又怕相寻觅。坐兜轿的共访','睢玄明','元','元曲','yuanqu','','[]','欧阳井，骑蹇驴的来寻和靖碑。',37,'元曲/yuanqu.json','["欧阳井，骑蹇驴的来寻和靖碑。", "闷选胜闲拾翠，凝翠霭亭台楼阁，琐晴岚茅舍疏篱。"]'),
('yuanqu-1637','四・步芳茵近柳洲，选湖船觅总宜，绣铺陈更有金妆饰。紫金罂满注琼花','睢玄明','元','元曲','yuanqu','','[]','酿，碧玉瓶偏宜琥珀杯。',35,'元曲/yuanqu.json','["酿，碧玉瓶偏宜琥珀杯。", "排果桌随时置，有百十等异名按酒，数千般官样茶食。"]'),
('yuanqu-1638','三・列兵厨比光禄寺更佳，论珍羞尚食局造不及，动箫韶比仙音院大乐犹','睢玄明','元','元曲','yuanqu','','[]','为最。',51,'元曲/yuanqu.json','["为最。", "云山水陆烹炮尽，歌舞吹弹腔韵齐。", "更那堪东风软春光媚，借着喜人心的山明水秀，又恐怕送残春绿暗红稀。"]'),
('yuanqu-1639','二・游春客误走到丹青彩画图，寻芳人错行入蜀川锦绣堆，向武陵溪攒砌','睢玄明','元','元曲','yuanqu','','[]','就花圈<囗贵>。',54,'元曲/yuanqu.json','["就花圈<囗贵>。", "看了这佳人宴赏西湖景，胜如仙子嬉游太液池，似王母蟠桃会。", "灵芝港揭席人散，趁着海棠风赏玩忘归。"]'),
('yuanqu-1640','尾・看方今宇宙间，遍寰区为第一。论中吴形胜真佳丽，除了天上天堂再','睢玄明','元','元曲','yuanqu','','[]','无比。',3,'元曲/yuanqu.json','["无比。"]'),
('yuanqu-1641','崔府君断冤家债主・仙吕/忆王孙','郑延玉','元','元曲','yuanqu','','[]','粗衣淡饭且淹消，养性修真常自保，贫富一般缘分了。',118,'元曲/yuanqu.json','["粗衣淡饭且淹消，养性修真常自保，贫富一般缘分了。", "任白发不相饶，但得个稚子山妻，我一世儿快活到老。", "(同卜儿下)(崔子玉云)兄弟同媳妇儿回家了也，俺自登途去咱。", "(诗云)此行元不为功名，总是尘根未得清。", "传语山中修道侣，好将心寄白云层。", "(下)。"]'),
('yuanqu-1642','崔府君断冤家债主・仙吕/点绛唇','郑延玉','元','元曲','yuanqu','','[]','浊骨凡胎，递生人海，三十载。',47,'元曲/yuanqu.json','["浊骨凡胎，递生人海，三十载。", "也是我缘分合该，(带云)正为这泼家私呵，(唱)我也曾捱淡饭黄齑菜。"]'),
('yuanqu-1643','崔府君断冤家债主・混江龙','郑延玉','元','元曲','yuanqu','','[]','俺大哥一家无外，干家活计觅钱财，积垒下前厅后阁，更攒下万贯家财。',191,'元曲/yuanqu.json','["俺大哥一家无外，干家活计觅钱财，积垒下前厅后阁，更攒下万贯家财。", "俺大哥爷娘行能行孝道，也是我前世里积阴功，苦修来。", "大的儿甘心守分，量力求财，为人本分，不染尘埃，衣不裁绫罗段疋，食不拣好歹安排，爷娘行千般孝顺，亲眷行万事和谐。", "若说着这个禽兽，知他怎天地栽排？每日向花门柳户，舞榭歌台，铅华触眼，酒肉拥颏，但行处着人骂，惹人嫌，将家私可便由他使，由他卖。", "这的是破家五鬼，不弱如横祸非灾。"]'),
('yuanqu-1644','崔府君断冤家债主・油葫芦','郑延玉','元','元曲','yuanqu','','[]','贼也你搭手在心头自监解，这家私端的是谁挣扎，则你那二十年何曾道觅的半文来？你、你、你，则待要撞着的赊下逢着的买，到家呵抹着的当了拿着的卖。',116,'元曲/yuanqu.json','["贼也你搭手在心头自监解，这家私端的是谁挣扎，则你那二十年何曾道觅的半文来？你、你、你，则待要撞着的赊下逢着的买，到家呵抹着的当了拿着的卖。", "你、你、你，无花呵眼倦开，无酒呵头也不抬。", "引着些个泼男泼女相扶策，你、你、你，则待每日上花台。"]'),
('yuanqu-1645','崔府君断冤家债主・鹊踏枝','郑延玉','元','元曲','yuanqu','','[]','一会家上心来，想这厮不成才！气的我手脚酸麻，东倒西歪。',50,'元曲/yuanqu.json','["一会家上心来，想这厮不成才！气的我手脚酸麻，东倒西歪。", "贼也，你少有的破了家宅，倒不如两下里早早分开。"]'),
('yuanqu-1646','崔府君断冤家债主・寄生草','郑延玉','元','元曲','yuanqu','','[]','你引着些帮闲汉，更和这吃剑才。',428,'元曲/yuanqu.json','["你引着些帮闲汉，更和这吃剑才。", "你只要杀羊造酒将人待，你道是使钱撒镘令人爱，你怎知囊空钞尽招人怪！气的我老业人目下一身亡。", "(带云)我死了呵，(唱)恁时节可也还彻你冤家债。", "(云)大哥，这也没奈何，你还了者。", "(乞僧云)父亲，你孩儿披星戴月，做买做卖，一文不使，半文不用，怎生攒下这家私，都着他花费了也。", "(卜儿云)大哥，你还他罢。", "(乞僧云)我还，我还。", "(做发付科，云)还了你去罢。", "(杂当云)还了我钱，我回家去也。", "(下)(正末云)婆婆，趁俺两口儿在，将这家私分开了罢。", "若不分开呵，久已后吃这厮凋零的无了。", "(卜儿云)老的，这家私分他怎么，还是着大哥管的好。", "(正末云)只是分开了罢。", "大哥，你将应有的家私，都搬出来，和那借钱钞的文书也拿将出来。", "(乞僧云)理会的。", "(正末云)婆婆，家私都在这里。", "三分儿分开者。", "(福僧云)分开这家私倒也好，省的絮絮聒聒的。", "(卜儿云)老的，怎生做三分儿分开？(正末云)他弟兄每两分，我和你留着一分。", "(卜儿云)这也说的是，都依着你便了。", "(正末唱)。"]'),
('yuanqu-1647','崔府君断冤家债主・赚煞','郑延玉','元','元曲','yuanqu','','[]','你待要沙暖睡鸳鸯，我则会岁寒知松柏，你将我这逆耳良言不采。',107,'元曲/yuanqu.json','["你待要沙暖睡鸳鸯，我则会岁寒知松柏，你将我这逆耳良言不采。", "这家私亏煞俺爷娘生受来，我便是释迦佛也恼下莲台。", "想这厮不成才，因此上各自分开，随你商量做买卖。", "常言道山河易改，本性儿还在，我则怕你有朝福过定生灾。", "(同下)。"]'),
('yuanqu-1648','崔府君断冤家债主・商调/集贤宾','郑延玉','元','元曲','yuanqu','','[]','自分开近并来百事有，这的是为儿女报官囚。',118,'元曲/yuanqu.json','["自分开近并来百事有，这的是为儿女报官囚。", "闪的个老业人不存不济，则俺这养家儿千死千休。", "这的是天网恢恢，果然道疏而不漏。", "(带云)若俺大哥有些好列呵，(唱)怎发付这无主意的老业人张善友？三十年一梦庄周。", "我恰便是俞阳般服药酒，恰便似庄子叹骷髅。"]'),
('yuanqu-1649','崔府君断冤家债主・逍遥乐','郑延玉','元','元曲','yuanqu','','[]','我则索仰神灵保佑，为孩儿所事存心，我怎肯等闲罢手！儿也，闪的我来有国难投，忍不住两泪交流。',210,'元曲/yuanqu.json','["我则索仰神灵保佑，为孩儿所事存心，我怎肯等闲罢手！儿也，闪的我来有国难投，忍不住两泪交流。", "莫不是我前世里烧香不到头，我则索把神灵来祷咒。", "只愿的减罪消灾，绝虑忘忧。", "(云)来到这佛堂前。", "我推开佛堂门。", "(做跪科，云)小的每将香来。", "家堂菩萨，有这大的个孩儿，多亏了他早起晚眠，披星戴月，挣揣下这个家私，今日可有病；小的个孩儿，吃酒赌钱，不成半器，他可无病。", "家堂爷爷，怎生可怜见老汉，着俺大的个孩儿，这病痊可咱。", "(做拜科)(唱)。"]'),
('yuanqu-1650','崔府君断冤家债主・梧叶儿','郑延玉','元','元曲','yuanqu','','[]','小的个儿何曾生受，他则待追朋趁友，每日家无月不登楼。',82,'元曲/yuanqu.json','["小的个儿何曾生受，他则待追朋趁友，每日家无月不登楼。", "大的个儿依先如旧，常则待将无做有，巴不得败子早回头，(带云)圣贤也！(唱)你怎生则拣着这个张善友心疼下便下手？。"]'),
('yuanqu-1651','崔府君断冤家债主・醋葫芦','郑延玉','元','元曲','yuanqu','','[]','你胸脯上着炙，肚皮上用手揉。',56,'元曲/yuanqu.json','["你胸脯上着炙，肚皮上用手揉。", "俺一家儿烧钱烈纸到神州，请法师唤太医疾快走。", "将那俺养家儿搭救，则教我肠慌腹热似烧油。"]'),
('yuanqu-1652','崔府君断冤家债主・幺篇','郑延玉','元','元曲','yuanqu','','[]','只见那两个帮闲的花满头，这一个败家的面带酒。',70,'元曲/yuanqu.json','["只见那两个帮闲的花满头，这一个败家的面带酒。", "你也想着一家儿披麻带孝为何由？故来这灵堂里寻斗殴。", "直恁般见死不救，莫不是你和他没些瓜葛没些忧？。"]'),
('yuanqu-1653','崔府君断冤家债主・穷河西','郑延玉','元','元曲','yuanqu','','[]','你道死和生，都是天数周，怎偏我子和娘拔著短筹？我如今备棺椁将他殡，不如我这业尸骸又著那个收？。',47,'元曲/yuanqu.json','["你道死和生，都是天数周，怎偏我子和娘拔著短筹？我如今备棺椁将他殡，不如我这业尸骸又著那个收？。"]'),
('yuanqu-1654','崔府君断冤家债主・凤鸾吟','郑延玉','元','元曲','yuanqu','','[]','怎不著我愁，这烦恼甚日休，天那！偏是俺好夫妻不到头。',147,'元曲/yuanqu.json','["怎不著我愁，这烦恼甚日休，天那！偏是俺好夫妻不到头。", "怎不著我愁，这烦恼甚日休，天那！偏是俺养家儿没福留。", "(崔子玉云)兄弟，你的寿算也还远哩，这家私便破散了些，打甚么不紧！且省烦恼波。", "(正末唱)想人生到中年以后，这光阴不久，还望甚家缘成就！随你便攒黄金过北斗，只落的干生受，天那！早寻个落叶归秋。"]'),
('yuanqu-1655','崔府君断冤家债主・中吕/粉蝶儿','郑延玉','元','元曲','yuanqu','','[]','活计萧疏，正遭逢太平时序，偏是我老不著暮景桑榆。',64,'元曲/yuanqu.json','["活计萧疏，正遭逢太平时序，偏是我老不著暮景桑榆。", "典了庄宅，卖了田土，销乏了几多钱物。", "委实的不曾半霎儿心舒，一天愁将我这两眉攒聚。"]'),
('yuanqu-1656','崔府君断冤家债主・醉春风','郑延玉','元','元曲','yuanqu','','[]','恨高似万重山，泪多如连夜雨。',63,'元曲/yuanqu.json','["恨高似万重山，泪多如连夜雨。", "眼见的儿亡妻丧，又有个病着床，老业人你畅好是苦，苦。", "则俺这小的个孩儿倘有些好歹，可著我那埚儿发付。"]'),
('yuanqu-1657','崔府君断冤家债主・红绣鞋','郑延玉','元','元曲','yuanqu','','[]','祷祸了千言万语，天啊！则愿的小冤家百病消除。',196,'元曲/yuanqu.json','["祷祸了千言万语，天啊！则愿的小冤家百病消除。", "儿也，便使的我片瓦根椽一文无，但存留的孩儿在，就是我护身符，又何必满堂金才是福？(云)二哥，你这早晚面色不好。", "你有甚么遗留言语，吩咐我咱。", "(福僧云)父亲，你不知道我这病。", "别人害的是气蛊水蛊，我害的是米蛊。", "(正末云)如何是米蛊？(福僧云)若不是米蛊呵，怎生偌大一个栲栳？父亲，我顾不的你也。", "(做死伏科)(正末做哭科，云)儿呵，则被你痛杀我也。", "(唱)。"]'),
('yuanqu-1658','崔府君断冤家债主・迎仙客','郑延玉','元','元曲','yuanqu','','[]','还只道沉沉的卧著床褥，谁知他悠悠的赴了冥途，空把我孩儿叫道有千百句。',74,'元曲/yuanqu.json','["还只道沉沉的卧著床褥，谁知他悠悠的赴了冥途，空把我孩儿叫道有千百句。", "阎君也，你好狠心肠；土地也，你好歹做处。", "闪的我鳏寡孤独，怎下的便撇了你这爹先去。"]'),
('yuanqu-1659','崔府君断冤家债主・白鹤子','郑延玉','元','元曲','yuanqu','','[]','他本是聪明正直神，掌管著寿夭存亡簿。',53,'元曲/yuanqu.json','["他本是聪明正直神，掌管著寿夭存亡簿。", "怎不容俺夫妇到白头？(带云)我那两个孩儿呵！(唱)也著他都死因何故？。"]'),
('yuanqu-1660','崔府君断冤家债主・幺篇','郑延玉','元','元曲','yuanqu','','[]','哎，想当日有一个狄梁公曾断虎，有一个西门豹会投巫。',47,'元曲/yuanqu.json','["哎，想当日有一个狄梁公曾断虎，有一个西门豹会投巫。", "又有个包待制白日里断阳间，他也曾夜断阴司路。"]'),
('yuanqu-1661','崔府君断冤家债主・上小楼','郑延玉','元','元曲','yuanqu','','[]','俺孩儿也不曾讹言谎语，又不曾方头不律。',74,'元曲/yuanqu.json','["俺孩儿也不曾讹言谎语，又不曾方头不律。", "俺孩儿量力求财，本分随缘，乐道闲居。", "阎神也有向顺，土地也不胡突。", "可怎生将俺孩儿一时勾去，害的俺张善友牵肠割肚。"]'),
('yuanqu-1662','崔府君断冤家债主・耍孩儿','郑延玉','元','元曲','yuanqu','','[]','神堂庙宇偏谁做？无过是烈士忠臣宰辅。',109,'元曲/yuanqu.json','["神堂庙宇偏谁做？无过是烈士忠臣宰辅。", "但生情发意运机谋，早明彰报应非诬。", "(云)哥哥，这桩事你不与我断，谁断？(唱)难道阳世间官府多机变，阴府内神灵也混俗。", "把森罗殿都做了营生铺，有钱的免了他轮回六道，无钱的去受那地狱三涂。"]'),
('yuanqu-1663','崔府君断冤家债主・二煞','郑延玉','元','元曲','yuanqu','','[]','我如今有家私谁管顾？有钱财谁做主？我死后谁浇茶、谁奠酒、谁啼哭？谁安灵位谁斋七？谁驾灵车谁挂服？止几个忤作行送出城门去，又无那花棺彩舆，多管是席卷椽舁。',76,'元曲/yuanqu.json','["我如今有家私谁管顾？有钱财谁做主？我死后谁浇茶、谁奠酒、谁啼哭？谁安灵位谁斋七？谁驾灵车谁挂服？止几个忤作行送出城门去，又无那花棺彩舆，多管是席卷椽舁。"]'),
('yuanqu-1664','崔府君断冤家债主・双调/新水令','郑延玉','元','元曲','yuanqu','','[]','一灵儿监押见阎君，闪的我虚飘飘有家难奔。',60,'元曲/yuanqu.json','["一灵儿监押见阎君，闪的我虚飘飘有家难奔。", "明知道空撒手，怕甚么业随身！托赖著阴府灵神，得见俺那阳世间的儿孙，便死也亦无恨。"]'),
('yuanqu-1665','崔府君断冤家债主・太平令','郑延玉','元','元曲','yuanqu','','[]','他平日里常只待寻争觅衅，儿也，你怎的也学他背义忘恩？这忤逆贼从来生忿，你须识一个高低远近。',303,'元曲/yuanqu.json','["他平日里常只待寻争觅衅，儿也，你怎的也学他背义忘恩？这忤逆贼从来生忿，你须识一个高低远近。", "(云)大哥，跟我家去来。", "(乞僧云)我填还了你的，俺和你不亲了也。", "(正末唱)你道我不亲强亲，咱须是你父亲，呀，好教我一言难尽。", "(阎君云)着这两个速退。", "(鬼力引乞僧、福僧下)(阎君)云你要见你那浑家么？(正末云)可知要见哩。", "(阎君云)鬼力，与我开了酆都城，拿出张善友的浑家来。", "(鬼力押卜儿上，见科)(正末云)婆婆，你为甚么来？(卜儿做哭科，云)老的也，我当初不合混赖了那五台山和尚十个银子。", "我死归冥路，教我十八层地狱，都游遍了也。", "你怎生救我咱？(正末做叹科，云)那五台僧人的银子，我只道还他去了，怎知赖了他的来？(唱)。"]'),
('yuanqu-1666','崔府君断冤家债主・雁儿落','郑延玉','元','元曲','yuanqu','','[]','我也曾有三年养育恩，为甚的没一个把亲爷认？原来大的儿是他前生少我钱，小的儿是我今世偿他本。',45,'元曲/yuanqu.json','["我也曾有三年养育恩，为甚的没一个把亲爷认？原来大的儿是他前生少我钱，小的儿是我今世偿他本。"]'),
('yuanqu-1667','崔府君断冤家债主・得胜令','郑延玉','元','元曲','yuanqu','','[]','这都是我那婆婆也作业自殃身，遗累及儿孙。',105,'元曲/yuanqu.json','["这都是我那婆婆也作业自殃身，遗累及儿孙。", "再休提世上无恩怨，须信道空中有鬼神。", "(崔子玉云)兄弟，你省悟了么？(正末云)哥哥，张善友如今才省悟了也。", "(唱)总不如安贫，落一个身困心无困。", "这便是修因，也免的钱亲人不亲。"]'),
('yuanqu-1668','诸葛亮博望烧屯・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','数下皇极，课传《周易》，知天理。',31,'元曲/yuanqu.json','["数下皇极，课传《周易》，知天理。", "饱养玄机，常有那尊道德参玄意。"]'),
('yuanqu-1669','诸葛亮博望烧屯・混江龙','无名氏','元','元曲','yuanqu','','[]','有朝一日，我出茅庐指点世人迷。',554,'元曲/yuanqu.json','["有朝一日，我出茅庐指点世人迷。", "凭着我剑挥星斗，我志逐风雪。", "圣明君稳坐九重龙凤阙，显出那大将军八面虎狼威。", "(云)道章，你见么？(道童云)师父，您徒弟见甚么？(正末唱)见风筛竹影，日射松穿。", "我恰才袖中发课，你去那门外观窥。", "安排着香桌，准备着烹茶，(云)道童，这一来。", "(道童云)师父，可是何人到此也。", "(正末唱)必定是关云长、张翼德和刘备。", "(云)道童。", "(道童云)师父有何话说？(正末唱)你与我忙铺下席簟，，你与我半掩得这些扉。", "(道童云)师父，您徒弟安排下香桌，烹了茶汤，铺下席簟，洒扫的干净了也。", "(正末云)道童，你门首觑者，看有甚么人来。", "(刘末同关末、张飞上)(刘末云)兄弟，可早来到也。", "远远的看见茅庵，将俺的军马屯在这山峪口，安营下寨。", "咱弟兄三人，直至茅庵中请师父去，可早来到也。", "二位兄弟，俺见师父去来。", "(张飞云)二位哥，今番第三遭，这村夫若下山去呵，我和他佛眼相看，若不下山去呵，我不道的烧了他哩。", "(关末云)兄弟，你休这等躁暴，俺求贤用士哩。", "(刘末云)兄弟，你不得躁暴，休误了大事。", "(刘末见道童科，云)道童，你师父庵中有么？(道童云)俺师父正在庵中盹睡哩。", "(张飞做揪住道童科，云)你师父在那里？(道童慌科，云)老官儿，我才不说来，师父昨日酒多了，还不曾睡醒哩。", "老官儿休要动手。", "(张飞云)这村夫到不纳房钱。", "则是睡。"]'),
('yuanqu-1670','诸葛亮博望烧屯・醉中天','无名氏','元','元曲','yuanqu','','[]','我见他挪身起，他忙挪步上阶基。',191,'元曲/yuanqu.json','["我见他挪身起，他忙挪步上阶基。", "(刘末拜科，云)师父，孤穷刘备，来两次不遇，今番是第三遭也。", "刘备特来相访。", "(正末唱)玄德公你这般两次三番劳贵体，(刘末云)小官特来相请也。", "(正末唱)你请贫逆因何意？(刘末云)一年三访不遇，今日得见吾师，实乃孤穷刘备之万幸也。", "(正末唱)我请你个玄德公安然坐的，(刘末云)孤穷刘备，断然不敢。", "(正未唱)他口声声道是孤穷刘备，那一个孤穷的他生这般舜目尧眉？。"]'),
('yuanqu-1671','诸葛亮博望烧屯・油葫芦','无名氏','元','元曲','yuanqu','','[]','我则待仿学巢由洗是非，我一心待习道德。',113,'元曲/yuanqu.json','["我则待仿学巢由洗是非，我一心待习道德。", "我可便喜登吕望钓鱼矾，谁待要蜗牛角上争名利？谁待要蜘蛛网内求官位？(刘末云)师父隐迹于此，不知主何意也？(正末唱)我但穿些布草衣，但吃些粗粝食。", "我则待日高三丈我便朦头睡，一任教乌兔走东西。"]'),
('yuanqu-1672','诸葛亮博望烧屯・天下乐','无名氏','元','元曲','yuanqu','','[]','我则是除睡人间总不知，我可便其也波实，其实可便无甚智，(刘末云)师父若肯下山去呵，同扶汉室，再立炎刘，有何不可也？(正末唱)你今日请贫道下山待出些气力。',119,'元曲/yuanqu.json','["我则是除睡人间总不知，我可便其也波实，其实可便无甚智，(刘末云)师父若肯下山去呵，同扶汉室，再立炎刘，有何不可也？(正末唱)你今日请贫道下山待出些气力。", "(云)贫道便下山去呵。", "(唱)我其实当不的寒，我可便济不的饥，便请下这个卧龙冈做甚的？。"]'),
('yuanqu-1673','诸葛亮博望烧屯・金盏儿','无名氏','元','元曲','yuanqu','','[]','他生的高耸耸俊英鼻，长挽挽卧蚕眉。',73,'元曲/yuanqu.json','["他生的高耸耸俊英鼻，长挽挽卧蚕眉。", "红馥馥面皮有似胭脂般赤，黑蓁蓁三绺美髯垂。", "这将军内藏着君子气，外显出渗人威。", "这将军生前为将相，他若是死后做神祗。"]'),
('yuanqu-1674','诸葛亮博望烧屯・尾声','无名氏','元','元曲','yuanqu','','[]','把您这孙刘曹、吴蜀魏，鼎足三分不可缺矣。',95,'元曲/yuanqu.json','["把您这孙刘曹、吴蜀魏，鼎足三分不可缺矣。", "曹操天时为第一，想孙权地利合宜，玄德公掌人和，稳胜磬石。", "先占了西蜀四千里，我对你个玄德公说知。", "哎！你个张将军赌气，我则见笑谈间一阵卷征旗。", "(同众下)。"]'),
('yuanqu-1675','诸葛亮博望烧屯・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','我则见遮天杂彩旗，震地花腔鼓。',75,'元曲/yuanqu.json','["我则见遮天杂彩旗，震地花腔鼓。", "关云长青龙偃月刀，张翼德银蟒可兀的点钢毒。", "齐臻臻铠甲结束，银缠杆花稍弩，兽吞金蘸斧。", "有五千员越岭奔彪，有百万只爬山猛虎。"]'),
('yuanqu-1676','诸葛亮博望烧屯・牧羊关','无名氏','元','元曲','yuanqu','','[]','则要你鱼鳞般排军阵，雁行般列队伍，依着我运计铺谋。',100,'元曲/yuanqu.json','["则要你鱼鳞般排军阵，雁行般列队伍，依着我运计铺谋。", "我不要你战斗相持，我则要你扬尘也那播土。", "你休去那垓心里撞，你则向草坡早伏。", "(刘封云)军师，则怕不中么？(正末唱)哎，你个义子休心怕，你正是贼儿胆底虚。"]'),
('yuanqu-1677','诸葛亮博望烧屯・贺新郎','无名氏','元','元曲','yuanqu','','[]','你向那博望城多准备着火葫芦，(云)等他入的城来，着鹿角叉住巷口，当住城门。',162,'元曲/yuanqu.json','["你向那博望城多准备着火葫芦，(云)等他入的城来，着鹿角叉住巷口，当住城门。", "(唱)你与我先点着粮车，后烧着窝铺。", "您四下里火箭一齐去，火烧的他神嚎也那鬼哭，火烧的他马死人无。", "着他在火坑中丧了性命，都着他火阵内丧了残躯。", "(糜竺云)则怕三将军他要去么？(正末唱)你着那张将军不索阶前怒，这的是黄公《三略》法，更压着那吕望《六韬》书。"]'),
('yuanqu-1678','诸葛亮博望烧屯・隔尾','无名氏','元','元曲','yuanqu','','[]','关云长你去漏陵渡，(关末云)师父，潺陵渡怎生堰住水口？(正末唱)用土布袋把长江紧当住，水淹杀的军兵死无数。',105,'元曲/yuanqu.json','["关云长你去漏陵渡，(关末云)师父，潺陵渡怎生堰住水口？(正末唱)用土布袋把长江紧当住，水淹杀的军兵死无数。", "他活时节是战夫，死后做了水卒。", "(云)二将军云长。", "(关末云)有。", "(正末唱)你若是得胜还营，你将我来自然许。"]'),
('yuanqu-1679','诸葛亮博望烧屯・双调/新水令','无名氏','元','元曲','yuanqu','','[]','管教这数千员敢战的铁衣郎，则有个莽张飞他可便不伏诸葛亮。',62,'元曲/yuanqu.json','["管教这数千员敢战的铁衣郎，则有个莽张飞他可便不伏诸葛亮。", "则因恶战讨，我可便懒下卧龙冈。", "则他这战马刀枪，多无那半个时分见明降。"]'),
('yuanqu-1680','诸葛亮博望烧屯・风入松','无名氏','元','元曲','yuanqu','','[]','您众将军武艺委实强，(云)好将军也。',65,'元曲/yuanqu.json','["您众将军武艺委实强，(云)好将军也。", "(唱)更那堪状貌堂堂。", "舍性命便往垓心里撞，恰便似闹垓垓虎荡群羊。", "饮过酒今番不忘，为将帅显高强。"]'),
('yuanqu-1681','诸葛亮博望烧屯・雁儿落','无名氏','元','元曲','yuanqu','','[]','眼见的鞭敲金镫响，将凯歌齐声唱。',32,'元曲/yuanqu.json','["眼见的鞭敲金镫响，将凯歌齐声唱。", "紧绑绑拴住臂膊，直挺挺舒着脖项。"]'),
('yuanqu-1682','诸葛亮博望烧屯・得胜令','无名氏','元','元曲','yuanqu','','[]','张飞也，你不道是架海紫金梁，他不是那托搭的李天王？得胜掌军师印，你道是不拿住不姓张。',104,'元曲/yuanqu.json','["张飞也，你不道是架海紫金梁，他不是那托搭的李天王？得胜掌军师印，你道是不拿住不姓张。", "你凭着马壮人强，你道是鞭督邮魂飘荡。", "你曾摔袁祥，(带云)张飞你不道来那，(张飞云)我道甚么来？(正末唱)你道是，男儿当自强。"]'),
('yuanqu-1683','诸葛亮博望烧屯・鸳鸯煞尾','无名氏','元','元曲','yuanqu','','[]','今日个领三军坐金顶莲花帐，披七星锦绣云鹤氅。',87,'元曲/yuanqu.json','["今日个领三军坐金顶莲花帐，披七星锦绣云鹤氅。", "早定了西蜀，我便访南阳。", "畅道觑曹操、孙权，似浮云瘙痒。", "我请您玄德、关、张，威镇住曹丞相。", "今日个稳定家邦，史策留名后人讲。", "(同下)。"]'),
('yuanqu-1684','诸葛亮博望烧屯・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','自从和曹操争锋，恰如同一场春梦。',60,'元曲/yuanqu.json','["自从和曹操争锋，恰如同一场春梦。", "摆列着盖国英雄，一个个善相持，能挑战，他可便超群出众。", "一个个都建了头功，真乃是世之梁栋。"]'),
('yuanqu-1685','诸葛亮博望烧屯・醉春风','无名氏','元','元曲','yuanqu','','[]','想昔日梦非熊，您今朝请卧龙。',410,'元曲/yuanqu.json','["想昔日梦非熊，您今朝请卧龙。", "我可甚两三番懒下卧龙冈，我其实怕冗，冗。", "我今日当权，掌军师名项，则不如我在那半坡里养性。", "(云)玄德公安排酒果，准备的齐整者。", "不到半时，必有说客至此。", "则要糜竺、糜芳在此，其余将军都承听令。", "赵云附耳来，可是恁的。", "(做打耳喑科)(赵云云)师父连主公也着回避，您众将听师父将令。", "糜竺、糜芳，紧守着师父，小心在意者。", "(正末云)是也。", "(刘末云)师父，连刘备也着回避，众将听师父将令。", "糜竺、糜芳，紧守着师父，小心在意。", "(赵云云)俺回避也。", "(同众下)(管通上，云)贫道管通是也。", "自离魏地，可早来到新野。", "小校报复去，道有一云游先生，乃是管通，特来相访。", "(卒子云)理会的。", "喏，报的军师得知，有一云游的先生管通，在于门首。", "(正末云)我须索接待哥哥，走一遭去。", "(见科，云)哥哥有请。", "(管通云)不敢。", "(正末云)哥哥，俺一向相别，拳拳在意，终日无忘。", "不想哥哥今日来到，实乃诸葛之万幸也。", "(管通云)贤兄久别情怀，常思快怏。"]'),
('yuanqu-1686','诸葛亮博望烧屯・剔银灯','无名氏','元','元曲','yuanqu','','[]','非是我厅阶前卖弄，你众将休要打哄。',58,'元曲/yuanqu.json','["非是我厅阶前卖弄，你众将休要打哄。", "若猜着众将休惊恐，您试看变化的这神通。", "这的是真术艺，又不是说脱空，睁着眼不要转动。"]'),
('yuanqu-1687','诸葛亮博望烧屯・十二月','无名氏','元','元曲','yuanqu','','[]','这个是常山赵云，(管通云)这个是谁？(正末唱)这个是义子刘封。',269,'元曲/yuanqu.json','["这个是常山赵云，(管通云)这个是谁？(正末唱)这个是义子刘封。", "(管通云)这个是谁？(正末唱)这个是燕人翼德。", "(管通云)这个是谁？(正末唱)这个是勇烈关公。", "(管通云)贫道相的不差也。", "(正末唱)哎，这个能相法哥哥管通，你可也比众难同。", "(云)哥哥，这四间房，哥哥都相过了。", "哥哥，你看这间房里如何？(管通云)我观这间房中，气象全别。", "你看那样云笼罩，紫气腾腾，必是贵人之相，都压着这几位将军。", "兄弟不信呵，开了门我试看者。", "(正末做怒科，云)休开门。", "(管通云)开了者。", "(正末云)休开门。", "(管通云)你为何不开，(正末云)哥哥，不争您兄弟开开这门，(唱)。"]'),
('yuanqu-1688','满江红','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末上)铁砚毛锥，几年向文场驰逐。',113,'元曲/yuanqu.json','["(末上)铁砚毛锥，几年向文场驰逐。", "任雕龙手段，俯头屈足。", "浪迹浑如萍逐水，虚名好似声传谷。", "笑半生梦里鬓添霜，空碌碌。", "酒人中，聊托宿；诗社内，聊容足。", "惯嘲风弄月，品红评绿。", "点染新词别样锦，推敲旧谱无瑕玉。", "管风流领袖播千秋，英雄独。"]'),
('yuanqu-1689','鸳鸯阵','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','孙毕家富贵，东京住，结义两乔人。',148,'元曲/yuanqu.json','["孙毕家富贵，东京住，结义两乔人。", "诳语谗言，从中搬斗，将孙荣赶逐，投奔无门。", "风雪里救兄一命，将恩作怨，妻谏反生嗔。", "施奇计，买王婆黄犬，杀取扮人身。", "夫回蓦地惊魂，去冫免龙卿、子传，托病不应承。", "再往窑中，试寻兄弟，移尸慨任，方辨疏亲。", "清官处乔人忘告，贤妻出首，发狗见虚真。", "重和睦，封章褒美，兄弟感皇恩。"]'),
('yuanqu-1690','挂真儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生上)积善之家庆有余，传留下万卷诗书。',392,'元曲/yuanqu.json','["(生上)积善之家庆有余，传留下万卷诗书。", "性禀刚贞，胸怀仁义，更喜门庭豪贵。", "两字功名志未酬，藏珠韫玉且优游。", "家传阀阅经多载，世代簪缨知几秋。", "天谄诈，有刚柔，果然名字播皇州。", "家中财宝如山积，库内钱财似水流。", "卑人姓孙，名华，排行第一，祖贯东京人氏。", "曾攻诗史，未遂风云。", "喜得家道丰盈，尽可优游岁月。", "荆妻杨氏，妇道颇娴。", "侍女迎春，家规能守。", "有个同胞兄弟。", "唤做孙荣，从小是卑人抚养成人，今经一十八岁，未曾婚匹。", "一应家事，俱是卑人总理。", "他只在学馆攻书，见成安享。", "这也罢了。", "奈他性多执拗，才欠圆通。", "胸中之学，或者有余；户外之事，全然未晓。", "每每触忤卑人，屡加训责，他从无怨恨之心，奈绝无顺从之美。", "正所谓\"江山易改，禀性难移\"。", "近来卑人结识得两个好友，一个是柳龙卿，一个是胡子传。", "此二人不但诗礼之儒，颇饶豪侠之气；又且知机识变，博学多能。", "物情市价，无所不通；官讼家常，何事不晓。", "与卑人相爱相亲，如同手足。"]'),
('yuanqu-1691','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','兄弟怡怡乐有余，终日里玩史攻书。',33,'元曲/yuanqu.json','["兄弟怡怡乐有余，终日里玩史攻书。", "十载辛勤，一朝遭际，不负家传豪贵。"]'),
('yuanqu-1692','绣带儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','吾朋友如龙卿有几。',16,'元曲/yuanqu.json','["吾朋友如龙卿有几。", "兼之子传贤齐。"]'),
('yuanqu-1693','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)忠规，非直谅多闻善辈，何必异姓结义！(生怒介)就结义个异姓何妨！(小生)今一语轻交，他时驷马难迫。',166,'元曲/yuanqu.json','["(小生)忠规，非直谅多闻善辈，何必异姓结义！(生怒介)就结义个异姓何妨！(小生)今一语轻交，他时驷马难迫。", "(生)休疑，此心独断无后悔。", "你这蠢东西，结义了这两个人，得他教导你教导也好，少不得学他些伶俐。", "(小生笑介)要他来教导孙荣。", "他教导出些什么来？小家子心低志低，这辈谄谀之人，还该疏远他才是，怎么倒去亲近他？难道是推不开嫡亲兄弟？。"]'),
('yuanqu-1694','大圣乐','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','吾家累代缨绅，我一身享现成。',67,'元曲/yuanqu.json','["吾家累代缨绅，我一身享现成。", "金玉满堂多豪贵，怎答谢父娘恩？奈嫡亲兄弟不和顺，却与非亲结义亲。", "(合)此事非容易，也算人生好恶，宿世缘分。"]'),
('yuanqu-1695','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)东人富室豪门，论结交须谨慎。',55,'元曲/yuanqu.json','["(末)东人富室豪门，论结交须谨慎。", "他人怎比得亲骨肉？久久见假和真。", "寻思及早回头省，莫把亲人如陌路人。", "(合前)。"]'),
('yuanqu-1696','丹凤吟','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','行过柳堤，步入园内。',22,'元曲/yuanqu.json','["行过柳堤，步入园内。", "(末)那一位解元何处？。"]'),
('yuanqu-1697','节节高犯','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','相邀结义的好兄弟，(见介。',39,'元曲/yuanqu.json','["相邀结义的好兄弟，(见介。", "净、丑)兄弟望兄不来至，肝肠碎。", "(末)试向前排吃食。"]'),
('yuanqu-1698','解连环','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)酬酢欢娱，拚今朝共伊沈醉，同携手步月归去。',47,'元曲/yuanqu.json','["(生)酬酢欢娱，拚今朝共伊沈醉，同携手步月归去。", "(合)逢知己，赛过关张管鲍的，切莫学割袍断义。"]'),
('yuanqu-1699','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净)兄饮一杯，但从今放开忧虑，兄有事弟当前去。',29,'元曲/yuanqu.json','["(净)兄饮一杯，但从今放开忧虑，兄有事弟当前去。", "(合前)。"]'),
('yuanqu-1700','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑)兄听因依，是吴忠把盔馔偷吃，适才的望兄不至。',30,'元曲/yuanqu.json','["(丑)兄听因依，是吴忠把盔馔偷吃，适才的望兄不至。", "(合前)。"]'),
('yuanqu-1701','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)谁是谁非，请不须再三提起，提将起恐伊羞耻。',29,'元曲/yuanqu.json','["(末)谁是谁非，请不须再三提起，提将起恐伊羞耻。", "(合前)。"]'),
('yuanqu-1702','新水令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','奴家年少多聪慧，伴娘行宴乐游戏。',47,'元曲/yuanqu.json','["奴家年少多聪慧，伴娘行宴乐游戏。", "昼永拈针指。", "(旦叫介)迎春！(贴)听帘前呼唤，不知有何言语？。"]'),
('yuanqu-1703','集贤宾','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)官人近日心恁偏，与兄弟结冤。',59,'元曲/yuanqu.json','["(旦)官人近日心恁偏，与兄弟结冤。", "每日与非亲同欢宴，把骨肉顿成抛闪。", "不听劝谏，怕迤逦日疏日远。", "长挂念，恐一宅分为两院。"]'),
('yuanqu-1704','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)人情好歹非偶然，奈总是前缘。',59,'元曲/yuanqu.json','["(贴)人情好歹非偶然，奈总是前缘。", "是则是官人没宛转，我娘行白当相劝。", "听时易言，不听后别作机变。", "休挂念，自临风对月消遣。"]'),
('yuanqu-1705','琥珀猫儿坠','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)良药苦口，逆耳乃忠言。',48,'元曲/yuanqu.json','["(旦)良药苦口，逆耳乃忠言。", "叹我儿大不信贤，几番劝解反埋冤。", "(合)难言，问甚日何时，得他心转？。"]'),
('yuanqu-1706','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)劝君不听，切莫再三言。',35,'元曲/yuanqu.json','["(贴)劝君不听，切莫再三言。", "又恐官人生别见，反将恩爱变成冤。", "(合前)。"]'),
('yuanqu-1707','五供养','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)今生有幸，喜一身生长豪门。',56,'元曲/yuanqu.json','["(小生上)今生有幸，喜一身生长豪门。", "家传朱紫贵，世簪缨。", "诗书尽览，时未至龙门难进。", "一日里遇风云，那时衣紫作公卿。"]'),
('yuanqu-1708','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','同胞至亲，更不知他因甚生嗔？朝夕长打骂，苦难禁。',53,'元曲/yuanqu.json','["同胞至亲，更不知他因甚生嗔？朝夕长打骂，苦难禁。", "不敢怨兄，只恨我不能随顺。", "早晚拈香告神明，愿兄早早可回心。"]'),
('yuanqu-1709','朱奴儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑上。',18,'元曲/yuanqu.json','["(净、丑上。", "净)常言道，人无远虑，。"]'),
('yuanqu-1710','桃李争春','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','蓦忽闻知，两个心友临门，不觉心中欢喜。',19,'元曲/yuanqu.json','["蓦忽闻知，两个心友临门，不觉心中欢喜。"]'),
('yuanqu-1711','引军旗','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','听拜禀：令弟不仁，赎毒药害你身。',73,'元曲/yuanqu.json','["听拜禀：令弟不仁，赎毒药害你身。", "兄弟见了痛伤情，哥哥自宜思忖。", "(生)舍弟是读书人至诚，无此事不须忧闷。", "(合)思之，祸福生死皆由命，果然半点不由人。"]'),
('yuanqu-1712','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','唐太宗是圣明之君，犹且杀建成。',55,'元曲/yuanqu.json','["唐太宗是圣明之君，犹且杀建成。", "哥哥莫待祸临身，临渴怎生掘井？(生)若非兄弟说着事因，险些儿遭他毒性。", "(合前)。"]'),
('yuanqu-1713','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','安享荣华，岂不念祖宗觅利艰辛！千重水面，虎口换出珠珍。',63,'元曲/yuanqu.json','["安享荣华，岂不念祖宗觅利艰辛！千重水面，虎口换出珠珍。", "你如今，海日攻书错留心。", "懒经求，不营运，待怎生？自今日不许再上我门庭！。"]'),
('yuanqu-1714','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)听禀：祖父同生，念同胞之义，手足之亲。',128,'元曲/yuanqu.json','["(小生)听禀：祖父同生，念同胞之义，手足之亲。", "读书美意，他日显耀门庭。", "(背介)思省，岂知哥哥生怒嗔？信谗言教我无投奔。", "(净、丑)我每两个为你，劝得口干舌扁，倒说信谗言，难道我每倒是谗言？如今大哥要打自打，不干我事！(小生)将我赶出门，望哥哥息怒，暂且回心。"]'),
('yuanqu-1715','锦衣香','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑)休抗拒，休回应，休要恼着哥哥，转添恶忿。',63,'元曲/yuanqu.json','["(净、丑)休抗拒，休回应，休要恼着哥哥，转添恶忿。", "且随他意暂出门，朝夕我两人劝他回心。", "倘回心转意，那时请你归来，依然弟兄和顺。"]'),
('yuanqu-1716','浆水令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','更迟疑不离我门，打教伊皮开见筋。',16,'元曲/yuanqu.json','["更迟疑不离我门，打教伊皮开见筋。"]'),
('yuanqu-1717','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)叹一身钱无半文，无相识有谁是亲？(生)你说书内有黄金，何不看书，度日营生？。',42,'元曲/yuanqu.json','["(小生)叹一身钱无半文，无相识有谁是亲？(生)你说书内有黄金，何不看书，度日营生？。"]'),
('yuanqu-1718','临江仙','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)被打出门珠泪流，教人羞耻向谁投？哥哥因甚赶无休？在他檐下过，怎敢不低头！。',41,'元曲/yuanqu.json','["(小生)被打出门珠泪流，教人羞耻向谁投？哥哥因甚赶无休？在他檐下过，怎敢不低头！。"]'),
('yuanqu-1719','皂罗袍','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(合)贺喜得他出外，自今后不许再上门阶。',68,'元曲/yuanqu.json','["(合)贺喜得他出外，自今后不许再上门阶。", "结义兄弟称心怀，同心同气同欢快。", "有茶有酒，朝往暮来。", "无愁无虑，分忧替灾，三人真个关张赛。", "(下)。"]'),
('yuanqu-1720','风马儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦上)倾国芳容正娇媚，家豪富比陶朱。',42,'元曲/yuanqu.json','["(旦上)倾国芳容正娇媚，家豪富比陶朱。", "(贴上)郎才女貌非凡比，宿缘相会，今世效于飞。"]'),
('yuanqu-1721','本宫赚','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','默默嗟吁，哽咽垂双泪。',59,'元曲/yuanqu.json','["默默嗟吁，哽咽垂双泪。", "直入画堂覆知，此事好伤悲。", "(旦)试问取，末审何人亏负你？你缘何垂双泪？不知怎地，你从头一一说与。"]'),
('yuanqu-1722','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)告且听启：小官人镇日攻书，被东人急呼至，说着几句，百般打骂赶出去。',72,'元曲/yuanqu.json','["(末)告且听启：小官人镇日攻书，被东人急呼至，说着几句，百般打骂赶出去。", "(贴)果恁的，奈我官人心性急，似撮盐入火内。", "猜着就里，又敢是听人胡语？。"]'),
('yuanqu-1723','竹马儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)他效学昔日关张结义，不思量久后有头无尾。',108,'元曲/yuanqu.json','["(旦)他效学昔日关张结义，不思量久后有头无尾。", "岂知他是调谎的，使虚心冷气，刁唆员外得如是。", "(贴)我东人枉恁地多伶俐，落圈匮总不知，把骨肉下得轻弃。", "你好直恁的，不思量手足恩深，岂知同胞义。", "谩教人无语泪双垂，说着后心碎。"]'),
('yuanqu-1724','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','自古及今结义的，除非管鲍更有谁？那一个人情得到底？院君，员外回来，怎生谏他一谏便好？(旦)是如此。',49,'元曲/yuanqu.json','["自古及今结义的，除非管鲍更有谁？那一个人情得到底？院君，员外回来，怎生谏他一谏便好？(旦)是如此。"]'),
('yuanqu-1725','清歌儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生作醉上)三杯酒万事和气，又何妨每日沉醉。',43,'元曲/yuanqu.json','["(生作醉上)三杯酒万事和气，又何妨每日沉醉。", "思量孙二太无知，伊来害我，我又如何饶你？。"]'),
('yuanqu-1726','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)员外吃得醺醺醉，我娘行自宜仔细。',40,'元曲/yuanqu.json','["(贴)员外吃得醺醺醉，我娘行自宜仔细。", "着些言语问因依，莫激他性发，好意反成恶意。"]'),
('yuanqu-1727','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)常言道要知心事，但听他口中言语。',134,'元曲/yuanqu.json','["(旦)常言道要知心事，但听他口中言语。", "不知员外怒着谁，从头至尾，说与奴家知会。", "迎春，员外醉了，且安置他睡了罢。", "(生)兄弟请酒，你吃一杯。", "(旦、贴)员外，这里是家里了。", "(生作醒介)呸！还要对你说，叵耐……(旦、贴)叵耐那个？(生)叵耐孙二无理！(旦、贴)二叔却便怎么？。"]'),
('yuanqu-1728','桂枝香','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)贤妻听启，孙荣无理。',93,'元曲/yuanqu.json','["(生)贤妻听启，孙荣无理。", "他要赎毒药害我身躯，把我家私占取。", "险些儿中了，险些儿中了，牢笼巧计。", "院君，被我赶出门去。", "(旦、贴)原来赶出去了，苦呵！(生)细思之，指望我遭毒于，我先将小计施。"]'),
('yuanqu-1729','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)同枝连气，同胞共乳。',69,'元曲/yuanqu.json','["(旦)同枝连气，同胞共乳。", "不念手足之亲，听信乔人言语。", "将兄弟赶出，将兄弟赶出，不容完聚，教人谈议。", "好痴迷，假饶染就干红色，也被傍人讲是非。"]'),
('yuanqu-1730','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)忠言不听，生出恶性。',103,'元曲/yuanqu.json','["(旦)忠言不听，生出恶性。", "(贴)把几句回他，怕怎么？(旦)欲要把几句回他，又恐怕夫妻争竞。", "只落得外人，只落得外人，胡言讲论。", "(贴)院君，外人讲论些什么来？(旦)讲论家不和顺。", "自评论，耐了一时气，家和万事成。"]'),
('yuanqu-1731','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)娘行听告，常言人道：热心闲管招非，冷眼无些烦恼。',85,'元曲/yuanqu.json','["(贴)娘行听告，常言人道：热心闲管招非，冷眼无些烦恼。", "(旦)迎春，你如今不要开口罢！(贴)奴不合口多，奴不合口多，惹得官人嗔叫，累娘焦燥。", "自今朝，闭口深藏舌，安身处处牢。"]'),
('yuanqu-1732','吴小四','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净扮王婆上)命儿孤，没丈夫。',46,'元曲/yuanqu.json','["(净扮王婆上)命儿孤，没丈夫。", "三十年来独自宿，开个店儿清又楚。", "往来官员士大夫，谁不识王大姑。"]'),
('yuanqu-1733','胡捣练','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)吾命窘，自嗟呀，哥哥同甚念头差？赶出此身无依倚，使人今夜落谁家？万事不由人计较，一生都是命安排。',130,'元曲/yuanqu.json','["(小生上)吾命窘，自嗟呀，哥哥同甚念头差？赶出此身无依倚，使人今夜落谁家？万事不由人计较，一生都是命安排。", "我孙荣被哥赶逐出来，没处安身，不免到王大姑店中借住几时，再作区处。", "此间已是了，婆婆有么？(净)呀！官人请坐。", "(小生)有坐。", "(净)官人家居何处？姓甚名谁？。"]'),
('yuanqu-1734','五更转','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)望婆婆听吾告，孙荣本富豪。',17,'元曲/yuanqu.json','["(小生)望婆婆听吾告，孙荣本富豪。"]'),
('yuanqu-1735','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','乞可怜相周庇，奈此身无所依，止求半室权居住。',64,'元曲/yuanqu.json','["乞可怜相周庇，奈此身无所依，止求半室权居住。", "有日天相吉人，依旧春风棠棣，房金价多共少当如意，决不有负相连累。", "结草衔环，报伊恩义。"]'),
('yuanqu-1736','夜行船','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生上)积玉堆金多富贵，幸遇太平年岁。',42,'元曲/yuanqu.json','["(生上)积玉堆金多富贵，幸遇太平年岁。", "(旦、贴上)今世夫妻，前缘匹配，美满共谐连理。"]'),
('yuanqu-1737','祝英台','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','草芊芊，花苒苒，轻暖艳阳天。',59,'元曲/yuanqu.json','["草芊芊，花苒苒，轻暖艳阳天。", "才子艳质，簇拥名园，嬉戏笑蹙秋千。", "排筵，好向花柳亭前，寻芳消遣。", "(合)我和你双双游赏欢宴。"]'),
('yuanqu-1738','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)俄然，笋成竿，荷展盖。',57,'元曲/yuanqu.json','["(旦)俄然，笋成竿，荷展盖。", "高柳噪新蝉。", "池畔避署，撒发披襟，欢笑同乐莲船。", "迷恋，好向流水亭前，纳凉消遣。", "(合前)。"]'),
('yuanqu-1739','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)天然，但愿人月团圆，千里共婵娟。',56,'元曲/yuanqu.json','["(贴)天然，但愿人月团圆，千里共婵娟。", "天朗气清，渐渐金风。", "时送桂花香远。", "堪羡，好向百尺楼前，玩月消遣。", "(合前)。"]'),
('yuanqu-1740','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)瞥见，朔风吹起彤云，帘幕乱飘绵。',61,'元曲/yuanqu.json','["(生)瞥见，朔风吹起彤云，帘幕乱飘绵。", "银砌玉妆，覆地漫天，都喜兆成丰年。", "(旦、贴)幽轩，尽教簇满红炉，观梅消遣。", "(合前)。"]'),
('yuanqu-1741','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(合)四时游赏多欢宴，三公不换此芳年，也是我和你夙世修来百福全。',32,'元曲/yuanqu.json','["(合)四时游赏多欢宴，三公不换此芳年，也是我和你夙世修来百福全。"]'),
('yuanqu-1742','一匹布','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净上)开食店，得多年，声名天下传。',33,'元曲/yuanqu.json','["(净上)开食店，得多年，声名天下传。", "那人久住不还钱，管取教伊吃拳。"]'),
('yuanqu-1743','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑上)方才睡，正酣眠，甚人只管缠？摩挲两眼出房前。',41,'元曲/yuanqu.json','["(丑上)方才睡，正酣眠，甚人只管缠？摩挲两眼出房前。", "我只道是谁叫，原来是阿娘老虔。"]'),
('yuanqu-1744','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)听呼唤，出房前，不知有甚言？寻思此事泪涟涟，原来是婆婆讨钱。',35,'元曲/yuanqu.json','["(小生上)听呼唤，出房前，不知有甚言？寻思此事泪涟涟，原来是婆婆讨钱。"]'),
('yuanqu-1745','刘衮','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)休剥去，休剥去，留与我遮羞。',54,'元曲/yuanqu.json','["(小生)休剥去，休剥去，留与我遮羞。", "再四哀求，不肯放手。", "(净、丑)欠债合还钱，无礼干休。", "急急剥下，可免出丑。"]'),
('yuanqu-1746','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','婆扯带，婆扯带，小二把衣袖抽，倒拽横拖，身不自由。',51,'元曲/yuanqu.json','["婆扯带，婆扯带，小二把衣袖抽，倒拽横拖，身不自由。", "(净、丑)衣服准房钱，胡乱可受。", "休得迟延，吃吾脚手。"]'),
('yuanqu-1747','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑)你即请行。',32,'元曲/yuanqu.json','["(丑)你即请行。", "迟时生受。", "(小生)吃定赶逐，无人搭救。", "(合前)。"]'),
('yuanqu-1748','山坡羊','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','乱荒荒婆婆前去。',91,'元曲/yuanqu.json','["乱荒荒婆婆前去。", "急煎煎留他不住，冷清清独立在此，懒怯怯暗自垂双泪。", "婆婆开门！我叫你，何曾应半句儿？又不是梨花带雨把门深闭，教我举目无亲倚靠谁？思之。", "思之泪暗垂。", "难捱，虚飘飘命怎期？。"]'),
('yuanqu-1749','胡捣练','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','江水远，恨悠悠，教人羞耻向谁求？枉自腹藏千古事，但趁一江清水向东流。',34,'元曲/yuanqu.json','["江水远，恨悠悠，教人羞耻向谁求？枉自腹藏千古事，但趁一江清水向东流。"]'),
('yuanqu-1750','锁南枝','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)孙员外是我兄，(外)令兄可是与柳龙卿、胡子传结义的孙华么？(小生)正是，将孙荣赶逐无投奔。',65,'元曲/yuanqu.json','["(小生)孙员外是我兄，(外)令兄可是与柳龙卿、胡子传结义的孙华么？(小生)正是，将孙荣赶逐无投奔。", "(外)你怎么不到前面店中安歇？。"]'),
('yuanqu-1751','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)听伊诉愁闷，教人不忍闻。',56,'元曲/yuanqu.json','["(外)听伊诉愁闷，教人不忍闻。", "本是同胞兄弟，你哥直恁无情，下得将伊摈。", "倘然伊富贵，他受贫，教他自寻思，可心肯？。"]'),
('yuanqu-1752','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)我身蓝缕没半文，饥寒两字难过存。',51,'元曲/yuanqu.json','["(小生)我身蓝缕没半文，饥寒两字难过存。", "又没个所在安身，又没个人怜悯。", "争似我，拚此身，丧江中，免劳困。"]'),
('yuanqu-1753','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)看伊貌聪俊，非是已下人。',84,'元曲/yuanqu.json','["(外)看伊貌聪俊，非是已下人。", "目下虽然流落，必然日后荣华，劝你捱时运。", "汉子，老夫有个所在，你可权住。", "(小生)公公，什么所在？(外)你权守困，莫恨贫，有所破瓦窑，暂安顿。"]'),
('yuanqu-1754','驻马听','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','世上为人，兄弟不亲谁是亲？须念生身父母，共乳同胞，休戚难分。',73,'元曲/yuanqu.json','["世上为人，兄弟不亲谁是亲？须念生身父母，共乳同胞，休戚难分。", "咳！孙员外，你结交终日醉醺醺，却教骨肉遭穷困。", "天理何存！任你满帆风使，终有个水穷山尽。"]'),
('yuanqu-1755','金珑璁','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生破衣上)长空云黯黯，那堪狂雪交加。',49,'元曲/yuanqu.json','["(小生破衣上)长空云黯黯，那堪狂雪交加。", "飞柳絮，舞梨花。", "孤身遭冻馁，何方干谒豪家？空叹息，自嗟呀。"]'),
('yuanqu-1756','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','天惨云迷，你看城郭村庄尽掩扉。',81,'元曲/yuanqu.json','["天惨云迷，你看城郭村庄尽掩扉。", "孙荣枉读诗书，到如今呵！一字不堪煮，怎得柴和米。", "吁！想蒙正守窑时，虽然困守破窑，还有妻儿相倚。", "似我孙荣，欲并谁为侣？回首无人形影随。"]'),
('yuanqu-1757','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','一撮糠粞，熬口粥汤充肚饥。',118,'元曲/yuanqu.json','["一撮糠粞，熬口粥汤充肚饥。", "放下连糠米，怎得这水？呸！这雪就是了。", "着上冰和水。", "这柴被雪打湿了，那里烧得着？我铺下还有一把干柴在那里，拿他来烧了，且再处。", "(作转跌介)呀！踢翻了瓦瓶儿，教我好难存济。", "冻死在窑中，做一个饥寒鬼。", "拨尽寒炉一夜灰。"]'),
('yuanqu-1758','蔷薇花','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生同净、丑上。',132,'元曲/yuanqu.json','["(生同净、丑上。", "生)严威正加，满空中如盐撒下。", "长安多少卖酒人家，料应此际增高价。", "长安三尺雪，尽道十年丰。", "二位兄弟，方才舍下吃酒，吃得不爽利，还到酒肆中去。", "(净、丑)前面新开一个酒馆在那里。", "(走介)酒家有么？(末上)造成春夏秋冬酒，卖与东西南北人。", "三位官人请上楼去。"]'),
('yuanqu-1759','驻云飞','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','酒保无知，故意教他来笑耻。',57,'元曲/yuanqu.json','["酒保无知，故意教他来笑耻。", "堪恨乔才辈，恼得心儿碎。", "呸！吃了这场亏，教人呕气。", "吃得醺醺。", "拚却今宵醉，痛饮前村踏雪山。"]'),
('yuanqu-1760','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑)前缘夙世做知交，赛关张强如管鲍，相携同步不辞劳。',43,'元曲/yuanqu.json','["(净、丑)前缘夙世做知交，赛关张强如管鲍，相携同步不辞劳。", "柳绵飘，梨花飞绕。", "(合前)。"]'),
('yuanqu-1761','蛮牌令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','哥哥占田庄，教兄弟受凄凉。',73,'元曲/yuanqu.json','["哥哥占田庄，教兄弟受凄凉。", "本是同胞养，又不是两爹娘。", "我穿的是粗衣破裳，你吃的是美洒肥羊。", "哥哥嗄！心下自思量，白忖量，若不思量后，分明是铁打心肠！。"]'),
('yuanqu-1762','绣停针','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','先自悲伤，又遭一跌痛怎当。',141,'元曲/yuanqu.json','["先自悲伤，又遭一跌痛怎当。", "抬身忍痛回头望，见一汉酒醉倒在街傍。", "汉子，你吃得这般大醉，倒在此雪里，何不省一口与我孙荣吃了，你也不见得这等醉了，我也不见得这般饥寒。", "我把古人比与你听：本待学刘伶入醉乡；你如今倒在雪里，又像一个古人，好一似卧冰王祥。", "呀！看看冷逼寒冻神魂丧，早难道酒解愁肠。"]'),
('yuanqu-1763','雁过南楼','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','我待不管他，欲待不睬他。',68,'元曲/yuanqu.json','["我待不管他，欲待不睬他。", "(作走，内扮土地扯住介)放手，放手！后面有人似扯住了咱，莫不是孙荣有些牵挂？回头看他，回头看他，不由人两泪如麻。"]'),
('yuanqu-1764','下山虎','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','有一个醉汉倒在街坊，大雪纷纷下，看着惨伤。',80,'元曲/yuanqu.json','["有一个醉汉倒在街坊，大雪纷纷下，看着惨伤。", "我好意教你开门早商量，笼些火焰，教他吃口滚汤。", "救人一命活，胜造七级浮屠福寿昌。", "你若不开门，后倘或死亡，带累邻家遭祸殃。"]'),
('yuanqu-1765','园林杵歌','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','这容庞，好似孙大郎。',100,'元曲/yuanqu.json','["这容庞，好似孙大郎。", "(惊介)唬得我魂飘荡，退后趋前心意忙。", "那堪柳絮梨花下得恁狂。", "似这般冷飕飕，寒凛凛，哥哥怎当？自忖量，自感伤，怕这雪冻死了兄长。", "怎禁得扑簌簌泪出痛肠！哥哥，你和柳龙卿、胡子传出来，。"]'),
('yuanqu-1766','望歌儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','三人踏雪同宴赏，他两个先自回归，撇你在长街上。',70,'元曲/yuanqu.json','["三人踏雪同宴赏，他两个先自回归，撇你在长街上。", "(生作醉语介)二位贤弟赛关张。", "(小生)口是心非，休想赛关张！到此方知他调谎，从今后休把亲撇漾。"]'),
('yuanqu-1767','罗帐里坐','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','欲送你到家，寻思惨伤。',53,'元曲/yuanqu.json','["欲送你到家，寻思惨伤。", "哥哥酒醒，祸起萧墙。", "谁教你上门自取灾映！只愁雪上更加箱，这顿拳头怎当！(背生走介)。"]'),
('yuanqu-1768','江头送别','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','哥哥的，哥哥的倚强恃长。',41,'元曲/yuanqu.json','["哥哥的，哥哥的倚强恃长。", "亲兄弟，亲兄弟意怎敢忘？好歹背你回家去，山可哥打骂何妨！。"]'),
('yuanqu-1769','忆多娇','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','兄见短，咱见长。',95,'元曲/yuanqu.json','["兄见短，咱见长。", "哥哥，你把身子略放松些便好，那知做兄弟的，两三日没有水米打牙，你是这等拖住了，教我那里背得起？苦嗄！我全无气力，须当勉强。", "念取同胞亲兄长，手足之情，手足之情，怕甚山遥路长！。"]'),
('yuanqu-1770','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','看看背过平康巷，哥哥酒醒从头想，兄弟是嫡亲结义的都是谎。',28,'元曲/yuanqu.json','["看看背过平康巷，哥哥酒醒从头想，兄弟是嫡亲结义的都是谎。"]'),
('yuanqu-1771','醉中归','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦上)晚来云布密，凛凛朔风送寒威。',70,'元曲/yuanqu.json','["(旦上)晚来云布密，凛凛朔风送寒威。", "俄然见六出花飞，长空一色，万里如银砌。", "(贴上)当此际，雪正飞，庆赏丰年祥瑞。", "同宴乐排筵，满饮羊羔拚沉醉。"]'),
('yuanqu-1772','泣颜回','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)他从早离门儿。',75,'元曲/yuanqu.json','["(旦)他从早离门儿。", "(小生)与谁为伴？(旦)与两个乔人排会，终朝宴乐，他两个却自先回。", "若非小叔，险些儿冻死在深雪里。", "背归来再生人世，不知他倒在何处？。"]'),
('yuanqu-1773','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)纷纷触目柳花飞，奈我无食无衣。',61,'元曲/yuanqu.json','["(小生)纷纷触目柳花飞，奈我无食无衣。", "荡风冒雪，干谒有谁怜敢？担饥受冷，到黄昏独自回窑去，见吾兄倒在雪里，是孙荣背负回归。"]'),
('yuanqu-1774','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)谢得恩意赐饭食，只恐哥哥酒醒禁持，劈面便打，不如忍饿回归。',86,'元曲/yuanqu.json','["(小生)谢得恩意赐饭食，只恐哥哥酒醒禁持，劈面便打，不如忍饿回归。", "(旦)叔叔休虑，你哥哥酒醉常贪睡。", "(小生)醒来怎么好？(旦)醒来我自支持，我妇人家岂怕男儿？(贴持饭上)。"]'),
('yuanqu-1775','赚','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','韩信当时，漂母哀怜赐与食，时运至，拜将封侯多富贵。',88,'元曲/yuanqu.json','["韩信当时，漂母哀怜赐与食，时运至，拜将封侯多富贵。", "二官人请饭。", "(小生接作吃介，生伸腰，小生慌堕箸介)呀！唬得我一双箸拿不住放不得，一口饭吞不进吐不出，嫂赐食，一似吕太后的筵席。"]'),
('yuanqu-1776','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)遍身泥水，满头巾似银铺砌。',102,'元曲/yuanqu.json','["(旦)遍身泥水，满头巾似银铺砌。", "员外，你每常间和柳龙卿、胡子传两个，吃得酒淹衫袖湿，花压帽檐低，撇下得赛关张亲兄弟。", "(小生)嫂嫂，你曾说与，哥哥酒醒自支持，一声喝起先惊惧。", "兀的是妇人家那怕男儿，去留无计。"]'),
('yuanqu-1777','扑灯蛾','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)打伊泼丑生，怎敢到此处！恶向胆边生，教人怒从心起也。',67,'元曲/yuanqu.json','["(生)打伊泼丑生，怎敢到此处！恶向胆边生，教人怒从心起也。", "(小生)适来路里，见吾兄倒在街衢。", "是孙荣背负你归，多谢得贤达嫂嫂留住赐乞食。"]'),
('yuanqu-1778','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)这乞才不道理。',161,'元曲/yuanqu.json','["(生)这乞才不道理。", "(又打介。", "旦)员外，你倒在雪里，就是别人背了你回来，也要与他些酒钱。", "一个嫡亲兄弟，背了你回来，你怎么只管要打他？(生)我早上带十三锭钞出去，八锭买了羊脂玉环，三锭还了酒钱，还剩两锭钞与玉环，都在靴桶里。", "若在便罢了，若没有，一定是他偷了。", "迎春看来！(贴应看介)没有。", "(旦)那一只再看。", "(贴又看介)也没有。"]'),
('yuanqu-1779','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)望息雷电威，可怜小兄弟，本是好心肠，谁想反成恶意也！(生)你一身穷困，敢起着不良之意。',78,'元曲/yuanqu.json','["(小生)望息雷电威，可怜小兄弟，本是好心肠，谁想反成恶意也！(生)你一身穷困，敢起着不良之意。", "把还我饶你去离，稍迟延打教你一命丧泉世。", "(打介，旦、贴劝介)。"]'),
('yuanqu-1780','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)休得发怒起，思量大道理，他拐钱拿宝贝，如何敢来此处也？(贴)望官人回嗔作喜，好念着同胞兄弟。',68,'元曲/yuanqu.json','["(旦)休得发怒起，思量大道理，他拐钱拿宝贝，如何敢来此处也？(贴)望官人回嗔作喜，好念着同胞兄弟。", "到如今失物怨谁，自不合好酒沈醉倒雪里。"]'),
('yuanqu-1781','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)官人且请归房内，叔叔回归下处，待等明朝复探取。',26,'元曲/yuanqu.json','["(旦)官人且请归房内，叔叔回归下处，待等明朝复探取。"]'),
('yuanqu-1782','胜胡芦','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净)我算一年本利，该着二十锭钞也么喳。',90,'元曲/yuanqu.json','["(净)我算一年本利，该着二十锭钞也么喳。", "算也算得好，说也说得好，番来覆去，覆去番来算得好。", "(丑)我算二年本利，该着四十锭钞也么喳。", "算也算得好，说也说得好，番来覆去，覆去番来算得好。"]'),
('yuanqu-1783','贺新郎','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑)夜来因吃酒，大雪中跌倒孙兄，让他落后。',72,'元曲/yuanqu.json','["(净、丑)夜来因吃酒，大雪中跌倒孙兄，让他落后。", "拿了他靴中两锭钞，又把玉环拐走。", "怎知今日跌破，我两个如蓝提水走归家，篮内何曾有？干呕气，惹场羞。"]'),
('yuanqu-1784','赏宫花','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)你两个歹凶，拐钱图使用。',45,'元曲/yuanqu.json','["(末)你两个歹凶，拐钱图使用。", "怎知遇着我，你手拿空。", "(合)好似雁从天上过，急忙归去炒油葱。"]'),
('yuanqu-1785','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净)当初放钱，十年本利浓。',29,'元曲/yuanqu.json','["(净)当初放钱，十年本利浓。", "扣算钱无数，总成空。", "(合前)。"]'),
('yuanqu-1786','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑)钱落手中，寻思跌破凶。',29,'元曲/yuanqu.json','["(丑)钱落手中，寻思跌破凶。", "干与他将去，杳无踪。", "(合前)。"]'),
('yuanqu-1787','梁州令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦同贴上，旦)默默思量怨我夫，赶兄弟无辜。',45,'元曲/yuanqu.json','["(旦同贴上，旦)默默思量怨我夫，赶兄弟无辜。", "(贴)弃亲结义两无徒，忠言谏，生嗔怒，反不足。"]'),
('yuanqu-1788','雁过声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)昨宵际晚时，见小叔背负员外归。',94,'元曲/yuanqu.json','["(旦)昨宵际晚时，见小叔背负员外归。", "穿一领百衲破衣，睚睚瘦得不中觑，铁心肠见了珠泪垂。", "(贴)一饭未曾举箸，员外酒醒喝起，便道他偷了环儿。", "更不分说几句，便拳踢乱打逐出去，破窑内受苦伊怎知！。"]'),
('yuanqu-1789','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)小叔知礼攻书，又怎肯怀着恶意？信他人搬喋是非，把亲生兄弟逐出去，每日劝戒不听取。',120,'元曲/yuanqu.json','["(旦)小叔知礼攻书，又怎肯怀着恶意？信他人搬喋是非，把亲生兄弟逐出去，每日劝戒不听取。", "(贴)同胞共乳，手足之义，割舍把他轻弃，将家私恃长不分取。", "小官人晓诗书，知礼义，尽让兄不肯说，他又何曾说是说非？(合)论得来谁是谁不是，何日劝得心意回？。"]'),
('yuanqu-1790','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','镇日坦饮酒杯，等待得他不醉归，再把忠言相劝取。',23,'元曲/yuanqu.json','["镇日坦饮酒杯，等待得他不醉归，再把忠言相劝取。"]'),
('yuanqu-1791','三台令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)夜来背负兄归，冤我偷了环儿。',33,'元曲/yuanqu.json','["(小生上)夜来背负兄归，冤我偷了环儿。", "心下自伤悲，好教我泪珠暗垂。"]'),
('yuanqu-1792','七贤过关','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','三人共赏雪，吃得醺醺醉。',90,'元曲/yuanqu.json','["三人共赏雪，吃得醺醺醉。", "撇我哥哥跌倒在深雪里，他两个撇了你自先回。", "却不道赛过关张有义气？冷清清冻死你做街头鬼，又还是孙荣背负你归。", "孙员外，你临危不见了赛关张，方信道打虎还须亲兄弟。"]'),
('yuanqu-1793','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)宅上事如麻，都要去解，那得工夫前来。',48,'元曲/yuanqu.json','["(末)宅上事如麻，都要去解，那得工夫前来。", "出于我无奈，非不用心，非不挂怀。", "望东人凡百事可怜担带。"]'),
('yuanqu-1794','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)见官人珠泪满腮，骨瘦如柴，后全没些光彩。',56,'元曲/yuanqu.json','["(末)见官人珠泪满腮，骨瘦如柴，后全没些光彩。", "有十贯现钱，舍的自己财，将不出来，端的是少些休怪。", "(小生不受介)。"]'),
('yuanqu-1795','福清歌','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','见着你每，珠泪暗倾，思往日教人懊恨！(末)见官人，没精神。',57,'元曲/yuanqu.json','["见着你每，珠泪暗倾，思往日教人懊恨！(末)见官人，没精神。", "遣吴忠珠泪流，似刀剜碎心。", "(合)受饥寒，煞害得壁尽离倾。"]'),
('yuanqu-1796','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)听说事因，贤达院君常劝戒官人不听。',51,'元曲/yuanqu.json','["(末)听说事因，贤达院君常劝戒官人不听。", "(小生)守清贫，且安分。", "去谒高门求口食，路上哀告人。", "(合前)。"]'),
('yuanqu-1797','香柳娘','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)把家私占了，把家私占了，因甚不争竞？只因要我家法正。',84,'元曲/yuanqu.json','["(小生)把家私占了，把家私占了，因甚不争竞？只因要我家法正。", "我宁可受苦，我宁可受苦，不敢怨家兄，教人自愁闷。", "(合)在破窑中冷落，在破窑中冷落，举目谁人是亲？闷怀无尽！。"]'),
('yuanqu-1798','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)告官人放心，告官人放心，且休愁闷，人若孝悌天心顺。',57,'元曲/yuanqu.json','["(末)告官人放心，告官人放心，且休愁闷，人若孝悌天心顺。", "但朝夕院君，但朝夕院君，劝戒我东人，不久自回心。", "(合前)。"]'),
('yuanqu-1799','菊花新','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生上)细思孙二煞无徒，使计藏奸要害吾。',34,'元曲/yuanqu.json','["(生上)细思孙二煞无徒，使计藏奸要害吾。", "虽然赶出去，遭穷困此身蓝缕。"]'),
('yuanqu-1800','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','今朝我夫不沉醉，独坐书斋看古书。',30,'元曲/yuanqu.json','["今朝我夫不沉醉，独坐书斋看古书。", "前去问因依，忠言劝愿回心意。"]'),
('yuanqu-1801','绛都春序','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','平生恋色，有忠臣伍奢，直谏获罪。',75,'元曲/yuanqu.json','["平生恋色，有忠臣伍奢，直谏获罪。", "伊儿伍尚，入朝齐杀取。", "有次子伍员，不肯赴召，欲报父兄之冤。", "子胥奔走吴国里，借兵马投入楚地。", "两军交战鸣鼙，金鼓震动天地。"]'),
('yuanqu-1802','降黄龙','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)吴国兵强，遂起兵征战，楚国难敌。',84,'元曲/yuanqu.json','["(旦)吴国兵强，遂起兵征战，楚国难敌。", "昭王败走，到楚江无渡，心下踌躇。", "(生)那时节怎么了？(旦)昭王正在忧疑之际，移时见一艄子，驾一叶扁舟来至，救昭王御弟夫人太子离去。"]'),
('yuanqu-1803','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','俄然风浪滔天，荡却船儿把身不住。',228,'元曲/yuanqu.json','["俄然风浪滔天，荡却船儿把身不住。", "船艄奏启告我王，请一位疏者落水。", "船艄奏曰：\"告我王，小船不堪重载，况风浪太急，告我王，请一位疏者落水，\"昭王曰：\"船内寡人、御弟、夫人、太子四人，皆是我亲，那一位是疏者？\"船艄曰：\"若不请一位下水，恐害一船性命。", "\"当时有御弟欠身而起：\"小臣情愿下水。", "\"昭王扯住衣袖道：\"御弟不可，不可！兄弟手足之义，如何使得！\"当时夫人欠身而起道：\"子童情愿下水。", "\"那昭王就无语。", "夫人欠身而起，奈顷刻天惨云迷，似落花趁着流水，悠悠大江东去。"]'),
('yuanqu-1804','黄龙滚','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','太子泪双垂，太子泪双垂，投入江儿水。',51,'元曲/yuanqu.json','["太子泪双垂，太子泪双垂，投入江儿水。", "风静浪平，楚王蹬岸离船去。", "暗忆太子，偷弹珠泪，投西楚往晋国奔逃去。"]'),
('yuanqu-1805','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','身与申包胥，身与申包胥，领着精兵至，来救昭王，遂与吴军相迎敌。',51,'元曲/yuanqu.json','["身与申包胥，身与申包胥，领着精兵至，来救昭王，遂与吴军相迎敌。", "两国争战，杀吴军退，群臣会请昭王回朝去。"]'),
('yuanqu-1806','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','再整旧华夷，再整旧华夷，重睹江山丽。',49,'元曲/yuanqu.json','["再整旧华夷，再整旧华夷，重睹江山丽。", "满朝朱紫，依旧还朝内。", "再立妃子，安居宫里，俄然又生太子昭王喜。"]'),
('yuanqu-1807','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','妻子易得之，妻子易得之，兄弟难轻弃。',53,'元曲/yuanqu.json','["妻子易得之，妻子易得之，兄弟难轻弃。", "若还死去时，算来难得重相会。", "两班文武，山呼声沸，扬尘罢舞蹈毕，皆欢喜。"]'),
('yuanqu-1808','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','一时楚国封登位，万民乐业太平时，致使流传作话儿。',31,'元曲/yuanqu.json','["一时楚国封登位，万民乐业太平时，致使流传作话儿。", "(贴捧茶上)。"]'),
('yuanqu-1809','引子','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','生居画阁兰堂里，忽听院君言语。',28,'元曲/yuanqu.json','["生居画阁兰堂里，忽听院君言语。", "千般百计，只为员外不听取。"]'),
('yuanqu-1810','普天乐','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)看一本楚昭王真贤慧，弃妻子怜兄弟。',76,'元曲/yuanqu.json','["(旦)看一本楚昭王真贤慧，弃妻子怜兄弟。", "伊不念共乳同胞，割舍赶他出去。", "念小叔真狼狈，我夫哀怜回心意，破窑内收取兄弟回归，同享富贵。", "效昭王爱亲，休学曹丕。"]'),
('yuanqu-1811','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)偶因观《三国志》，曹操子曹丕的，因兄弟广记多才，七步已成诗句。',76,'元曲/yuanqu.json','["(生)偶因观《三国志》，曹操子曹丕的，因兄弟广记多才，七步已成诗句。", "兄妒忌恐怕他夺位，定计施谋杀兄弟。", "我端详细察因依，兄杀弟有理。", "曹丕见识，正合着我意。"]'),
('yuanqu-1812','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)告官人听咨启，岂不晓其中意？我娘行贤达聪明，提说故事比喻。',73,'元曲/yuanqu.json','["(贴)告官人听咨启，岂不晓其中意？我娘行贤达聪明，提说故事比喻。", "曹丕妒忌休学取，愿学昭王怜兄弟。", "望员外息怒停嗔，从是改非。", "赛过关张，到底都是乔的。"]'),
('yuanqu-1813','梁州序','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)员外，你和他结义，心肠奸狡，到底不是坚牢。',86,'元曲/yuanqu.json','["(旦)员外，你和他结义，心肠奸狡，到底不是坚牢。", "心非口是，只恐笑里藏刀。", "(生)是我三人结义，赛过关张，永远学管鲍。", "你不知就里乱言敢胡道。", "(旦)恐怕将来没下梢，空惹得外人笑。"]'),
('yuanqu-1814','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)伊家不晓，思之失笑。',77,'元曲/yuanqu.json','["(生)伊家不晓，思之失笑。", "妇人家有甚机谋，言三语四，只管絮絮叨叨。", "(旦)自古常言人道，逆耳忠言，苦口良药妙。", "劝君不省反焦躁，冷地思量自烦恼，舌果是斩身刀。"]'),
('yuanqu-1815','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)转念取同乳同胞，忍教他一身无靠？破窑中寂寞，怨恨难消。',80,'元曲/yuanqu.json','["(贴)转念取同乳同胞，忍教他一身无靠？破窑中寂寞，怨恨难消。", "(旦)他每日沿街哀告，告人求食，受苦伤怀抱。", "你每日常快乐醉陶陶。", "(生)不道孙荣志量高，赎毒药害吾曹。"]'),
('yuanqu-1816','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)是甚人说起根苗？扯着他当官陈告。',78,'元曲/yuanqu.json','["(旦)是甚人说起根苗？扯着他当官陈告。", "葫芦提赶打，好没分晓。", "(生)从此今朝为始，休得多言多语寻烦恼。", "前生注定不相饶，兄弟不和都是命里招。", "(旦)劝员外免煎熬。"]'),
('yuanqu-1817','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','敬重他人如珍宝，把亲者轻如粪草，劝谏不从空自恼。',24,'元曲/yuanqu.json','["敬重他人如珍宝，把亲者轻如粪草，劝谏不从空自恼。"]'),
('yuanqu-1818','那吒令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净)子传听说因依，咱每和你商议。',32,'元曲/yuanqu.json','["(净)子传听说因依，咱每和你商议。", "夜来忽地生一计，说起教伊欢喜。"]'),
('yuanqu-1819','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑)骗人钱钞环儿，指望于分入己。',32,'元曲/yuanqu.json','["(丑)骗人钱钞环儿，指望于分入己。", "怎知跌破那环儿，钞与别人将去。"]'),
('yuanqu-1820','行香子','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)日有阴晴，月有亏盈，算人无久富长贫。',44,'元曲/yuanqu.json','["(小生上)日有阴晴，月有亏盈，算人无久富长贫。", "秋来自然黄叶飘零，到春来，花重吐，柳拖金。"]'),
('yuanqu-1821','风入松','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','岂不闻伊尹未逢时，(净、丑)又来通文了。',41,'元曲/yuanqu.json','["岂不闻伊尹未逢时，(净、丑)又来通文了。", "(小生)向莘野锄耕。", "(净、丑)还有谁来？。"]'),
('yuanqu-1822','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)时人何异古时人？自古贤愚不等。',91,'元曲/yuanqu.json','["(小生)时人何异古时人？自古贤愚不等。", "(净、丑)如何见得贤愚？(小生)贤者正直无谗佞，愚蠢的言而无信，处处有君子小人。", "(净、丑)君子小人固有，我两个比众不同。", "(小生)吾一日三省其身。"]'),
('yuanqu-1823','急三枪','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)我一时穷，一箪食，一瓢饮。',65,'元曲/yuanqu.json','["(小生)我一时穷，一箪食，一瓢饮。", "常忧道，不忧贫。", "(净)只是这般，几时会发迹？(小生)我多豪迈，多才调，多聪俊，管一跃，跳过龙门。"]'),
('yuanqu-1824','风入松','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)与哥哥一个父娘生，却把我做陌路之人。',40,'元曲/yuanqu.json','["(小生)与哥哥一个父娘生，却把我做陌路之人。", "(净、丑)怎么他又发迹，你又贫苦？。"]'),
('yuanqu-1825','急三桅','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)败风俗，歹言语怎听？没家法，坏乱人伦。',60,'元曲/yuanqu.json','["(小生)败风俗，歹言语怎听？没家法，坏乱人伦。", "(净、丑)我两个替你告如何？(小生)逞奸狡，刁唆人告论，君子貌，小人心！。"]'),
('yuanqu-1826','风入松','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)你与哥哥结义胜嫡亲，敢恁的反面忘恩！我哥哥行使些糖蜜口，我根底刁唆休论。',59,'元曲/yuanqu.json','["(小生)你与哥哥结义胜嫡亲，敢恁的反面忘恩！我哥哥行使些糖蜜口，我根底刁唆休论。", "我哥哥有眼何曾识好人？你只宜假不宜真。"]'),
('yuanqu-1827','博头钱','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)你好忒胡逞！你好不本分！教我争，你有何安稳？(净、丑)不听道，忒煞村！不依教，该受贫。',66,'元曲/yuanqu.json','["(小生)你好忒胡逞！你好不本分！教我争，你有何安稳？(净、丑)不听道，忒煞村！不依教，该受贫。", "(外)算来贫富是前因，皆由命岂由人！。"]'),
('yuanqu-1828','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑)你好忒执性！你好不思忖！好言语你每全不听。',105,'元曲/yuanqu.json','["(净、丑)你好忒执性！你好不思忖！好言语你每全不听。", "(小生)不论告，由我每。", "不争竞，由我每。", "(净、丑)全然不忖骂咱每，犹兀自假惺惺！忠言逆耳，反生怒嗔。", "良药苦口，敢恶骂人！(外)大家休得要争竞，莫失信，且安分。"]'),
('yuanqu-1829','腊梅花','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴上)光阴荏苒疾似箭，追思往事怎生言，遣人珠泪涟。',42,'元曲/yuanqu.json','["(贴上)光阴荏苒疾似箭，追思往事怎生言，遣人珠泪涟。", "去时节暖阁排筵，转眼清明在目前。"]'),
('yuanqu-1830','挂真儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','几阵催花雨初霁，和风至艳阳天气。',81,'元曲/yuanqu.json','["几阵催花雨初霁，和风至艳阳天气。", "(贴)清白微黄，娇红嫩绿，妆点名园佳致。", "(旦)窗外日光弹指过，庭前花影座间移。", "迎春，时光似箭，自从小官人被员外赶出，不觉又半载矣。"]'),
('yuanqu-1831','锦上花','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)你说与王老听，明日东人要上坟。',79,'元曲/yuanqu.json','["(旦)你说与王老听，明日东人要上坟。", "劝官人须教三省，休恁痴迷执性。", "结义两无情，亲者到底只是亲。", "(合)将兄弟赶出门，非亲却是亲。", "仗托王公直语忠言，劝官人回转心。"]'),
('yuanqu-1832','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)那王老九十三岁，伏侍祖上亲。',52,'元曲/yuanqu.json','["(贴)那王老九十三岁，伏侍祖上亲。", "也须听从今改正，撇了结交的，思念手足亲。", "休得把至亲如陌路人。", "(合前)。"]'),
('yuanqu-1833','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑)思之自古常言，家和万事成。',53,'元曲/yuanqu.json','["(丑)思之自古常言，家和万事成。", "我东人怎不思省？转教安童前去，请王老劝官人。", "兀的不是谢得贤院君。", "(合前)。"]'),
('yuanqu-1834','出队子','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外扮白须王老上)银须霜鬓，世。',16,'元曲/yuanqu.json','["(外扮白须王老上)银须霜鬓，世。"]'),
('yuanqu-1835','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑上)跋涉古道，不惮迢迢去路遥，院君严命敢辞劳！王老忠言劝必好，真个是妻贤夫祸少。',42,'元曲/yuanqu.json','["(丑上)跋涉古道，不惮迢迢去路遥，院君严命敢辞劳！王老忠言劝必好，真个是妻贤夫祸少。"]'),
('yuanqu-1836','古针线厢','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','劝解不听，未审东人却怎生。',63,'元曲/yuanqu.json','["劝解不听，未审东人却怎生。", "只听结义相调引，割舍背义忘恩。", "小官人从来本分，平白地赶出门庭。", "(合)若得劝回心，取回兄弟，永远和顺。"]'),
('yuanqu-1837','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)世上为人，兄弟不亲谁是亲？不思共乳同胞义，又不念手足之恩。',53,'元曲/yuanqu.json','["(外)世上为人，兄弟不亲谁是亲？不思共乳同胞义，又不念手足之恩。", "我如今和伊到城，说几句劝我东人。", "(合前)。"]'),
('yuanqu-1838','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑)不必入城，明日东人要上坟。',53,'元曲/yuanqu.json','["(丑)不必入城，明日东人要上坟。", "若蒙劝解回心转，男儿感得恩深。", "太公曾伏侍他祖亲，忠言语不敢不听。", "(合前)。"]'),
('yuanqu-1839','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)老倒无成，九十三年是他门下人。',54,'元曲/yuanqu.json','["(外)老倒无成，九十三年是他门下人。", "来朝亲诣坟头去，管取劝他回心。", "自古来帝君有臣，无纳谏忠言听信。", "(合前)。"]'),
('yuanqu-1840','粉蝶儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生上)才过烧灯，不觉又逢寒食，草铺茵万花堆绮。',52,'元曲/yuanqu.json','["(生上)才过烧灯，不觉又逢寒食，草铺茵万花堆绮。", "(旦上)向西郊，堪玩赏，红娇绿媚。", "步西郊，山阴右军修禊。"]'),
('yuanqu-1841','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)阳和天气，阳和天气，梅子青青燕子飞。',86,'元曲/yuanqu.json','["(旦)阳和天气，阳和天气，梅子青青燕子飞。", "春随人意，催花雨细，绽开群蕊。", "海棠胭脂染，娇如美女，动人情意儿。", "见游蜂趁粉蝶，往来园内。", "争如共伊不暂离，同携手闹花丛里。", "(合前)。"]'),
('yuanqu-1842','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)游人如蚁，游人如蚁，紫陌红尘拂面飞。',85,'元曲/yuanqu.json','["(生)游人如蚁，游人如蚁，紫陌红尘拂面飞。", "秋千蹙起，夭桃临水，翠柳盈堤。", "牡丹独豪贵，百花怎比？翠红深处，见才子共佳人，并肩低语。", "踏青斗草撒满地，贪欢宴堕簪遣珥。", "(合前)。"]'),
('yuanqu-1843','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)山阴佳趣，山阴佳趣，想羲之当日设筵席。',87,'元曲/yuanqu.json','["(旦)山阴佳趣，山阴佳趣，想羲之当日设筵席。", "群贤毕会，兰亭修禊，至今留题。", "恣赏名园内，千葩万卉，鼓乐盈耳。", "见齐郎共麻婆，舞得仡戏。", "争如我共伊沈醉归，霓裳舞柳腰纤细。", "(合前)。"]'),
('yuanqu-1844','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','悲欢离合情千古，雪月风花景四时，女貌郎才能有几？。',25,'元曲/yuanqu.json','["悲欢离合情千古，雪月风花景四时，女貌郎才能有几？。"]'),
('yuanqu-1845','庆青春','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)芳草铺茵，夭桃喷火，丝丝细柳拖金。',198,'元曲/yuanqu.json','["(小生上)芳草铺茵，夭桃喷火，丝丝细柳拖金。", "捻指光阴，使人无限伤情。", "归家暖阁排宴饮，才过了除夕，正遇元宵，游赏花灯，又早清明。", "感叹孩儿孝顺情，痛思父母泪偷零。", "去年记得兄和弟，同到坟前拜祖亲。", "今岁里，赶出门，哥哥豪富我身贫。", "正是坟前不敢高声哭，恐怕人闻也断魂。", "今日却是清明佳节，孙荣别无孝顺，寻得一陌纸钱，叫化得半瓶酒在此，不免去祖宗父母坟前拜扫，聊表孙荣穷孝顺。", "说话之间，已到父母坟前。", "(哭介)。"]'),
('yuanqu-1846','雁过沙','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','想爹娘养孙荣，抚养已艰辛，三年乳哺恩爱深，推干就湿多劳顿。',49,'元曲/yuanqu.json','["想爹娘养孙荣，抚养已艰辛，三年乳哺恩爱深，推干就湿多劳顿。", "养儿长成，爹娘一命倾，痛思我父母珠泪零。"]'),
('yuanqu-1847','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','佳节是清明，孙荣拜坟庭，思量起珠泪零。',53,'元曲/yuanqu.json','["佳节是清明，孙荣拜坟庭，思量起珠泪零。", "爹娘，望你阴中受领。", "一杯鲁酒列芳庭，一陌纸钱直得甚？表扬小儿穷孝心。"]'),
('yuanqu-1848','梧桐树','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑)官人听我言：世事只如此。',64,'元曲/yuanqu.json','["(丑)官人听我言：世事只如此。", "只重衣衫，那重人贤慧！如今只重钱和势，你恁贫寒识甚高低？一领布衫，比不得咱每的？何须共你争闲气！。"]'),
('yuanqu-1849','多娇面','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)见吴忠，珠泪倾，许多时不见你每头影，你缘何背主忘恩？思量你好没人情！。',39,'元曲/yuanqu.json','["(小生)见吴忠，珠泪倾，许多时不见你每头影，你缘何背主忘恩？思量你好没人情！。"]'),
('yuanqu-1850','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)告官人，听拜禀。',36,'元曲/yuanqu.json','["(末)告官人，听拜禀。", "宅门里每日忙奔，念吴忠委实官身，不由己一言难尽！。"]'),
('yuanqu-1851','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑跪介)见官人，忠孝心，思量后口头忒紧，不合出言伤触了大人，如今悔之不尽。',38,'元曲/yuanqu.json','["(丑跪介)见官人，忠孝心，思量后口头忒紧，不合出言伤触了大人，如今悔之不尽。"]'),
('yuanqu-1852','夜行船','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生上)日暖融和景明媚，和风扇夜开琼蕊。',43,'元曲/yuanqu.json','["(生上)日暖融和景明媚，和风扇夜开琼蕊。", "(末、丑)古墓坟头，儿孙来至，列香纸祭之以礼。"]'),
('yuanqu-1853','石竹花','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','时遇寒食感孝情，办虔心特来拜坟。',54,'元曲/yuanqu.json','["时遇寒食感孝情，办虔心特来拜坟。", "一杯美酒浇奠，使人不觉泪零。", "纸钱高挂坟头，略表孝情。", "酒肴罗列坟头，乞赐受领。"]'),
('yuanqu-1854','柳絮飞','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑上)闻知道哥哥上坟，上坟，强如拾得珠珍，珠珍。',46,'元曲/yuanqu.json','["(净、丑上)闻知道哥哥上坟，上坟，强如拾得珠珍，珠珍。", "急急前来问事因，结义人算来强如手足亲。"]'),
('yuanqu-1855','忆多娇','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)生事之，死葬之，祭之以礼浇奠取。',64,'元曲/yuanqu.json','["(生)生事之，死葬之，祭之以礼浇奠取。", "(净偷酒吃介。", "生)兄弟，你方才筛的酒，怎么不见了？(丑)想是孙阿伯吃了。", "(净)待我来斟酒。"]'),
('yuanqu-1856','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','你两个是死鬼，我两个是活鬼，有名叫做拖狗皮。',37,'元曲/yuanqu.json','["你两个是死鬼，我两个是活鬼，有名叫做拖狗皮。", "买些生姜，擦出眼泪。", "(合前)。"]'),
('yuanqu-1857','园林好','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','听老夫从头拜覆，这画儿略堪驻目。',16,'元曲/yuanqu.json','["听老夫从头拜覆，这画儿略堪驻目。"]'),
('yuanqu-1858','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)是田真兄弟和媳妇，这妇人叫田三嫂。',119,'元曲/yuanqu.json','["(外)是田真兄弟和媳妇，这妇人叫田三嫂。", "(净、丑)田三嫂是搅家精。", "(外)这妇女刁唆他丈夫，要兄弟分开两处。", "(生)他丈夫怎么说？(外)夫见说便推阻。", "田广和妻说：\"我兄弟三人有愿在前，若要分时，待门首紫荆花树死，方可分开。", "\"直待花树死便分居。"]'),
('yuanqu-1859','忒忒令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)那妇女每心肠太毒，见不从便生嫉妒。',74,'元曲/yuanqu.json','["(外)那妇女每心肠太毒，见不从便生嫉妒。", "暗藏奸计，等男儿出去，这妇人等他丈夫出去了，(生)却怎的？(外)将门道紫荆花，把长钉钉，热汤泼，教花死树枯。"]'),
('yuanqu-1860','沉醉东风','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)奈田真哭泣痛苦。',144,'元曲/yuanqu.json','["(外)奈田真哭泣痛苦。", "田真哭一会去了，两兄弟也泪珠扑簌。", "两兄弟也哭一会去了。", "只因这场痛哭，惊动了上界玉帝，见他兄弟不忍分开，洒下甘露来，救活了此树。", "感天地暗相扶，花开如故。", "三弟兄道：\"先因树死分居，如今荆树重生，我兄弟也该重合了。", "\"弟和兄再成一处，依然手足，同居如故。", "因此上义居流传万古。"]'),
('yuanqu-1861','川拨棹','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)乔人物，那些是人间大丈夫！说得个者也之乎，说得个者也之乎，难道你文章满腹。',49,'元曲/yuanqu.json','["(外)乔人物，那些是人间大丈夫！说得个者也之乎，说得个者也之乎，难道你文章满腹。", "不识羞？酸饿儒！。"]'),
('yuanqu-1862','豆叶黄','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','你缘何无故调拨我恩主，赶兄弟在破窑内落泊，历尽艰苦？搬老婆舌头败风俗，你两个甚豪富？真乃天教一世苦！。',51,'元曲/yuanqu.json','["你缘何无故调拨我恩主，赶兄弟在破窑内落泊，历尽艰苦？搬老婆舌头败风俗，你两个甚豪富？真乃天教一世苦！。"]'),
('yuanqu-1863','窜地锦裆','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)员外祖上置田屋，攒下家私传父母，你得来全不费工夫，不想窑中人受苦？。',37,'元曲/yuanqu.json','["(外)员外祖上置田屋，攒下家私传父母，你得来全不费工夫，不想窑中人受苦？。"]'),
('yuanqu-1864','双劝酒','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)你抛弃手足，疏远骨肉，非亲是亲，全不省悟。',38,'元曲/yuanqu.json','["(外)你抛弃手足，疏远骨肉，非亲是亲，全不省悟。", "一朝马转刀横，只恐悔不当初。"]'),
('yuanqu-1865','红绣鞋','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)愿学田真泣树，泣树，取回兄弟同居，同居。',45,'元曲/yuanqu.json','["(外)愿学田真泣树，泣树，取回兄弟同居，同居。", "美风俗，辨亲疏，兄与弟两和睦，欢喜煞老农夫。"]'),
('yuanqu-1866','似娘儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生上)今日上坟时，一口气嘿嘿嗟吁，思之堪恨奴欺主。',43,'元曲/yuanqu.json','["(生上)今日上坟时，一口气嘿嘿嗟吁，思之堪恨奴欺主。", "多应我弟，想必孙荣教唆那王老如是。"]'),
('yuanqu-1867','玉交枝','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','奴婢欺主，料孙荣令他恁地。',65,'元曲/yuanqu.json','["奴婢欺主，料孙荣令他恁地。", "我说与两个亲兄弟，教谋计害了孙二，无人处打死，撇在水里，不然暗把刀杀取。", "免得我吃人笑耻，免得我吃人笑耻。"]'),
('yuanqu-1868','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)听君言语，果然是当局者迷。',108,'元曲/yuanqu.json','["(旦)听君言语，果然是当局者迷。", "无故杀子孙亦有罪。", "(生)便是官府知道了，无过只要使钱。", "(旦)直恁下得谋杀同气。", "(生)不怕，只要我钱，不要我命。", "(旦)阳世有钱来买罪，阴司怎生饶得你？劝我夫把家私做主，劝我夫把家私做主。"]'),
('yuanqu-1869','好姐姐','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)我妻，听说就里，不杀他怎消恶气！恶缘聚会，拚个直恁的，不足虑。',50,'元曲/yuanqu.json','["(生)我妻，听说就里，不杀他怎消恶气！恶缘聚会，拚个直恁的，不足虑。", "两个兄弟曾说誓，纵有官司他替取。"]'),
('yuanqu-1870','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)小事，他便替你，杀人事不肯当抵。',50,'元曲/yuanqu.json','["(旦)小事，他便替你，杀人事不肯当抵。", "君还犯罪，有钱谁救你？听奴语，船到岸边先修理，莫等江心补漏迟。"]'),
('yuanqu-1871','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)妇女，不识就里，结义的强如骨肉，吉凶祸福，好歹必替吾。',51,'元曲/yuanqu.json','["(生)妇女，不识就里，结义的强如骨肉，吉凶祸福，好歹必替吾。", "越添怒，常言道恨小非君子，果是无毒不丈夫。"]'),
('yuanqu-1872','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)信他，脱空弄虚，空教你通今博古。',51,'元曲/yuanqu.json','["(旦)信他，脱空弄虚，空教你通今博古。", "你杀人坐狱，那时不管顾。", "听嘱付，吃酒弟兄千个有，临难之时一个无。"]'),
('yuanqu-1873','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(夫)领指挥，领指挥。',58,'元曲/yuanqu.json','["(夫)领指挥，领指挥。", "待等一更至，换衣装改庞儿前去。", "到得破窑中，他有翼如何逃避。", "魄散魂飞，把尸骸撇在水里。", "(合前)。"]'),
('yuanqu-1874','上林春','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦上)手足之亲，无故赶出，今日里又生恶意。',40,'元曲/yuanqu.json','["(旦上)手足之亲，无故赶出，今日里又生恶意。", "(贴上)娘行力谏不从，遣人无语嗟吁。"]'),
('yuanqu-1875','宜春令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)心间事难推索，我官人作事全不知错。',68,'元曲/yuanqu.json','["(旦)心间事难推索，我官人作事全不知错。", "存心不善，结交非义谋凶恶，更不思手足之亲，把骨肉埋在沟壑。", "(合)唬得人战战兢兢，扑簌簌泪珠偷落。"]'),
('yuanqu-1876','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)官人煞不量度，把小官人无罪赶出漂泊。',55,'元曲/yuanqu.json','["(贴)官人煞不量度，把小官人无罪赶出漂泊。", "分文不与，又无亲识相依托，破窑中受尽凄凉，那曾知哥哥行恶？(合前)。"]'),
('yuanqu-1877','光光乍','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','谁人叫王婆！叫得我声恁速。',34,'元曲/yuanqu.json','["谁人叫王婆！叫得我声恁速。", "待我开门看则个，呀！元来是迎春姐姐忙万福。"]'),
('yuanqu-1878','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','因感病不痊，合药用多般。',28,'元曲/yuanqu.json','["因感病不痊，合药用多般。", "要买婆婆一黄犬，特与婆婆饯一贯。"]'),
('yuanqu-1879','系人心','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)要一狗合药甚紧？告婆婆且休忧闷。',48,'元曲/yuanqu.json','["(旦)要一狗合药甚紧？告婆婆且休忧闷。", "与婆婆隔壁住年深，一半邻，一半亲。", "且宜思忖，休教失了人情。"]'),
('yuanqu-1880','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)算远亲不如近邻，你何须苦苦执性？要狗合药救人命。',47,'元曲/yuanqu.json','["(贴)算远亲不如近邻，你何须苦苦执性？要狗合药救人命。", "休怒嗔，休怒嗔，出语伤人，算一狗直甚？。"]'),
('yuanqu-1881','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净)这狗子从小养成，割舍得害他一命？院君休得把人轻。',47,'元曲/yuanqu.json','["(净)这狗子从小养成，割舍得害他一命？院君休得把人轻。", "空有金，空有银，纵有珍珠，休得倚富吞贫。"]'),
('yuanqu-1882','皂罗袍','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)狗子坚执不卖，便出言道语，恼人心怀，仔细思量为何来？王婆你好不相待！多年邻舍，茶酒往来，些须小事，不遂我怀，从今休把我门儿踹。',66,'元曲/yuanqu.json','["(旦)狗子坚执不卖，便出言道语，恼人心怀，仔细思量为何来？王婆你好不相待！多年邻舍，茶酒往来，些须小事，不遂我怀，从今休把我门儿踹。"]'),
('yuanqu-1883','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净)是我不合口，如今改过，已往修来。',63,'元曲/yuanqu.json','["(净)是我不合口，如今改过，已往修来。", "院君容恕望怜哀，一床锦被都遮盖。", "多年邻舍，非关吝财，其间就里，好难布摆，踌蹰再四难轻卖。"]'),
('yuanqu-1884','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)软弱立身之本，论刚强惹祸之胎。',62,'元曲/yuanqu.json','["(贴)软弱立身之本，论刚强惹祸之胎。", "利刀割水两难开，好语解人金腰带。", "多年邻舍，且宜忍耐，休发言语，冤只可解，依然两下人情在。"]'),
('yuanqu-1885','江头送别','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','杀一狗，杀一狗，生魂那里？思量起，思量起，泪珠暗垂。',53,'元曲/yuanqu.json','["杀一狗，杀一狗，生魂那里？思量起，思量起，泪珠暗垂。", "当初养你防家计，谁知道今日有灾危！(杀介。", "旦、贴上)。"]'),
('yuanqu-1886','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','忽听得，忽听得，叫声惨凄。',41,'元曲/yuanqu.json','["忽听得，忽听得，叫声惨凄。", "忙来看，忙来看，顿觉心碎。", "愿他早早脱生去，休得要堕轮回。"]'),
('yuanqu-1887','北清江引','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净)将狗儿扯将来忙杀取，看起垂珠泪，怎的割舍得？愿你超生去，院君你自作区处。',39,'元曲/yuanqu.json','["(净)将狗儿扯将来忙杀取，看起垂珠泪，怎的割舍得？愿你超生去，院君你自作区处。"]'),
('yuanqu-1888','锦缠道','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)计谋成，杀一狗撇在后门，扮妆似人形。',82,'元曲/yuanqu.json','["(旦)计谋成，杀一狗撇在后门，扮妆似人形。", "试看来鲜血遍污衣巾，我儿夫必道是人，猛然间魄散魂惊。", "若问我原因，说着几句，教他自猛心省。", "(合)愿得回心后，爱兄弟远别他人。"]'),
('yuanqu-1889','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴)我官人，近日来不知怎生，偏向外人亲。',64,'元曲/yuanqu.json','["(贴)我官人，近日来不知怎生，偏向外人亲。", "每日里同饮同坐同行，把兄弟逐出受贫。", "娘行劝抵死不听。", "杀狗扮人形，设着此计，必须改过心。"]'),
('yuanqu-1890','粉蝶儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外扮土地上)略驾祥云，霎时便临凡世。',19,'元曲/yuanqu.json','["(外扮土地上)略驾祥云，霎时便临凡世。"]'),
('yuanqu-1891','北得胜令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','化一狗，假如人，撇他在后园门。',53,'元曲/yuanqu.json','["化一狗，假如人，撇他在后园门。", "孙员外匆忙见，料无能辨假真！杀人，教他结义的难承认，销魂，须知是亲人到底亲。"]'),
('yuanqu-1892','玩仙灯','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生作醉，净、丑扶上)欢宴醉，归来早，不觉黄昏至也。',26,'元曲/yuanqu.json','["(生作醉，净、丑扶上)欢宴醉，归来早，不觉黄昏至也。"]'),
('yuanqu-1893','薄媚衮','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)因带酒回到后门，一跌疼难忍。',61,'元曲/yuanqu.json','["(生)因带酒回到后门，一跌疼难忍。", "回首看时，瞥见一人，跌倒在草径，呼唤不醒。", "忙扶起，血沾手，污我身。", "不知何人，杀死他身？。"]'),
('yuanqu-1894','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)奴试听君说元因，心下添忧闷。',60,'元曲/yuanqu.json','["(旦)奴试听君说元因，心下添忧闷。", "回言三省，若到官时，先且捉亲邻，唤问凶身。", "君不认，遭打讯，你怎禁？急早商量，莫待祸生。"]'),
('yuanqu-1895','双声子','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)结交的，结交的，待他恩深厚。',61,'元曲/yuanqu.json','["(旦)结交的，结交的，待他恩深厚。", "急请来，急请来，到此移尸首。", "(合)莫停留，莫停留，便去休，便去休，拖尸首葬了，免惹忧愁。"]'),
('yuanqu-1896','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)非说口，非说口，两个知心友。',64,'元曲/yuanqu.json','["(生)非说口，非说口，两个知心友。", "若请他，若请他，断然不落后。", "(合前)(生)院君，如今我便占。", "(旦)你快去，我只在此处等候你来。"]'),
('yuanqu-1897','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','赛关张结义做知交，事急心忙遗忘了。',84,'元曲/yuanqu.json','["赛关张结义做知交，事急心忙遗忘了。", "浑家见识高，混起这根苗，真乃要贤夫祸少。", "这里已是柳龙卿门首了，不免叫一声。", "兄弟开门！(净内应介)是谁？(生)是我，兄弟。", "(净上)来了。"]'),
('yuanqu-1898','玉抱肚','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','忽然心痛。',40,'元曲/yuanqu.json','["忽然心痛。", "(生)兄弟赛关张！(净)赛不过关张弟兄。", "哥哥杀了几个？(生)只是一个。"]'),
('yuanqu-1899','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','当初言定，赛关张结交义深。',48,'元曲/yuanqu.json','["当初言定，赛关张结交义深。", "他前日说道杀人替我偿命，今日反面忘恩。", "心非口是这般人，行短天教一世贫。"]'),
('yuanqu-1900','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','我忽然闪气，赛不过关张结义。',65,'元曲/yuanqu.json','["我忽然闪气，赛不过关张结义。", "(生)兄弟，你曾说有事替我。", "(丑)你杀人命合当偿，怎教我替你埋尸？(生)我与你是好兄弟，怎么说这话？。"]'),
('yuanqu-1901','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','结交义好，我与伊钱供养老小。',47,'元曲/yuanqu.json','["结交义好，我与伊钱供养老小。", "你当初对我曾道，当自效犬马之报。", "养军千日用在一朝，到此方知没下梢。"]'),
('yuanqu-1902','青玉案','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦上)停针闷坐心疑虑，盼望儿夫未见归，镇夜倚门无情绪。',44,'元曲/yuanqu.json','["(旦上)停针闷坐心疑虑，盼望儿夫未见归，镇夜倚门无情绪。", "多应说与，两个推托，不肯替移尸。"]'),
('yuanqu-1903','呼唤子','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','从来不自量，信那人常说，赛过关张。',38,'元曲/yuanqu.json','["从来不自量，信那人常说，赛过关张。", "却不道死事替你承当？思量，口是心非都调谎。"]'),
('yuanqu-1904','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)吾家本善良，赖祖宗积趱，富贵非常。',60,'元曲/yuanqu.json','["(生)吾家本善良，赖祖宗积趱，富贵非常。", "谁知今日祸起萧墙！斟量，自不合酒性刚。", "道出言语触伊行，都撇漾，夫妻义重休挂心肠。"]'),
('yuanqu-1905','大迓鼓','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(且)你结交恩义深，不知因甚反面忘恩？我劝你不从听，霸王空有重瞳目，官人，有眼何曾识好人！。',46,'元曲/yuanqu.json','["(且)你结交恩义深，不知因甚反面忘恩？我劝你不从听，霸王空有重瞳目，官人，有眼何曾识好人！。"]'),
('yuanqu-1906','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)听咱说事因，一人心痛，一个腰疼，假意佯推病。',41,'元曲/yuanqu.json','["(生)听咱说事因，一人心痛，一个腰疼，假意佯推病。", "果然日久见人心，到此方知没义人。"]'),
('yuanqu-1907','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)官人听拜禀，窑中兄弟是你的亲，唤他必然肯。',40,'元曲/yuanqu.json','["(旦)官人听拜禀，窑中兄弟是你的亲，唤他必然肯。", "教君识破假和真，自古的亲无怨心。"]'),
('yuanqu-1908','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)从来结义深，他还沦旨我怎生禁？休误人言难信。',41,'元曲/yuanqu.json','["(生)从来结义深，他还沦旨我怎生禁？休误人言难信。", "夫妻有话且三分，未可全抛一片心。"]'),
('yuanqu-1909','大河蟹','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)却遣吴忠杀他人，吉凶事无凭。',17,'元曲/yuanqu.json','["(生)却遣吴忠杀他人，吉凶事无凭。"]'),
('yuanqu-1910','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)你往窑中探信音，必竟见假真。',17,'元曲/yuanqu.json','["(生)你往窑中探信音，必竟见假真。"]'),
('yuanqu-1911','铁骑儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末上)离门儿，离门儿心惊胆碎，步疾去如飞。',34,'元曲/yuanqu.json','["(末上)离门儿，离门儿心惊胆碎，步疾去如飞。", "到城南破窑，了事便回归。"]'),
('yuanqu-1912','菊花新','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)自恨生米时不利，遭此孤穷，十分惭愧。',43,'元曲/yuanqu.json','["(小生上)自恨生米时不利，遭此孤穷，十分惭愧。", "未知何日上云梯？那时节才显得英雄豪气！。"]'),
('yuanqu-1913','粉蝶儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','只见玉兔尔升，寂寂夜深人静，冷清清掩上窑门。',47,'元曲/yuanqu.json','["只见玉兔尔升，寂寂夜深人静，冷清清掩上窑门。", "纸衾单，芦席冷。", "孤眠独醒对寒灯，知他是甚般情兴！。"]'),
('yuanqu-1914','红芍药','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)蓦听得甚人敲门，莫不是巡捕军兵？(旦)开门！(小生)仔细听来却是妇人声。',118,'元曲/yuanqu.json','["(小生)蓦听得甚人敲门，莫不是巡捕军兵？(旦)开门！(小生)仔细听来却是妇人声。", "且住，记得金精曾戏窦仪，你是何方兴妖鬼精？(巳)我是良人。", "(小生)既是良人。", "因何夜扣门？莫非是见情思景？待我把这门再紧拴上。", "劝伊家及早回心，莫教恼乱春心！。"]'),
('yuanqu-1915','大影戏','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)嫂嫂行不由径，(旦)开门！。',18,'元曲/yuanqu.json','["(小生)嫂嫂行不由径，(旦)开门！。"]'),
('yuanqu-1916','念佛子','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)往日哥打骂人生怒嗔，今日缘何战兢跪咱每？请兄起来休还礼，男儿膝下有黄金。',40,'元曲/yuanqu.json','["(小生)往日哥打骂人生怒嗔，今日缘何战兢跪咱每？请兄起来休还礼，男儿膝下有黄金。"]'),
('yuanqu-1917','缕缕金','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','你平白地将咱赶出门，杀人来唤我去埋形。',60,'元曲/yuanqu.json','["你平白地将咱赶出门，杀人来唤我去埋形。", "你今打些不干净，须要对证。", "(生、旦作慌介。", "小生)唬得他夫妇战兢兢，一个个胆丧心惊。"]'),
('yuanqu-1918','越恁好','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)与君同气，与君同气。',64,'元曲/yuanqu.json','["(小生)与君同气，与君同气。", "一个父娘生，难忘了这些恩和义，手足亲。", "从今休得再讲论。", "倘或事生发，哥哥，你莫胡招认，兄弟替着哥哥认。"]'),
('yuanqu-1919','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','打虎须还亲兄弟，上阵无过父子兵，自今莫把亲为陌路人！。',27,'元曲/yuanqu.json','["打虎须还亲兄弟，上阵无过父子兵，自今莫把亲为陌路人！。"]'),
('yuanqu-1920','四边静','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)思之两个忘恩的，教人恨切齿。',55,'元曲/yuanqu.json','["(生)思之两个忘恩的，教人恨切齿。", "错认定盘星，教缘我不是。", "(合)把从前是非，再休提起。", "从此水团圆，骨肉再和美。"]'),
('yuanqu-1921','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)当初你共他结义，效关张胜刘备。',35,'元曲/yuanqu.json','["(旦)当初你共他结义，效关张胜刘备。", "死事替承当，抬尸怎不去？(合前)。"]'),
('yuanqu-1922','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)不拣甚事都休理，交付与小兄弟。',36,'元曲/yuanqu.json','["(小生)不拣甚事都休理，交付与小兄弟。", "都莫管尸骸，孙荣背将去。", "(合前)。"]'),
('yuanqu-1923','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(末)思亲念旧回心意，吴忠甚欢喜。',34,'元曲/yuanqu.json','["(末)思亲念旧回心意，吴忠甚欢喜。", "人道院君贤，今日果如是。", "(合前)。"]'),
('yuanqu-1924','天下乐','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴上)独守房儿，懒拈针指，潜移步，探因依。',97,'元曲/yuanqu.json','["(贴上)独守房儿，懒拈针指，潜移步，探因依。", "官人与院君说详细，我一言都尽知。", "昨日院君设计，果然叫两个结义的不来。", "如今已去叫小官人移尸，他决然肯来，真个是亲无怨也，今番必定弟兄相和，皆是院君如此。"]'),
('yuanqu-1925','孝顺歌','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','取结义的背死骸，多应两人不肯来。',56,'元曲/yuanqu.json','["取结义的背死骸，多应两人不肯来。", "今取小官人，他却肯前来。", "冤只可解，兄弟和睦，亲亲相爱。", "分与家财，小官人苦尽甘来。"]'),
('yuanqu-1926','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','论杀狗劝夫，古今罕见来。',55,'元曲/yuanqu.json','["论杀狗劝夫，古今罕见来。", "兄弟又成乖，今番有恩爱。", "傍人道来，我院君贤达，人间没赛。", "正是家有贤妻，夫不遭横祸飞灾。"]'),
('yuanqu-1927','步步娇','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)哥哥嫂嫂回家去，心下休疑虑，多应中计矣！喜得门头，巡军皆睡，将尸埋在土沙中，回去说详细。',49,'元曲/yuanqu.json','["(小生上)哥哥嫂嫂回家去，心下休疑虑，多应中计矣！喜得门头，巡军皆睡，将尸埋在土沙中，回去说详细。"]'),
('yuanqu-1928','梅子黄时雨','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','追想当时，三人共结义，今日里显出乔的。',43,'元曲/yuanqu.json','["追想当时，三人共结义，今日里显出乔的。", "(旦上)论的亲凶吉事相济，自古及今，已改非从是。"]'),
('yuanqu-1929','忒忒令','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生、旦)许多时缘何未归？眼巴。',16,'元曲/yuanqu.json','["(生、旦)许多时缘何未归？眼巴。"]'),
('yuanqu-1930','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生上)背尸骸出城去离，幸喜得巡军皆睡，且喜街上，没个人迹。',49,'元曲/yuanqu.json','["(小生上)背尸骸出城去离，幸喜得巡军皆睡，且喜街上，没个人迹。", "埋他在土沙中深草径，荒郊外回来贺喜。"]'),
('yuanqu-1931','红绣鞋','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','明日办个筵席，筵席，把家私付与兄弟，兄弟。',39,'元曲/yuanqu.json','["明日办个筵席，筵席，把家私付与兄弟，兄弟。", "(小生)谢哥哥转心意，结义的再休题。"]'),
('yuanqu-1932','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)须则三人结义，结义，今日显出乔的。',39,'元曲/yuanqu.json','["(旦)须则三人结义，结义，今日显出乔的。", "信谗言使虚脾，宜自省改前非。", "(合前)。"]'),
('yuanqu-1933','水底鱼儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑上。',67,'元曲/yuanqu.json','["(净、丑上。", "净)昨晚孙兄，到家中来扣门，(丑)有尸教咱埋殡，我每不行从。", "(净)今日去叫他，须留我每吃几钟。", "(丑)若还不肯，教他立见凶。"]'),
('yuanqu-1934','啄木儿','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑)孙员外听拜启，我当初共伊结义。',84,'元曲/yuanqu.json','["(净、丑)孙员外听拜启，我当初共伊结义。", "(生)亏你还说结义，惶恐惶恐!(净)夜来非诈心疼，兄弟应知得罪，是真难灭假除易。", "(小生)休多说，假饶染就干红色，也被傍人道是非。"]'),
('yuanqu-1935','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)雪儿下共醉迷，拐玉环先自归。',17,'元曲/yuanqu.json','["(生)雪儿下共醉迷，拐玉环先自归。"]'),
('yuanqu-1936','三段子','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生、小生)请出去离，这狂言实难信伊！(净、丑)你休强嘴，便教你灾祸忽起。',68,'元曲/yuanqu.json','["(生、小生)请出去离，这狂言实难信伊！(净、丑)你休强嘴，便教你灾祸忽起。", "(生、小生)忘恩负义无知贼！当初效学关张的，倒做了孙庞斗使计。"]'),
('yuanqu-1937','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑)你杀了人，使孙荣埋尸葬躯。',18,'元曲/yuanqu.json','["(净、丑)你杀了人，使孙荣埋尸葬躯。"]'),
('yuanqu-1938','缠枝花','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)笑你两个忘恩义，为甚把咀擒住？(小生)常言狗有湿草义，马有摹缰志。',70,'元曲/yuanqu.json','["(生)笑你两个忘恩义，为甚把咀擒住？(小生)常言狗有湿草义，马有摹缰志。", "(净)恼得人恶怒起，趱步即拖去。", "(合)算来谁是谁不是，到官司明白处。"]'),
('yuanqu-1939','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(丑)杀人罪犯难轻恕，实事难抵对。',61,'元曲/yuanqu.json','["(丑)杀人罪犯难轻恕，实事难抵对。", "害人一命，还人一命，有钱难买罪。", "(小生)逞胡言，生奸计，天理不容你！(净，丑)(合前)。"]'),
('yuanqu-1940','贺新郎','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)怎赛得关张义气？眼睁睁割袍断义。',56,'元曲/yuanqu.json','["(生)怎赛得关张义气？眼睁睁割袍断义。", "(净、丑)犯官司难觑面皮，又何必说是讲非？擒住伊，扯住伊，到官司吉凶便知。"]'),
('yuanqu-1941','生姜芽','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦上)闻知我小叔与儿夫，被龙卿、子传拖拽去公堂里，妄告他杀人罪。',70,'元曲/yuanqu.json','["(旦上)闻知我小叔与儿夫，被龙卿、子传拖拽去公堂里，妄告他杀人罪。", "奴家夜来不曾况详细，不知是狗穿人衣袂。", "弄巧成拙是愚痴，怎知好意番成恶意！。"]'),
('yuanqu-1942','西地锦','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','幸得一人有庆，万民咸赖康宁。',28,'元曲/yuanqu.json','["幸得一人有庆，万民咸赖康宁。", "蛮夷拱手米皈顺，奉国泰民清。"]'),
('yuanqu-1943','绛都春','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生、小生)闻知府尹清廉，望高抬明镜。',19,'元曲/yuanqu.json','["(生、小生)闻知府尹清廉，望高抬明镜。"]'),
('yuanqu-1944','好姐姐','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','告禀龙图大尹，状告那孙华孙荣。',48,'元曲/yuanqu.json','["告禀龙图大尹，状告那孙华孙荣。", "昨夜三更，悄然来叩门，道杀人命，要教我两人偷埋殡。", "望乞恩官详事因。"]'),
('yuanqu-1945','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','念孙华是京都小民，那柳龙卿、胡子传呵，他两个全无忠信。',59,'元曲/yuanqu.json','["念孙华是京都小民，那柳龙卿、胡子传呵，他两个全无忠信。", "昔日共他，结义作弟兄，相勾引。", "近日他窘迫不随顺，妄捏虚词恼大尹。"]'),
('yuanqu-1946','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)你每休得避隐，虚事从不入公门，实事怎生，到此不尽情？还不认，硬棒软索披头棍，拷打扌朋扒怎地禁！。',51,'元曲/yuanqu.json','["(外)你每休得避隐，虚事从不入公门，实事怎生，到此不尽情？还不认，硬棒软索披头棍，拷打扌朋扒怎地禁！。"]'),
('yuanqu-1947','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)告得恩官试听，孙荣是杀人凶身。',91,'元曲/yuanqu.json','["(小生)告得恩官试听，孙荣是杀人凶身。", "(净、丑介)爷爷，小的两个不是诬告的！(外)你因何杀人？(小生)爷爷，小人呵！被哥哥赶出，破窑中吃苦辛，因怀恨，临门故杀平人命，陷害哥哥怨恨心。"]'),
('yuanqu-1948','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)相公清廉平正，果然是怀揣明镜。',49,'元曲/yuanqu.json','["(旦)相公清廉平正，果然是怀揣明镜。", "结义兄弟，我夫不三省，亲昆仲，赶出受苦说不尽，故此奴家巧计生。"]'),
('yuanqu-1949','普天乐','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)告恩官抬明镜，杀的是戌生命。',17,'元曲/yuanqu.json','["(旦)告恩官抬明镜，杀的是戌生命。"]'),
('yuanqu-1950','秋夜月','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)吾表文，奏上朝廷去，我王必降天恩露，加官进禄封贤妇。',39,'元曲/yuanqu.json','["(外)吾表文，奏上朝廷去，我王必降天恩露，加官进禄封贤妇。", "因祸致福，因祸致福。"]'),
('yuanqu-1951','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(旦)听拜禀，杀狗非心欲，劝谏儿大相和睦。',39,'元曲/yuanqu.json','["(旦)听拜禀，杀狗非心欲，劝谏儿大相和睦。", "相公若旨垂清目，奴家分福，奴家分福。"]'),
('yuanqu-1952','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生、小生、净、丑、末上)领指挥，同往城南去，掘出尸骸非人类，却是狗子穿衣袂。',52,'元曲/yuanqu.json','["(生、小生、净、丑、末上)领指挥，同往城南去，掘出尸骸非人类，却是狗子穿衣袂。", "果然是杀狗劝夫，杀狗劝夫。"]'),
('yuanqu-1953','北后庭花','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)既没高见识，怎图人小富贵？原旨的福成祸，被告的忧变喜。',133,'元曲/yuanqu.json','["(外)既没高见识，怎图人小富贵？原旨的福成祸，被告的忧变喜。", "你两个昧心贼，忘恩失了义。", "杀狗的没气志，背尸骸有礼义。", "被告的没理会，告状的失了意志。", "男儿，兀的不是赛关张刘备，验得他两个口是心非。", "(旦)妾送得男儿小叔当堂跪，险些个遭刑际，争些个受禁持，兀的不是家有贤妻！。"]'),
('yuanqu-1954','念佛子','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外)孙院君忒贤慧，为丈夫和你结义，信谗言赶逐兄弟狼狈。',58,'元曲/yuanqu.json','["(外)孙院君忒贤慧，为丈夫和你结义，信谗言赶逐兄弟狼狈。", "(旦)奴计杀狗穿衣袂，遣丈夫令你移尸，你忘恩负义，不肯前去。"]'),
('yuanqu-1955','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑)孙华杀人是实，孙荣移尸去，假妆成狗是乔的。',53,'元曲/yuanqu.json','["(净、丑)孙华杀人是实，孙荣移尸去，假妆成狗是乔的。", "(生)你不说赏雪醉迷，跌倒在雪儿取，拐玉环你回家去？。"]'),
('yuanqu-1956','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','你曾知口是心非，忘恩与失义，到如今尚故如此，早招取重情断罪，(外)宛转周全你，更迟疑定不姑恕。',47,'元曲/yuanqu.json','["你曾知口是心非，忘恩与失义，到如今尚故如此，早招取重情断罪，(外)宛转周全你，更迟疑定不姑恕。"]'),
('yuanqu-1957','前腔','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(净、丑)告论你，要你钱财图个富贵，何曾知被枷招罪！(小生)好愚痴，论富贵大眼难容恕。',56,'元曲/yuanqu.json','["(净、丑)告论你，要你钱财图个富贵，何曾知被枷招罪！(小生)好愚痴，论富贵大眼难容恕。", "情节已显然，千虚不抵一实。"]'),
('yuanqu-1958','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(外、生、旦、小生)笑你每怎招取，到这世如何推抵？谩诲人已后毋得忘义！。',36,'元曲/yuanqu.json','["(外、生、旦、小生)笑你每怎招取，到这世如何推抵？谩诲人已后毋得忘义！。"]'),
('yuanqu-1959','金鸡叫','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(贴上)不听好言语，镇日间无情无绪。',135,'元曲/yuanqu.json','["(贴上)不听好言语，镇日间无情无绪。", "羡我院君多伶俐，设下机谋，手足又和美。", "我员外当初听信乔人，赶出兄弟。", "我院君杀狗劝夫，回心转意，弟兄和睦。", "不想柳龙卿、胡子传今早又到我家，道员外不睬，又到官府出首员外杀人，小官人埋尸。", "为此院君亲往府尹处诉明，尚未回来，不知怎生决断了？。"]'),
('yuanqu-1960','驻马听','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生、旦、小生、净、丑上。',77,'元曲/yuanqu.json','["(生、旦、小生、净、丑上。", "生)当日大雪纷纷，故意将人撇在窘。", "盗去玉环宝钞，潜地归家，两下平分。", "感吾兄弟背回门，反生恶意将他恨。", "兄弟是嫡亲，从今莫把闲言论。"]'),
('yuanqu-1961','羽调排歌','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(生)愚蠢孙华，情偏意迷，全亏家有贤妻。',39,'元曲/yuanqu.json','["(生)愚蠢孙华，情偏意迷，全亏家有贤妻。", "(旦)今朝兄弟共怡怡，堪笑乔人枉用机。"]'),
('yuanqu-1962','道和排歌','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(小生)想他每结义时，要学关张的。',71,'元曲/yuanqu.json','["(小生)想他每结义时，要学关张的。", "言语总成虚，寻思太无知。", "那些恩德！那些仁义！(贴)嫡亲兄弟受凌逼，娘行杀狗劝夫回，骨肉团圆不暂离。", "(合前)。"]'),
('yuanqu-1963','尾声','徐田臣《杀狗记》','元','元曲','yuanqu','','[]','(合)世间难得惟兄弟，贤阃调和更罕稀，旌表门闾教人作话儿。',29,'元曲/yuanqu.json','["(合)世间难得惟兄弟，贤阃调和更罕稀，旌表门闾教人作话儿。"]'),
('yuanqu-1964','仙吕・点绛唇慢马','杨舜臣','元','元曲','yuanqu','','[]','四只粗蹄，一条乌尾，棕垂地。',28,'元曲/yuanqu.json','["四只粗蹄，一条乌尾，棕垂地。", "搭上鞍骑，二三百棍行三四里。"]'),
('yuanqu-1965','后庭花煞・叹梁园芳草萋，怕蓝关瑞雪飞。为爱背山咏，任教杜宇啼。空','杨舜臣','元','元曲','yuanqu','','[]','吃得似水牛肥。',27,'元曲/yuanqu.json','["吃得似水牛肥。", "你可甚日行千里，报主人恩，何日把缰垂？。"]'),
('yuanqu-1966','铁拐李度金童玉女・仙吕/八声甘州','贾仲明','元','元曲','yuanqu','','[]','花遮翠拥，香霭飘霞，烛影摇红。',194,'元曲/yuanqu.json','["花遮翠拥，香霭飘霞，烛影摇红。", "月梁云栋，上金钩十二帘栊。", "金雀屏开玳瑁筵，绿蚁光浮白玉钟。", "爽气透襟怀，满面春风。", "(铁拐上，云)贫道按落云头，来到女直地面。", "这里就是金安寿家。", "我去与他添寿化斋，看他说甚么。", "(见科云)稽首。", "贫道特来化斋添寿。", "(正末云)一个先生来化斋求利市。", "不知先生从那里来？(铁拐云)从三岛来。", "(正末云)往那里去？(铁拐云)特来度你为神仙，往蓬莱去。", "(正末云)休胡说那。", "(唱)。"]'),
('yuanqu-1967','铁拐李度金童玉女・寄生草','贾仲明','元','元曲','yuanqu','','[]','俺围珠翠冰绡内，胜蓬莱阆苑中。',106,'元曲/yuanqu.json','["俺围珠翠冰绡内，胜蓬莱阆苑中。", "他淡昏昏半窗明月梨花梦，我谩匆匆满溪流水天台梦，你叹空空一襟清露游仙梦。", "(铁拐云)贫道昨日蕊珠宫醉倒，今日却在这里。", "(正末笑科)(唱)你昨宵个夜沉沉醉卧蕊珠宫，今日暖融融误入桃源洞。"]'),
('yuanqu-1968','铁拐李度金童玉女・满堂红','贾仲明','元','元曲','yuanqu','','[]','凤凰台下风凰台也波台。',53,'元曲/yuanqu.json','["凤凰台下风凰台也波台。", "凤凰台上凤凰来也波来，天籁地籁闻人籁也波籁。", "八音谐，绿云裁，翠烟开，月明吹彻海山白。"]'),
('yuanqu-1969','铁拐李度金童玉女・大德歌','贾仲明','元','元曲','yuanqu','','[]','碧泠泠，五铿铿，七政匏为定。',40,'元曲/yuanqu.json','["碧泠泠，五铿铿，七政匏为定。", "攒紫霞，嵌晓星，箜簧点点皆相应。", "善吹的是子晋董双成。"]'),
('yuanqu-1970','铁拐李度金童玉女・芭蕉延寿','贾仲明','元','元曲','yuanqu','','[]','韵清微，高山流水野猿嘶，楚雨湘云塞雁飞，清风明月孤鹤唳。',40,'元曲/yuanqu.json','["韵清微，高山流水野猿嘶，楚雨湘云塞雁飞，清风明月孤鹤唳。", "春融和，莺乱啼。", "(下)。"]'),
('yuanqu-1971','铁拐李度金童玉女・上马娇','贾仲明','元','元曲','yuanqu','','[]','日高也花影重，风香也酒力涌。',36,'元曲/yuanqu.json','["日高也花影重，风香也酒力涌。", "宝篆袅博山铜，罗裙轻拂湘纹动，侬半札凤头弓。"]'),
('yuanqu-1972','铁拐李度金童玉女・胜葫芦','贾仲明','元','元曲','yuanqu','','[]','恰便似银汉星回一道通，嫦娥出素华宫。',42,'元曲/yuanqu.json','["恰便似银汉星回一道通，嫦娥出素华宫。", "弦管声中更漏永，千般婉转，万般调弄，不觉夜将终。"]'),
('yuanqu-1973','铁拐李度金童玉女・幺篇','贾仲明','元','元曲','yuanqu','','[]','可正是歌尽桃花扇底风，人面映和花红，两下春心应自懂。',42,'元曲/yuanqu.json','["可正是歌尽桃花扇底风，人面映和花红，两下春心应自懂。", "怜香惜玉，颠鸾倒凤，人在锦胡同。"]'),
('yuanqu-1974','铁拐李度金童玉女・赚煞尾','贾仲明','元','元曲','yuanqu','','[]','枉了你费精神，休则管相拦纵，怎撇的玉天仙风流爱宠？(铁拐云)这尤物要他怎么？(正末唱)端的个鱼水夫妻两意同，少年人兴味偏浓。',113,'元曲/yuanqu.json','["枉了你费精神，休则管相拦纵，怎撇的玉天仙风流爱宠？(铁拐云)这尤物要他怎么？(正末唱)端的个鱼水夫妻两意同，少年人兴味偏浓。", "绣帏中淡荡春风，红浪轻翻翠被重。", "玉绳拽遥天半空，银漏逐梅花三弄，直吃的斗杓回，月影转梧桐。", "(同旦下)。"]'),
('yuanqu-1975','铁拐李度金童玉女・南吕/一枝花','贾仲明','元','元曲','yuanqu','','[]','花溪音乐喧，竹坞人家小。',77,'元曲/yuanqu.json','["花溪音乐喧，竹坞人家小。", "香车游上苑，宝马满东郊。", "杂杂嘈嘈，一程程锦绣似花枝绕，一处处管弦般鸟语调。", "垂杨院卖花人一声声叫过红楼，杏花村题诗客一个个醉眠芳草。"]'),
('yuanqu-1976','铁拐李度金童玉女・梁州第七','贾仲明','元','元曲','yuanqu','','[]','看春江鸭头绿皱，接行云雁翅红娇。',181,'元曲/yuanqu.json','["看春江鸭头绿皱，接行云雁翅红娇。", "酒旗向青杏园林挑。", "佳人斗草，公子妆幺。", "秋千料峭，鼓吹游遨。", "上新黄柳曳金条，绽嫣红花簇冰绡。", "芳丛内采嫩蕊，粉蝶队队身轻，回塘畔点香芹，紫燕翩翩翅袅；碧阴中弄清音，流莺恰恰声交。", "难挑，怎描？便那女娘行心思十分巧，其实的刺不成绣不到。", "丹青手虽然百倍高，也画不出这重叠周遭。", "(带云)我想俺这一对好夫妻，也非今世姻缘，是前生配定也。", "(唱)。"]'),
('yuanqu-1977','铁拐李度金童玉女・四块玉','贾仲明','元','元曲','yuanqu','','[]','他碾香轮将芳径穿，我催骏马宛把丝鞭袅。',67,'元曲/yuanqu.json','["他碾香轮将芳径穿，我催骏马宛把丝鞭袅。", "俺这对美爱夫妻宿缘招，俊宠儿落雁沉鱼貌。", "俺两口儿恰便似地长就并蒂花，水养成交颈鸳，天生下比翼鸟。"]'),
('yuanqu-1978','铁拐李度金童玉女・骂玉郎','贾仲明','元','元曲','yuanqu','','[]','他将我这马头拦住高声叫，辔揪住黄金勒，鞭挽住紫藤梢。',119,'元曲/yuanqu.json','["他将我这马头拦住高声叫，辔揪住黄金勒，鞭挽住紫藤梢。", "(铁拐鼓掌大笑，云)你愚眉肉眼，怎识的贫道那？(正末唱)见他风风魔魔掴着手，佯推笑。", "(铁拐云)弃了家业，快逃性命，着你不生不灭，跟我出家去。", "(正末唱)你着我将家业抛，性命逃，便是朝闻道。"]'),
('yuanqu-1979','铁拐李度金童玉女・感皇恩','贾仲明','元','元曲','yuanqu','','[]','你觑花枝般淹润妖娆，我更笋条般风流年少。',67,'元曲/yuanqu.json','["你觑花枝般淹润妖娆，我更笋条般风流年少。", "你着我跨青鸾，乘彩凤，上丹霄，怎如我那花柔柳嫩，玉软香娇？恨不的心窝里放，手掌中擎，眼皮上阁。"]'),
('yuanqu-1980','铁拐李度金童玉女・采茶歌','贾仲明','元','元曲','yuanqu','','[]','你着我戏仙瓢，过金桥，怎肯生拆散碧桃花下凤鸾交？伴着你个铁拐云游同去也，可不闪的俺玉人何处教吹箫？。',50,'元曲/yuanqu.json','["你着我戏仙瓢，过金桥，怎肯生拆散碧桃花下凤鸾交？伴着你个铁拐云游同去也，可不闪的俺玉人何处教吹箫？。"]'),
('yuanqu-1981','铁拐李度金童玉女・侧砖儿','贾仲明','元','元曲','yuanqu','','[]','我怎旨寻真误入蓬莱岛，向群仙队里会蟠桃。',63,'元曲/yuanqu.json','["我怎旨寻真误入蓬莱岛，向群仙队里会蟠桃。", "早难道好者为之乐，(铁拐云)弃了家缘，跟贫道出家去！(正末唱)怎舍的俺铜斗般锦窠巢？。"]'),
('yuanqu-1982','铁拐李度金童玉女・竹枝歌','贾仲明','元','元曲','yuanqu','','[]','看了俺胸背搀绒宫锦袍，(铁拐云)俺出家的藤冠衲袄，草履麻绦，长生不老，比你还受用哩。',98,'元曲/yuanqu.json','["看了俺胸背搀绒宫锦袍，(铁拐云)俺出家的藤冠衲袄，草履麻绦，长生不老，比你还受用哩。", "(正未唱)怎系这等续断滥麻绦？你则看他江梅风韵海棠标，樱桃樊素口，杨柳小蛮腰。", "你可也徒劳，怎把兰蕙性浪比蓬蒿？。"]'),
('yuanqu-1983','铁拐李度金童玉女・玄鹤鸣','贾仲明','元','元曲','yuanqu','','[]','遵径道，达玄妙，参祖师，习鸿宝。',123,'元曲/yuanqu.json','["遵径道，达玄妙，参祖师，习鸿宝。", "说杀你驾青牛，乘赤鲤，骖白鹿，骑黄鹤，怎如俺这宝马雕鞍最好？(铁拐云)你有甚快乐？快快跟我出家去。", "(正末云)我去不的。", "(唱)俺春风桃李，夏月葵榴，秋天金菊，冬雪江梅，一年中景物饶。", "料你那茅庵草舍，争似俺兰堂画阁？。"]'),
('yuanqu-1984','铁拐李度金童玉女・乌夜啼','贾仲明','元','元曲','yuanqu','','[]','我平生不识邯郸道，料黄粱怎比羊羔？(铁拐云)俺那里香风不动松花老。',140,'元曲/yuanqu.json','["我平生不识邯郸道，料黄粱怎比羊羔？(铁拐云)俺那里香风不动松花老。", "跟我出家，可不快活？(正末唱)休夸你香风不动松花老，争如俺月夜花朝，雨媚云娇？(铁拐云)跟我去赴蟠桃会好的多哩！(正末唱)跟你去九重春色醉仙桃，争如俺一生花柳从吾好？白玉池，琼花岛，将我度为道友，这便是你善与人交。"]'),
('yuanqu-1985','铁拐李度金童玉女・春归怨','贾仲明','元','元曲','yuanqu','','[]','夫贵妻荣，多来大福。',42,'元曲/yuanqu.json','["夫贵妻荣，多来大福。", "画堂罗列锦模糊。", "妻才子禄前生注。", "庆有余，美满欢娱，配凤友对鸾雏。"]'),
('yuanqu-1986','铁拐李度金童玉女・雁儿落','贾仲明','元','元曲','yuanqu','','[]','赋新声咏乐府，歌古调达音律。',38,'元曲/yuanqu.json','["赋新声咏乐府，歌古调达音律。", "是一朵没包弹娇柔解语花，是一块无瑕玷温润生香玉。"]'),
('yuanqu-1987','铁拐李度金童玉女・幺篇','贾仲明','元','元曲','yuanqu','','[]','他笑呵似秋莲恰半吐，他悲呵似梨花春带雨。',122,'元曲/yuanqu.json','["他笑呵似秋莲恰半吐，他悲呵似梨花春带雨。", "行呵似新雁云边落，话呵似雏莺枝上语，醉呵似晚风前垂柳翠扶疏，浴呵似海棠擎露。", "立呵渲丹青仕女图，坐呵观世音自在居，睡呵羊脂般卧着美玉。", "吹呵韵清音射碧虚，弹呵拂冰弦断复续，歌呵白苎宛意有余，舞呵彩云旋掌上珠。"]'),
('yuanqu-1988','铁拐李度金童玉女・望远行','贾仲明','元','元曲','yuanqu','','[]','叵奈这无端的铁拐使机谋，不知怎生用些道术，将俺同坐香车，迷惑来去赴玄都。',104,'元曲/yuanqu.json','["叵奈这无端的铁拐使机谋，不知怎生用些道术，将俺同坐香车，迷惑来去赴玄都。", "扌蚩、扌蚩、扌蚩，扯碎俺姻缘簿，忽剌八掘断俺前程路，空没乱椎胸跌足，揉腮瞪目。", "将一朵并头莲碜可可分两处，生拆散燕莺孤，吉丁当摔碎连环玉。"]'),
('yuanqu-1989','铁拐李度金童玉女・贺圣朝','贾仲明','元','元曲','yuanqu','','[]','陡涧高山，险峻崎岖，教我手脚慌乱无是处。',91,'元曲/yuanqu.json','["陡涧高山，险峻崎岖，教我手脚慌乱无是处。", "流水横桥，眼晕心虚，蟠巨蟒老树枯，渗金睛猛虎伏。", "且躲避在林莽，俺映我身躯。", "(正末做慌科)(铁拐叫云)金安寿！(正末疑科，云)是那个叫？(唱)。"]'),
('yuanqu-1990','铁拐李度金童玉女・凤鸾吟','贾仲明','元','元曲','yuanqu','','[]','听的将金安寿名字呼？我这里低首拜伏。',144,'元曲/yuanqu.json','["听的将金安寿名字呼？我这里低首拜伏。", "(铁拐云)金安寿。", "你怎生得到俺这里？(正末唱)这埚里云水林峦，甚么去处？(铁拐云)这里是洞天福地。", "但能到此，吃仙桃，饮甘露，伴猿鹤，与龟鹿齐寿。", "(正末唱)呀！元来这琳宫绀宇，是仙居洞府，食仙桃饮琼浆甘露。", "朱顶鹤，献果猿，绿毛龟，衔花鹿，寿长生玉篆丹书。"]'),
('yuanqu-1991','铁拐李度金童玉女・牡丹春','贾仲明','元','元曲','yuanqu','','[]','婴儿姹女趣，黄芽白雪枯。',46,'元曲/yuanqu.json','["婴儿姹女趣，黄芽白雪枯。", "被金枷玉锁紧相拘，将心猿意马牢拴住。", "虽然足得省悟，你可也回首认当初。"]'),
('yuanqu-1992','铁拐李度金童玉女・凉亭乐','贾仲明','元','元曲','yuanqu','','[]','迅速光阴过隙驹，一梦华胥。',272,'元曲/yuanqu.json','["迅速光阴过隙驹，一梦华胥。", "走兔飞鸟紧相逐，昼夜催寒暑。", "便道你本来面目，仙风道骨，争如俺鼍鼓笛儿者刺古？歌鹦鹉，舞鹧鸪。", "(铁拐云)他尚俗牵未尽，再有道理。", "金安寿，你看那百花烂熳，春景融和。", "(正末云)是好景也！(铁拐云)可早炎天似火，暑气烦蒸。", "(正末云)好热也！(铁拐云)你觑黄花遍野，红叶纷飞。", "(正末云)好惨也！(铁拐云)又早朔风凛冽，瑞雪飘扬。", "(正末云)好冷也！(铁拐云)金安寿，你省的么？(正末云)兀的不侯幸杀我也！正是春天，又临夏暑，顷刻秋霜，逡巡冬雪。", "天地中造化，难晓难参，(诗云)才见垂杨绿，俄然麦又黄。", "蝉声犹未尽，寒雁已成行。", "(唱)。"]'),
('yuanqu-1993','铁拐李度金童玉女・小梁州','贾仲明','元','元曲','yuanqu','','[]','恰才个东风四友尽喧呼，正青春紫翠模糊。',42,'元曲/yuanqu.json','["恰才个东风四友尽喧呼，正青春紫翠模糊。", "却早碧池绿水映芙蕖，承炎暑，又早是落叶晓霜铺。"]'),
('yuanqu-1994','铁拐李度金童玉女・幺篇','贾仲明','元','元曲','yuanqu','','[]','正蛩吟清露滋黄菊，便怎生水晶寒雪莹冰壶，暗里将流年度。',46,'元曲/yuanqu.json','["正蛩吟清露滋黄菊，便怎生水晶寒雪莹冰壶，暗里将流年度。", "怎不想个归根之处，直待临死也做工夫？。"]'),
('yuanqu-1995','铁拐李度金童玉女・啄木儿尾','贾仲明','元','元曲','yuanqu','','[]','拜辞了翠裙红袖簇，朱唇皓齿扶。',45,'元曲/yuanqu.json','["拜辞了翠裙红袖簇，朱唇皓齿扶。", "梦回明月生南浦，向无何深处，步瑶池，游阆苑，到蓬壶。", "(下)。"]'),
('yuanqu-1996','铁拐李度金童玉女・双调/新水令','贾仲明','元','元曲','yuanqu','','[]','你如今上丹霄赴绛阙步瑶台，比红尘巾别是一重境界。',119,'元曲/yuanqu.json','["你如今上丹霄赴绛阙步瑶台，比红尘巾别是一重境界。", "我灵光回阆苑，他慧性到蓬莱。", "当日个染了凡胎，准承望填还这场债。", "(金母云)金童玉女，为你思凡，致使吾令铁拐，亲往尘世度你等重还仙界。", "你从今后，休动凡心者。", "(正末旦拜，云)再不敢了。", "(正末唱)。"]'),
('yuanqu-1997','铁拐李度金童玉女・庆宣和','贾仲明','元','元曲','yuanqu','','[]','不是俺忒疏狂性格乖，也则是业缘里合该。',93,'元曲/yuanqu.json','["不是俺忒疏狂性格乖，也则是业缘里合该。", "今日个一双双跪在金阶，乞仙真痛责。", "(金母云)您两个思凡尘世，托生女直地面，配为夫妇。", "女直家多会歌舞，您两个带舞带唱，我试看咱。", "(正末同旦舞科，唱)。"]'),
('yuanqu-1998','铁拐李度金童玉女・挂搭沽','贾仲明','元','元曲','yuanqu','','[]','则俺那头巾上珍珠砌成界，画拖四叶飞霞带。',62,'元曲/yuanqu.json','["则俺那头巾上珍珠砌成界，画拖四叶飞霞带。", "绣胸背搀绒可体裁，玉兔鹘堪人爱。", "把翠叶贴，将奇花摘。", "趁着这绿鬓朱颜，不负了杏脸桃腮。"]'),
('yuanqu-1999','铁拐李度金童玉女・石竹子','贾仲明','元','元曲','yuanqu','','[]','鼍鼓咚咚声和凯，缕管轻轻音韵谐。',34,'元曲/yuanqu.json','["鼍鼓咚咚声和凯，缕管轻轻音韵谐。", "女直家筵会实难赛，直吃的梨花月上来。"]'),
('yuanqu-2000','铁拐李度金童玉女・山石榴','贾仲明','元','元曲','yuanqu','','[]','紫云娘，多娇色。',23,'元曲/yuanqu.json','["紫云娘，多娇色。", "腰枝一搦东风摆，谪仙女临凡界。"]'),
('yuanqu-2001','铁拐李度金童玉女・幺篇','贾仲明','元','元曲','yuanqu','','[]','佩云肩，玉项牌，凤头鞋。',27,'元曲/yuanqu.json','["佩云肩，玉项牌，凤头鞋。", "羞花闭月天然态，香串结同心带。"]'),
('yuanqu-2002','铁拐李度金童玉女・醉也摩挲','贾仲明','元','元曲','yuanqu','','[]','咱和你同离瑶台也波台，同离瑶台也波台。',36,'元曲/yuanqu.json','["咱和你同离瑶台也波台，同离瑶台也波台。", "杨柳形骸，海棠颜色，端的是可憎才。"]'),
('yuanqu-2003','铁拐李度金童玉女・相公爱','贾仲明','元','元曲','yuanqu','','[]','恰便似并蒂池莲一处栽，春水游鱼两和谐。',37,'元曲/yuanqu.json','["恰便似并蒂池莲一处栽，春水游鱼两和谐。", "疑猜，恐青春不再来，挨甚么时光待？。"]'),
('yuanqu-2004','铁拐李度金童玉女・胡十八','贾仲明','元','元曲','yuanqu','','[]','花镇荣，月常在，人不老，酒频酾，荣华富贵已定排。',52,'元曲/yuanqu.json','["花镇荣，月常在，人不老，酒频酾，荣华富贵已定排。", "金安寿俊才，娇兰又美爱。", "俺则是天上有也者，料人间决无赛。"]'),
('yuanqu-2005','铁拐李度金童玉女・一锭银','贾仲明','元','元曲','yuanqu','','[]','趁着这千树桃花云锦开，向流水天台。',36,'元曲/yuanqu.json','["趁着这千树桃花云锦开，向流水天台。", "动箫韶仙音一派，可不是前世里得修来！。"]'),
('yuanqu-2006','铁拐李度金童玉女・慢金盏','贾仲明','元','元曲','yuanqu','','[]','猛想起步香阶，露湿弓鞋。',62,'元曲/yuanqu.json','["猛想起步香阶，露湿弓鞋。", "宿世该，前生载。", "淡涂着花额，眉分着翠黛。", "五簪着凤钗，粉衬着莲腮。", "和这画堂金谷豪华客，软款情，温柔态。"]'),
('yuanqu-2007','铁拐李度金童玉女・大拜门','贾仲明','元','元曲','yuanqu','','[]','正是女貌郎才，厮亲厮爱，这一段风流意脉。',42,'元曲/yuanqu.json','["正是女貌郎才，厮亲厮爱，这一段风流意脉。", "题诗在绿苔，吹箫在凤台，似牛女在银汉边双排。"]'),
('yuanqu-2008','铁拐李度金童玉女・喜人心','贾仲明','元','元曲','yuanqu','','[]','看松云掩霭，闻桂风潇洒。',56,'元曲/yuanqu.json','["看松云掩霭，闻桂风潇洒。", "竹影藤花月色，紫府金坛放毫彩。", "醉舞狂歌，长笑高吟，疏散情怀。", "他壶内天无坏，咱静里神氏泰。"]'),
('yuanqu-2009','铁拐李度金童玉女・风流体','贾仲明','元','元曲','yuanqu','','[]','临清流，临一带心快哉。',44,'元曲/yuanqu.json','["临清流，临一带心快哉。", "玩明月，玩一轮情舒解。", "枕黄石，枕一块意豁开，卧白云，卧一片身自在。"]'),
('yuanqu-2010','铁拐李度金童玉女・忽都白','贾仲明','元','元曲','yuanqu','','[]','翠壁丹崖，玉殴金阶，再不必猜也么猜。',53,'元曲/yuanqu.json','["翠壁丹崖，玉殴金阶，再不必猜也么猜。", "我如今丫髻环绦，椰瓢执袋，麻袍宽快，布袜芒鞋。", "饥后餐松柏，渴来清泉解。"]'),
('yuanqu-2011','铁拐李度金童玉女・唐兀歹','贾仲明','元','元曲','yuanqu','','[]','安乐窠修真好避乖，翠林峦金碧楼台。',89,'元曲/yuanqu.json','["安乐窠修真好避乖，翠林峦金碧楼台。", "纳头一觉回光入玄界，畅好是清也波哉！(金母云)金童玉女，您离瑶池多时。", "您则知您女直家会歌舞，可着俺八仙，舞一会你看。", "(八仙上，歌舞科)(共唱)。"]'),
('yuanqu-2012','铁拐李度金童玉女・青天歌','贾仲明','元','元曲','yuanqu','','[]','真仙聚会瑶池上，仙乐和鸣鸾凤降，鸾凤双飞下紫霄，仙鹤共舞仙童唱。',262,'元曲/yuanqu.json','["真仙聚会瑶池上，仙乐和鸣鸾凤降，鸾凤双飞下紫霄，仙鹤共舞仙童唱。", "仙童唱歌歌太平，尝得蟠桃寿万龄。", "瑞霭祥光满天地，群仙会里说长生。", "长生自知微妙诀，番口开门应难说。", "不妨泄漏这玄机，惊得虚空长吐舌。", "舌端放出玉毫光，辉辉朗朗照十方。", "春风只在花梢上，何处园林不艳阳？艳阳时节采灵苗，莫等中秋月色高。", "颠倒离男逢坎女，黄婆拍手喜相招。", "相招相唤配阴阳，密雨浓云入洞房。", "十载灵胎生个子，倒骑白鹿上穹苍。", "穹苍颢气罡风健，吹得璇玑从左转。", "三辰万象总森罗，三界仙官朝玉殿。", "玉殿金阶列众仙，蟠桃高捧献华筵。", "仙洒仙花映仙果，长生不老亿千年。", "(正末唱)。"]'),
('yuanqu-2013','铁拐李度金童玉女・川拨棹','贾仲明','元','元曲','yuanqu','','[]','今日个畅情怀，纵神游遍九垓。',39,'元曲/yuanqu.json','["今日个畅情怀，纵神游遍九垓。", "慧眼睁开，道性明白。", "依旧是风魂月魄。", "悟春从天上来。"]'),
('yuanqu-2014','铁拐李度金童玉女・七弟兄','贾仲明','元','元曲','yuanqu','','[]','银槐翠柏洞天开，击法鼓雷动沧瀛海。',34,'元曲/yuanqu.json','["银槐翠柏洞天开，击法鼓雷动沧瀛海。", "扣金钟霞散阆风台，敲碧磐绕松花盖。"]'),
('yuanqu-2015','铁拐李度金童玉女・收江南','贾仲明','元','元曲','yuanqu','','[]','呀！兀的不是月明千里故人来，抵多少一场春梦唤回来。',52,'元曲/yuanqu.json','["呀！兀的不是月明千里故人来，抵多少一场春梦唤回来。", "今日个满堂和气醉归来，贤贤易色，再休提洛阳花酒一齐来。"]'),
('yuanqu-2016','铁拐李度金童玉女・鸳鸯煞','贾仲明','元','元曲','yuanqu','','[]','从来个天堂本与尘寰隔，谁承型凡人重把神仙拜。',97,'元曲/yuanqu.json','["从来个天堂本与尘寰隔，谁承型凡人重把神仙拜。", "感谢得金母提携，识认了群真风彩。", "唱道汉钟离绿蚁醺酣，唐吕公红颜不改，韩湘子顷刻花开，张果老倒骑的驴儿快，蓝采和达道诙谐，李先生四海云游，全凭着这条拐。"]'),
('yuanqu-2017','严子陵垂钓七里滩・仙吕/点绛唇','宫天挺','元','元曲','yuanqu','','[]','开创高皇，上天责降，萧丞相、韩信、张良。',27,'元曲/yuanqu.json','["开创高皇，上天责降，萧丞相、韩信、张良。", "自平帝生王莽。"]'),
('yuanqu-2018','严子陵垂钓七里滩・混江龙','宫天挺','元','元曲','yuanqu','','[]','自从夏桀将禹丧，独夫殷纣灭成汤。',156,'元曲/yuanqu.json','["自从夏桀将禹丧，独夫殷纣灭成汤。", "丕显立吊民伐罪，丕承立守绪成王。", "刚四十垂拱严郎朝彩风，弟五辈巡狩湘流中淹杀昭王。", "自开基起运，立国安邦，坐筹帏幄，竭力疆场。", "百十万阵，三五千场，满身矢簇，遍体金疮，尸横草野，鸦啄人肠。", "未曾立两行墨迹在史书中，却早卧一丘新土在芒山上。", "咱人这富贵如蜗牛角半痕涎沫，功名似飞萤尾一点光芒。"]'),
('yuanqu-2019','严子陵垂钓七里滩・油葫芦','宫天挺','元','元曲','yuanqu','','[]','刘文叔相期何故爽？一会家白暗想，怎生来今日晚了时光？他则在鱼州揽住收罾网。',81,'元曲/yuanqu.json','["刘文叔相期何故爽？一会家白暗想，怎生来今日晚了时光？他则在鱼州揽住收罾网。", "酒旗摇处沽村酿，畅情时酌一壶，开怀时饮几觞。", "知他是暮年间身死中年间丧，醉不到三万六千场。"]'),
('yuanqu-2020','严子陵垂钓七里滩・天下乐','宫天挺','元','元曲','yuanqu','','[]','则愿的王新室官家寿命长。',61,'元曲/yuanqu.json','["则愿的王新室官家寿命长。", "我这里斟量，有个意况。", "体乾坤姓正的由他姓王。", "他夺厂呵夺汉朝，篡了呵篡了汉邦，到与俺闲人每留下醉乡。"]'),
('yuanqu-2021','严子陵垂钓七里滩・那吒令','宫天挺','元','元曲','yuanqu','','[]','则咱这醉眼觑世界，不悠悠荡荡。',75,'元曲/yuanqu.json','["则咱这醉眼觑世界，不悠悠荡荡。", "则咱这醉眼觑日月，不来来往往。", "则咱这醉眼觑富贵，不劳劳穰穰。", "咱醉眼宽似沧海中，咱醉眼竟高似青霄上，咱醉眼不识个宇宙洪荒。"]'),
('yuanqu-2022','严子陵垂钓七里滩・鹊踏枝','宫天挺','元','元曲','yuanqu','','[]','他笑咱唱的来不依腔，舞的来煞颠狂，俺不比您名皱定眉儿别是天堂。',55,'元曲/yuanqu.json','["他笑咱唱的来不依腔，舞的来煞颠狂，俺不比您名皱定眉儿别是天堂。", "富汉每喝菜汤穿粗衣朴裳，有一日泼家私似狗令羊肠。"]'),
('yuanqu-2023','严子陵垂钓七里滩・寄生草','宫天挺','元','元曲','yuanqu','','[]','我比他吃茶饭知个饥饱，我比他穿衣服知个暖凉。',68,'元曲/yuanqu.json','["我比他吃茶饭知个饥饱，我比他穿衣服知个暖凉。", "酒添的神气能荣旺，饭装的皮袋偏肥胖，衣穿的寒暑难侵傍。", "看谁人省悟是谁痴，怕不凤凰飞在梧桐上。"]'),
('yuanqu-2024','严子陵垂钓七里滩・六幺序','宫天挺','元','元曲','yuanqu','','[]','您将他称赏，把他赞奖。',97,'元曲/yuanqu.json','["您将他称赏，把他赞奖。", "那厮则是火避苛虎，当道豺狼。", "咱人但晓三章，但识斟量，忠孝贤良，但似严光，怎肯受王新室紫绶金章？时史令鬼眼通身眼，有多少马壮人强，改年建号时间旺，夺了刘家朝典，夺了汉世封疆。"]'),
('yuanqu-2025','严子陵垂钓七里滩・幺篇','宫天挺','元','元曲','yuanqu','','[]','遍端详，那厮模佯，休紧休忙。',145,'元曲/yuanqu.json','["遍端详，那厮模佯，休紧休忙。", "等那穹苍，到那时光，汉室忠良，议论商量。", "引领刀枪，撞入门墙，拖下龙床，脱了衣裳，木驴牵将，闹市云阳，手脚舒长，六道长丁钉上。", "咱大家看一场。", "不争你动起刀枪，天下荒荒，正应道龙门鱼伤，尽乾坤一片青罗网。", "咱人逃出大纛高张，您汉家枝叶合兴旺，见放着天天摧地搭，国破家亡。"]'),
('yuanqu-2026','严子陵垂钓七里滩・青哥儿','宫天挺','元','元曲','yuanqu','','[]','那里面暗隐着风波、风波千丈，你说波使磁瓯的有甚灾伤？我醉了呵东倒西歪尽不妨。',133,'元曲/yuanqu.json','["那里面暗隐着风波、风波千丈，你说波使磁瓯的有甚灾伤？我醉了呵东倒西歪尽不妨。", "我若烂醉在村乡，着李二公扶将到茅舍茅堂。", "靠瓮牖蓬窗，新苇席清凉，旧木枕边厢，袒脱下衣裳，放散诞心肠，任百事无妨。", "倒大来免虑忘忧，纳被蒙头，任意番身。", "强如您宰相侯王，遭断没属官象牙床，泥金坑。"]'),
('yuanqu-2027','严子陵垂钓七里滩・紫花儿','宫天挺','元','元曲','yuanqu','','[]','您道我不达时务，我是个避世严陵，钓几尾漏网的游鱼。',82,'元曲/yuanqu.json','["您道我不达时务，我是个避世严陵，钓几尾漏网的游鱼。", "怎禁四蹄玉兔，三足金乌。", "子细踌躇，观了些成败兴亡阅了些今古，浪淘尽千古风流人物。", "昨日个虎踞在咸阳，今日早鹿走姑苏。"]'),
('yuanqu-2028','严子陵垂钓七里滩・金蕉叶','宫天挺','元','元曲','yuanqu','','[]','七里滩从来是祖居，十辈儿不知祸福。',39,'元曲/yuanqu.json','["七里滩从来是祖居，十辈儿不知祸福。", "常绕定滩头景物，我若是不做官一世儿平生愿足。"]'),
('yuanqu-2029','严子陵垂钓七里滩・调笑令','宫天挺','元','元曲','yuanqu','','[]','巴到日暮，看天隅，见隐隐残霞三四缕。',58,'元曲/yuanqu.json','["巴到日暮，看天隅，见隐隐残霞三四缕。", "钓的这锦鳞来满向篮中贮，正是收纶罢钓渔父。", "那的是江上晚来堪画处，抖擞着绿蓑归去。"]'),
('yuanqu-2030','严子陵垂钓七里滩・鬼三台','宫天挺','元','元曲','yuanqu','','[]','休停住，疾回去，不去呵枉惹的我讹言讹语。',76,'元曲/yuanqu.json','["休停住，疾回去，不去呵枉惹的我讹言讹语。", "回奏与您汉銮舆，休着俺闲人受苦。", "皂朝靴紧行拘我二足，纱幞头带着掐我额颅。", "我手执的是斑竹纶竿，谁秉得你花纹象笏？。"]'),
('yuanqu-2031','严子陵垂钓七里滩・圣药王','宫天挺','元','元曲','yuanqu','','[]','我在这水国居，乐有余。',62,'元曲/yuanqu.json','["我在这水国居，乐有余。", "你问我弃高官不做待闲居。", "重呵止不过请些俸禄，轻呵但抹着灭了九族。", "不用一封天子诏贤书，回去也不是护身符。"]'),
('yuanqu-2032','严子陵垂钓七里滩・麻郎儿','宫天挺','元','元曲','yuanqu','','[]','我尽说与你肺腹，我共您銮舆，俺两个常绕着南刚酒卢，醉酩酊不能家去。',33,'元曲/yuanqu.json','["我尽说与你肺腹，我共您銮舆，俺两个常绕着南刚酒卢，醉酩酊不能家去。"]'),
('yuanqu-2033','严子陵垂钓七里滩・幺篇','宫天挺','元','元曲','yuanqu','','[]','俺是酒徒醉余睡处，又无甚花毡绣褥。',35,'元曲/yuanqu.json','["俺是酒徒醉余睡处，又无甚花毡绣褥。", "我布袍袖将他盖覆，常与我席头儿多处。"]'),
('yuanqu-2034','严子陵垂钓七里滩・络丝娘','宫天挺','元','元曲','yuanqu','','[]','倒两个醉廛市同眠抵足，我怎去他手里三叩头扬尘拜舞？我说来的言词你寄将去，休忘了我-句。',43,'元曲/yuanqu.json','["倒两个醉廛市同眠抵足，我怎去他手里三叩头扬尘拜舞？我说来的言词你寄将去，休忘了我-句。"]'),
('yuanqu-2035','严子陵垂钓七里滩・正宫/端正好','宫天挺','元','元曲','yuanqu','','[]','高祖般性宽洪，义帝般心明圣，可知汉业中兴。',37,'元曲/yuanqu.json','["高祖般性宽洪，义帝般心明圣，可知汉业中兴。", "为我不从丹诏修书请，更道违宣命。"]'),
('yuanqu-2036','严子陵垂钓七里滩・滚绣球','宫天挺','元','元曲','yuanqu','','[]','严子陵，莫不忒煞逞？我是个道人家动不如静。',85,'元曲/yuanqu.json','["严子陵，莫不忒煞逞？我是个道人家动不如静。", "休！休！我今番索通个人情，便索登，远路程，怎禁他礼节相敬，岂辞劳鞍马前行。", "不免的手攀明月来天阙，我则索袖挽清风入帝京，怎得消停。"]'),
('yuanqu-2037','严子陵垂钓七里滩・倘秀才','宫天挺','元','元曲','yuanqu','','[]','来了我呵鸥鹭在滩头失惊，不见我呵渔父在矶台漫等。',56,'元曲/yuanqu.json','["来了我呵鸥鹭在滩头失惊，不见我呵渔父在矶台漫等。", "来了我呵钓台上青苔即渐生。", "这其间柴门静悄悄，茅舍冷清清，料应！。"]'),
('yuanqu-2038','严子陵垂钓七里滩・滚绣球','宫天挺','元','元曲','yuanqu','','[]','柴门知他扃也不扃？人笑却足应也那不应？荒疏了俺那柳阴花径，有宾朋来呵淮人出户相迎？到初更酒半醒，猛想起故园景，忽然感怀诗兴，对蓬窗斜月似挑灯。',98,'元曲/yuanqu.json','["柴门知他扃也不扃？人笑却足应也那不应？荒疏了俺那柳阴花径，有宾朋来呵淮人出户相迎？到初更酒半醒，猛想起故园景，忽然感怀诗兴，对蓬窗斜月似挑灯。", "香馥馥暗香浮动梅摇影。", "疏刺剌翠色相交竹弄声，感旧伤情。"]'),
('yuanqu-2039','严子陵垂钓七里滩・倘秀才','宫天挺','元','元曲','yuanqu','','[]','见旗帜上月华日精，唬的些居民从速风迸，呈百般的下路潜藏无掩映。',43,'元曲/yuanqu.json','["见旗帜上月华日精，唬的些居民从速风迸，呈百般的下路潜藏无掩映。", "不知您，帝王情，是怎生。"]'),
('yuanqu-2040','严子陵垂钓七里滩・滚绣球','宫天挺','元','元曲','yuanqu','','[]','折銮驾却是应也不应？布民人却是惊也不惊？更做道一人有庆，汉君王真恁地将銮驾别无处施呈。',110,'元曲/yuanqu.json','["折銮驾却是应也不应？布民人却是惊也不惊？更做道一人有庆，汉君王真恁地将銮驾别无处施呈。", "他出郭迎，俺旧伴等，待刚来我根前显耀他帝王的权柄，和俺钓鱼人莫不两国相争。", "齐臻臻戈殳镫棒当头摆，明晃晃武士金瓜夹路行，我怎敢冲撞朝廷。"]'),
('yuanqu-2041','严子陵垂钓七里滩・倘秀才','宫天挺','元','元曲','yuanqu','','[]','他往常穿一领粗布袍被我常扯的扁襟旦领，他如今穿着领柘黄袍我若是轻抹着该多大来罪名。',70,'元曲/yuanqu.json','["他往常穿一领粗布袍被我常扯的扁襟旦领，他如今穿着领柘黄袍我若是轻抹着该多大来罪名。", "我则似那草店上相逢时那个身命，便和您，叙交情，做听那伴等。"]'),
('yuanqu-2042','严子陵垂钓七里滩・滚绣球','宫天挺','元','元曲','yuanqu','','[]','投至得帝业兴，家业成，四边平静，经了几千场虎斗龙争。',87,'元曲/yuanqu.json','["投至得帝业兴，家业成，四边平静，经了几千场虎斗龙争。", "则为我交契情，我费打听，到处里曾问遍庶民百姓，最显的是暮秋霜气岩凝。", "都说你须知复汉功臣力，不及泥田一片冰，端的是鬼怕神惊。"]'),
('yuanqu-2043','严子陵垂钓七里滩・脱布衫','宫天挺','元','元曲','yuanqu','','[]','则为你般调人两字功名，躯荣人半世浮生。',38,'元曲/yuanqu.json','["则为你般调人两字功名，躯荣人半世浮生。", "-个楚霸王拔山举鼎，乌江岸剑抹了咽颈。"]'),
('yuanqu-2044','严子陵垂钓七里滩・小梁州','宫天挺','元','元曲','yuanqu','','[]','都则为耻向东吴再起兵，那其间也汉高祖功成。',40,'元曲/yuanqu.json','["都则为耻向东吴再起兵，那其间也汉高祖功成。", "道贼王莽篡了龙廷，有真命，文叔再中兴。"]'),
('yuanqu-2045','严子陵垂钓七里滩・幺篇','宫天挺','元','元曲','yuanqu','','[]','贫道暗暗心内自思省，建武十三年八月期程，王新室有百万兵，困你在昆阳阵。',56,'元曲/yuanqu.json','["贫道暗暗心内自思省，建武十三年八月期程，王新室有百万兵，困你在昆阳阵。", "那其间醉魂也半轮明月，觉来时，依旧照茅亭。"]'),
('yuanqu-2046','严子陵垂钓七里滩・耍孩儿','宫天挺','元','元曲','yuanqu','','[]','自古兴亡成败皆前定，若是你不患难如何得太平？自从祖公公昔日陷彭城，真乃是死里逃生。',87,'元曲/yuanqu.json','["自古兴亡成败皆前定，若是你不患难如何得太平？自从祖公公昔日陷彭城，真乃是死里逃生。", "不龙吟怎得真龙显？不发黑如何得晓日明？虽然你心明圣，若不是云台上英雄并力，你独自个孤掌难鸣。"]'),
('yuanqu-2047','严子陵垂钓七里滩・煞','宫天挺','元','元曲','yuanqu','','[]','为民的乐业在家内居，为农的欣然在垄上耕。',73,'元曲/yuanqu.json','["为民的乐业在家内居，为农的欣然在垄上耕。", "从你为君，社稷安，盗贼息，狼烟静。", "九层春露都恩到，两鬓秋霜何星星？百姓每家家庆，庆道是民安国泰，法正官清。"]'),
('yuanqu-2048','严子陵垂钓七里滩・三','宫天挺','元','元曲','yuanqu','','[]','休将闲事争提，莫将席面冷，磁瓯瓦钵似南阳兴。',67,'元曲/yuanqu.json','["休将闲事争提，莫将席面冷，磁瓯瓦钵似南阳兴。", "若相逢个饮空归去，我怕听阳关第四声。", "你把这瓮内酒休教剩，我若不令十分酩酊，怎解咱数载离情。"]'),
('yuanqu-2049','严子陵垂钓七里滩・四','宫天挺','元','元曲','yuanqu','','[]','你也不是我的君，我也不是你的卿，咱两个一樽酒罢先言定。',80,'元曲/yuanqu.json','["你也不是我的君，我也不是你的卿，咱两个一樽酒罢先言定。", "若你万圣主今夜还得去，我便七里滩途程来日登。", "又不曾更了名姓，你则是十年前沾酒刘秀，我则是七卫滩垂钓的严陵。"]'),
('yuanqu-2050','严子陵垂钓七里滩・尾','宫天挺','元','元曲','yuanqu','','[]','您每朝聚九卿，你须当起五更，去得迟呵着那两班文武在丹墀候等。',64,'元曲/yuanqu.json','["您每朝聚九卿，你须当起五更，去得迟呵着那两班文武在丹墀候等。", "俺出家来纳被蒙头，黑甜一枕，直睡到红日三竿犹兀自唤不的我醒。", "(下)。"]'),
('yuanqu-2051','严子陵垂钓七里滩・双调/新水令','宫天挺','元','元曲','yuanqu','','[]','屈恙着野人心直宣的我入宫来，笑刘文叔我似前是何相待。',73,'元曲/yuanqu.json','["屈恙着野人心直宣的我入宫来，笑刘文叔我似前是何相待。", "待刚来则是矜夸些金暇宁，显耀些玉楼台，末过足玉殿金阶。", "我住的草舍茅斋。", "比您不曾差犬役着万民羞。"]'),
('yuanqu-2052','严子陵垂钓七里滩・乔牌儿','宫天挺','元','元曲','yuanqu','','[]','辇路傍啄绿苔，猛然间那惊怪，元来是七里滩朱顶仙鹤在碧云间将雪翅开，他直飞到皇宫探我来。',156,'元曲/yuanqu.json','["辇路傍啄绿苔，猛然间那惊怪，元来是七里滩朱顶仙鹤在碧云间将雪翅开，他直飞到皇宫探我来。", "他为甚还闷在阑干外？是不是我的仙鹤？若是我的呵，则不肯来。", "和他那献果木猿猱也到来。", "我山野的心常布。", "俺那里水似蓝山如黛，不由我见景生情，睹物伤怀。", "俺那七里滩好多好景致：麋鹿衔花，野猿献果。", "天灯自见，乌鹊报晓，禽有禽言，兽有兽语。"]'),
('yuanqu-2053','严子陵垂钓七里滩・折桂令','宫天挺','元','元曲','yuanqu','','[]','疑猜我在钓鱼滩醉倒来回来，俺出家儿散诞心肠，放浪形骸。',114,'元曲/yuanqu.json','["疑猜我在钓鱼滩醉倒来回来，俺出家儿散诞心肠，放浪形骸。", "我把您上下君臣，非是严光，把您花白。", "为君的紧打并吞伏四海，为臣的紧铺劳日转千阶。", "我说与您听，我不人才。", "有那等不染尘埃，不识兴衰，靠岭偎崖，撒网担柴，寻觅将来，则那的便是人才。"]'),
('yuanqu-2054','严子陵垂钓七里滩・乔牌儿','宫天挺','元','元曲','yuanqu','','[]','脚紧抬脚慢抬，一层迈两层迈上金阶。',33,'元曲/yuanqu.json','["脚紧抬脚慢抬，一层迈两层迈上金阶。", "宫女将我忙从策，把严陵来休怪责。"]'),
('yuanqu-2055','严子陵垂钓七里滩・殿前欢','宫天挺','元','元曲','yuanqu','','[]','扶策的我步瑶阶，心怀七里濉钓鱼台。',76,'元曲/yuanqu.json','["扶策的我步瑶阶，心怀七里濉钓鱼台。", "醉醺醺跳出龙门外，似草店上般东倒四歪，把我脑撺的抢将下米。", "这殿阁初兴盖，您君臣斗耍夸胸大，大古里是茅茨不剪，三尺台阶。"]'),
('yuanqu-2056','严子陵垂钓七里滩・水仙子','宫天挺','元','元曲','yuanqu','','[]','我这里轻揎袍袖手舒开，满饮琼浆款落台。',76,'元曲/yuanqu.json','["我这里轻揎袍袖手舒开，满饮琼浆款落台。", "饮罢时放的稳忙加额，比俺那使磁瓯奸好不自在，怎如咱草店上倒开怀。", "不想阗是祸患，不知阗足利害，畅好拘束人也玳则筵歼。"]'),
('yuanqu-2057','严子陵垂钓七里滩・落梅风','宫天挺','元','元曲','yuanqu','','[]','我在江村里住，肚皮里饥上来，俺则有油盐和的半盏野菜。',50,'元曲/yuanqu.json','["我在江村里住，肚皮里饥上来，俺则有油盐和的半盏野菜。", "食鱼羹稻饭几曾卓器摆，几曾这般区区将将大惊小怪。"]'),
('yuanqu-2058','严子陵垂钓七里滩・离亭宴煞','宫天挺','元','元曲','yuanqu','','[]','九经三史文书册，压着一千场国破山河改。',76,'元曲/yuanqu.json','["九经三史文书册，压着一千场国破山河改。", "富贵荣华，草介尘埃。", "唱道禄重官高，阗是祸害，凤阁龙楼，包着成败。", "您那里是舜殿尧阶，严光则是跳出了十万丈风波是非海。"]'),
('yuanqu-2059','陈季卿误上竹叶舟・仙吕/点绛唇','杨梓','元','元曲','yuanqu','','[]','恰离了北海苍梧，可义蚤岁华几度，成今古。',35,'元曲/yuanqu.json','["恰离了北海苍梧，可义蚤岁华几度，成今古。", "叹世事荣枯，准识的这长生路？。"]'),
('yuanqu-2060','陈季卿误上竹叶舟・混江龙','杨梓','元','元曲','yuanqu','','[]','量那些一陀儿寰土，经了些前朝后代战争余。',120,'元曲/yuanqu.json','["量那些一陀儿寰土，经了些前朝后代战争余。", "俺从这劈开混沌，踏破空虚。", "俺不用九转丹成千岁寿，俺不用一斤铅结万年珠。", "也不采甚么奇苗异草，也不佩甚么宝篆灵符，只要养的这精神似水，炼的这骨髓如酥，常日把那心猿意马牢拴拄。", "一任教陵移谷变，石烂的这松枯。"]'),
('yuanqu-2061','陈季卿误上竹叶舟・油葫芦','杨梓','元','元曲','yuanqu','','[]','叹你这千丈风波名利途，端的个枉受苦。',123,'元曲/yuanqu.json','["叹你这千丈风波名利途，端的个枉受苦。", "便做道佩苏秦相印待何如！你则石凌烟阁那个是真英武，你则看金谷乡都是些乔男女。", "(陈季卿云)这也要辨个贤愚，怎么一概都说是假的？(正末唱)你可也辨甚么贤，辨甚么愚，折莫将陶朱公贵像把黄金铸，倒底也载不的西子泛正湖。"]'),
('yuanqu-2062','陈季卿误上竹叶舟・那吒令','杨梓','元','元曲','yuanqu','','[]','岂不闻有一个列御寇，驾泠风遍八区。',102,'元曲/yuanqu.json','["岂不闻有一个列御寇，驾泠风遍八区。", "(陈季卿云)是一个了，再有谁呢？(正末唱)有一个张子房，迫赤忪别帝都。", "(陈季卿云)再呢？(正末唱)行一个葛仙翁，采丹砂入洞府。", "他虽则土木骸，这都足神仙骨。", "不似你肉眼凡夫。"]'),
('yuanqu-2063','陈季卿误上竹叶舟・寄生草','杨梓','元','元曲','yuanqu','','[]','枉踏破你那游仙履，怎寻的着我这炼药炉。',68,'元曲/yuanqu.json','["枉踏破你那游仙履，怎寻的着我这炼药炉。", "我则是任来任去随缘住，无风无雨难倾覆，不修不垒常坚固，那里有洞门深锁远山中，端的个白云满地无寻处。"]'),
('yuanqu-2064','陈季卿误上竹叶舟・醉中天','杨梓','元','元曲','yuanqu','','[]','这词呵胜王粲《登楼赋》，似宗炳《卧游图》。',186,'元曲/yuanqu.json','["这词呵胜王粲《登楼赋》，似宗炳《卧游图》。", "(做取竹叶粘壁上科)(唱)你觑这渺渺沧波一叶芦。", "(云)疾！秀才，兀的不是一只船了也？(陈季卿云)恰才是一片竹叶儿，粘在壁上，怎么就变成了一只船？可也奇怪。", "(惠安云)道兄，这船也小，只怕借不得我故人回去。", "(正末云)呆汉，正好借去。", "(唱)休猜做野水无人渡，你本待挟三策做公孙应举，眼见的不及第学渊明归去，怎知道这两桩儿都则是一梦华胥。"]'),
('yuanqu-2065','陈季卿误上竹叶舟・金盏儿','杨梓','元','元曲','yuanqu','','[]','你不见远树蔽荆吴，暗水泛归舻。',73,'元曲/yuanqu.json','["你不见远树蔽荆吴，暗水泛归舻。", "从教他风涛汹涌蛟龙怒，你则是紧闭着双目，稳站着身躯，一任的棹穿江月泠，帆挂海云孤。", "寒烟生古渡，兀良便足你茅舍旧乡闾。"]'),
('yuanqu-2066','陈季卿误上竹叶舟・赚煞','杨梓','元','元曲','yuanqu','','[]','我与你踢倒鬼门关，打开这槐安路，把-枕南柯省悟。',104,'元曲/yuanqu.json','["我与你踢倒鬼门关，打开这槐安路，把-枕南柯省悟。", "再休被利锁名缰相缠住，急回头又蚤则暮景桑榆。", "你若是做吾徒，我与你割断凡俗，怕甚么苦海茫茫难跳出？趁烟霞伴侣，乘着这浮槎而去，兀的不朗吟飞过洞庭湖。", "(留荆篮下)。"]'),
('yuanqu-2067','陈季卿误上竹叶舟・双调/新水令','杨梓','元','元曲','yuanqu','','[]','五湖四海自遨游，则俺这拂天风两枚袍袖。',48,'元曲/yuanqu.json','["五湖四海自遨游，则俺这拂天风两枚袍袖。", "唤灵童采瑞草，同仙子上瀛洲。", "似这等荡荡悠悠，叹尘世几昏昼。"]'),
('yuanqu-2068','陈季卿误上竹叶舟・驻马听','杨梓','元','元曲','yuanqu','','[]','仙苑优游，物换星移几度秋。',64,'元曲/yuanqu.json','["仙苑优游，物换星移几度秋。", "将玄关参透，经了些夕阳西下水东流。", "一生空抱一生愁，千年可有千年寿。", "则合的蚤回头，和着那闲云野鹤常相守。"]'),
('yuanqu-2069','陈季卿误上竹叶舟・雁儿落','杨梓','元','元曲','yuanqu','','[]','你急煎煎误吞他名利钩，虚飘飘竟忘了我这烟霞叟。',41,'元曲/yuanqu.json','["你急煎煎误吞他名利钩，虚飘飘竟忘了我这烟霞叟。", "白茫茫穷途何处归，眼睁睁苦海无人救。"]'),
('yuanqu-2070','陈季卿误上竹叶舟・得胜令','杨梓','元','元曲','yuanqu','','[]','呀，你不道经史习如流，青紫不须忧，怎不将连城璧丹墀奏，博一个取凌阳万户侯，今日个啾啾。',71,'元曲/yuanqu.json','["呀，你不道经史习如流，青紫不须忧，怎不将连城璧丹墀奏，博一个取凌阳万户侯，今日个啾啾。", "这是你为官的偏生受，倒不如休也波休，蚤随我出家儿得自由。"]'),
('yuanqu-2071','陈季卿误上竹叶舟・挂玉钩','杨梓','元','元曲','yuanqu','','[]','你道我不是知音话不投，只去把《九域志》闲穷究。',70,'元曲/yuanqu.json','["你道我不是知音话不投，只去把《九域志》闲穷究。", "翻惹动你一点乡心泪暗流，滴满了征衫袖。", "现如今路又迷，途难叩，你则认那画里家山，怎知是梦里神游。"]'),
('yuanqu-2072','陈季卿误上竹叶舟・沽美酒','杨梓','元','元曲','yuanqu','','[]','你道是困萤窗年岁久，只待要题雁塔姓名留，壮志腾腾贯斗牛。',44,'元曲/yuanqu.json','["你道是困萤窗年岁久，只待要题雁塔姓名留，壮志腾腾贯斗牛。", "巴的个风云会偶，肯落在他人后？。"]'),
('yuanqu-2073','陈季卿误上竹叶舟・太平令','杨梓','元','元曲','yuanqu','','[]','你则说做官的金章紫绶，我则说出家的三岛十洲；你则说做官的功成名就，我则说出家的延年益寿。',69,'元曲/yuanqu.json','["你则说做官的金章紫绶，我则说出家的三岛十洲；你则说做官的功成名就，我则说出家的延年益寿。", "你呵罢手，闭口，只看我这道友，呀，那个不弃官如垢。"]'),
('yuanqu-2074','陈季卿误上竹叶舟・甜水令','杨梓','元','元曲','yuanqu','','[]','俺也曾凤阙跻攀，龙门踊跃，马蹄驰骤，高折桂枝秋。',53,'元曲/yuanqu.json','["俺也曾凤阙跻攀，龙门踊跃，马蹄驰骤，高折桂枝秋。", "偶然间经过邯郸，逢师点化，黄粱醒后，因此上把尘心一笔都勾。"]'),
('yuanqu-2075','陈季卿误上竹叶舟・川拨棹','杨梓','元','元曲','yuanqu','','[]','我笑你这呆头，便夺得个状元来应了口，受用着后拥前驺。',64,'元曲/yuanqu.json','["我笑你这呆头，便夺得个状元来应了口，受用着后拥前驺。", "画阁朱楼，舞袖歌喉。", "也做不得功施宇宙，(做指列科，唱)怎如俺这驭清风列御寇。"]'),
('yuanqu-2076','陈季卿误上竹叶舟・七弟兄','杨梓','元','元曲','yuanqu','','[]','怎如俺这运筹，决谋，汉留侯。',55,'元曲/yuanqu.json','["怎如俺这运筹，决谋，汉留侯。", "(指葛科，唱)怎如俺这炼丹砂葛令辞勾漏。", "你则看玉溪边烟水不停流，翠岩前风月长依旧。"]'),
('yuanqu-2077','陈季卿误上竹叶舟・梅花酒','杨梓','元','元曲','yuanqu','','[]','你可也休待两鬓秋，与天子分忧。',82,'元曲/yuanqu.json','["你可也休待两鬓秋，与天子分忧。", "叹岁月难留，蚤白了人头。", "你献《长杨》临紫陌，我寻大药返丹丘，共三人归去休。", "这一个倚银筝步瀛洲，这一个吹铁笛卧岩幽，这一个弹锦瑟上孤舟。"]'),
('yuanqu-2078','陈季卿误上竹叶舟・收江南','杨梓','元','元曲','yuanqu','','[]','呀，则俺呵曾经三醉岳阳楼，踏罡风吹上碧云游，枉下俺这大罗仙来度脱你个报官囚。',138,'元曲/yuanqu.json','["呀，则俺呵曾经三醉岳阳楼，踏罡风吹上碧云游，枉下俺这大罗仙来度脱你个报官囚。", "空笑杀城南老柳，则教你做一场蝴蝶梦庄周。", "(列御寇云)秀才，你既不肯跟随我等出家，不可久留在此，你回去罢。", "(陈季卿云)只是小生迷着路哩。", "(正末云)呆汉，前途不远，你到家近了也，只要你休忘了正道。", "(唱)。"]'),
('yuanqu-2079','陈季卿误上竹叶舟・梁州第七','杨梓','元','元曲','yuanqu','','[]','管甚么有程期夕阳西下，一任他没心情江水东流。',158,'元曲/yuanqu.json','["管甚么有程期夕阳西下，一任他没心情江水东流。", "常则是淡烟疏雨迷前后，经了些村桥野店，沙渚汀洲。", "俺自有蓑衣斜挂，箬笠轻兜。", "后来这打渔人少闷无愁，相伴着浴鹭眠鸥。", "恰离了陶朱公一派平湖，抹过了蜀诸葛三江渡口，蚤来到汉严陵七里滩头。", "你道那几个是咱故友，无过是沧波老树知心旧，楚江萍胜肥肉。", "还有那缩项的鳊鱼新上钩，吃的不醉无休。"]'),
('yuanqu-2080','陈季卿误上竹叶舟・隔尾','杨梓','元','元曲','yuanqu','','[]','你莫不是燃犀温峤江心里走，你莫不是鼓瑟湘灵水面上游，却教我呆邓邓葭蒲边耐心守。',71,'元曲/yuanqu.json','["你莫不是燃犀温峤江心里走，你莫不是鼓瑟湘灵水面上游，却教我呆邓邓葭蒲边耐心守。", "这里又不是关津隘口，又不是你家前院后，怎么的唤渡行人在那搭儿有。"]'),
('yuanqu-2081','陈季卿误上竹叶舟・贺新郎','杨梓','元','元曲','yuanqu','','[]','你道俺扣，渔人不索问根由，俺则问你是做买卖经商？(陈季卿云)不是。',386,'元曲/yuanqu.json','["你道俺扣，渔人不索问根由，俺则问你是做买卖经商？(陈季卿云)不是。", "(正末唱)是探故乡亲旧？(陈季卿云)不是。", "(正末唱)既不吵你怎生在长江侧畔将咱候？(陈季卿云)我是要过江去的。", "(正末唱)你莫不是楚三闾怀沙自投？你莫不是伍子胥雪父冤雠？你莫不是李谪仙扪月去？你莫不是郑交甫弄珠游？(陈季卿云)我要去的急，怎当这渔翁攀今揽古，只管里盘问我这许多，好生聒絮。", "渔翁，你猜的可也都不是，你只渡我过江去罢。", "(正末云)这等，你是什么样人，要我渡你？若不说呵，我也不渡。", "(陈季卿云)我是个应举落第的秀才。", "如今要回家去哩。", "(正末唱)原来是赶科场应举的村学究。", "若及第呵骤春风五花骢马辔，不及第则待泛沧浪一叶小渔舟。", "(陈季卿云)是了。", "我如今要赶回武林余杭去，见我父母妻子一面，就趁你这船，还要重来应举，我多与你些船钱如何？(正末云)这也使的。", "你快上来，我便开船也。", "(陈季卿做上船科)(正末唱)。"]'),
('yuanqu-2082','陈季卿误上竹叶舟・骂玉郎','杨梓','元','元曲','yuanqu','','[]','则被-天露湿渔蓑透，摇短棹下中流，过得这横桥独木龙腰瘦。',42,'元曲/yuanqu.json','["则被-天露湿渔蓑透，摇短棹下中流，过得这横桥独木龙腰瘦。", "见轻鸥，厮趁逐，妆点秋江秀。"]'),
('yuanqu-2083','陈季卿误上竹叶舟・感皇恩','杨梓','元','元曲','yuanqu','','[]','云影油油，风力飕飕。',75,'元曲/yuanqu.json','["云影油油，风力飕飕。", "转出这绿畅堤，芳草岸，蓼花洲。", "(陈季卿云)渔翁。", "这里那里？(正未唱)行尽了秦淮界首，不觉的吴越分流。", "可早则近乡闾，临故卫，莫停留。"]'),
('yuanqu-2084','陈季卿误上竹叶舟・采茶歌','杨梓','元','元曲','yuanqu','','[]','你不索问更筹，则看这水云收，半轮明月在柳梢头。',91,'元曲/yuanqu.json','["你不索问更筹，则看这水云收，半轮明月在柳梢头。", "(做住船科，云)秀才，我这船只在此，等你见了你父母妻子，你可便来。", "(唱)我这里将半橛孤桩船缆住，则听得汪汪犬吠竹林幽。", "(同陈季卿暂下)。"]'),
('yuanqu-2085','陈季卿误上竹叶舟・哭皇天','杨梓','元','元曲','yuanqu','','[]','则管里絮叨叨将他斗，泪潸潸不住流。',103,'元曲/yuanqu.json','["则管里絮叨叨将他斗，泪潸潸不住流。", "快随他齐臻臻鹅鹭侣，权撇下娇滴滴凤鸾俦。", "则不如准备着纶竿、纶竿钓舟，向富春渚侧，渭水河边，伴烟波渔父，风月闲人，倒落得个散诞逍遥、逍遥百不忧。", "遮莫的山崩海漏，鸟飞也那兔走。"]'),
('yuanqu-2086','陈季卿误上竹叶舟・三煞','杨梓','元','元曲','yuanqu','','[]','趁着这响咿哑数声柔橹前溪口，早看见明滴溜儿点渔灯古渡头。',137,'元曲/yuanqu.json','["趁着这响咿哑数声柔橹前溪口，早看见明滴溜儿点渔灯古渡头。", "(陈季卿云)渔翁，把船遥近岸些，兀的不起了风也。", "(正末唱)则见秋江雪浪拍天浮，更月黑云愁，疏刺刺风狂雨骤，这天气甚时候？(陈季卿云)渔翁，这等风雨，波浪陡作，兀的不唬杀我也！(正末唱)白茫茫银涛不断流，那里也骑鹤扬州。"]'),
('yuanqu-2087','陈季卿误上竹叶舟・二煞','杨梓','元','元曲','yuanqu','','[]','忽听的雷盘绝壁蛟龙吼，又则见电绕空林鬼魅愁。',116,'元曲/yuanqu.json','["忽听的雷盘绝壁蛟龙吼，又则见电绕空林鬼魅愁。", "似这等翻江搅海怒阳侯，唬的他怯怯乔乔，怎提防倾覆，这性命有准救？争些儿踏破渔翁一钓舟，做的个水上浮沤。", "(陈季卿云)哎哟，船坏了也！渔翁，你救我咱！(做念经科，云)太乙救苦天尊！(正未唱)。"]'),
('yuanqu-2088','陈季卿误上竹叶舟・黄钟尾','杨梓','元','元曲','yuanqu','','[]','你枉下告玄冥礼河们频叉手，只要你安魂魄定精神紧闭眸。',98,'元曲/yuanqu.json','["你枉下告玄冥礼河们频叉手，只要你安魂魄定精神紧闭眸。", "风陡作，水倒流，排三山，荡九州，撼天关，动地轴。", "唬的你战兢兢，似楚囚，死临侵，一命休，不能彀，葬故氏。", "从今后万古千秋，准与你奠一盏儿北邙坟上酒。"]'),
('yuanqu-2089','陈季卿误上竹叶舟・村里迓鼓','杨梓','元','元曲','yuanqu','','[]','我这卫洞大深处，端的是世人不到，我则待埋名隐姓，无荣无辱无烦无恼。',80,'元曲/yuanqu.json','["我这卫洞大深处，端的是世人不到，我则待埋名隐姓，无荣无辱无烦无恼。", "你看那蜗角名，蝇头利，多多少少，我则待夜睡到明，明睡到夜，睡直到觉。", "呀！蚤则似刮马儿光阴过下。"]'),
('yuanqu-2090','陈季卿误上竹叶舟・元和令','杨梓','元','元曲','yuanqu','','[]','我吃的是千家饭化半瓢，我穿的是百衲衣化一套。',66,'元曲/yuanqu.json','["我吃的是千家饭化半瓢，我穿的是百衲衣化一套。", "似这等粗衣淡饭且淹消，任天公饶不饶。", "我则待竹篱茅舍枕着山腰，掩柴扉静悄悄，叹人生空扰扰。"]'),
('yuanqu-2091','陈季卿误上竹叶舟・上马娇','杨梓','元','元曲','yuanqu','','[]','你待要名誉兴，爵位高，那些儿便是你杀人刀。',43,'元曲/yuanqu.json','["你待要名誉兴，爵位高，那些儿便是你杀人刀。", "几时得舒心快意宽怀抱？常则是，焦蹙损两眉梢。"]'),
('yuanqu-2092','陈季卿误上竹叶舟・胜葫芦','杨梓','元','元曲','yuanqu','','[]','你则待日夜思量计万条，怎如我无事乐陶陶。',50,'元曲/yuanqu.json','["你则待日夜思量计万条，怎如我无事乐陶陶。", "我这些春夏秋冬草不凋，倚晴窗寄傲，杖短筇凝眺，看海上熟蠕桃。"]'),
('yuanqu-2093','陈季卿误上竹叶舟・正宫/端正好','杨梓','元','元曲','yuanqu','','[]','俺不去北溟游，俺不去东山卧，得磨跎且自瞻跎。',44,'元曲/yuanqu.json','["俺不去北溟游，俺不去东山卧，得磨跎且自瞻跎。", "打数，打数声愚鼓向尘寰中坐，这便是俺闲功课。"]'),
('yuanqu-2094','陈季卿误上竹叶舟・滚绣球','杨梓','元','元曲','yuanqu','','[]','叹光阴似掷梭，想人生能几何？急问首百年已过，对菏铜两鬓皤皤。',92,'元曲/yuanqu.json','["叹光阴似掷梭，想人生能几何？急问首百年已过，对菏铜两鬓皤皤。", "见下留撇会科，听沙，二嘲会歌。", "送了些下峥嵘贪图呆货，到头来得了个甚么？你不见窗前故友午年少，郊外新坟岁岁多，这都是一枕南柯。"]'),
('yuanqu-2095','陈季卿误上竹叶舟・倘秀才','杨梓','元','元曲','yuanqu','','[]','则见他荆棘律忙忙走着，(做摇手科，唱)哎。',104,'元曲/yuanqu.json','["则见他荆棘律忙忙走着，(做摇手科，唱)哎。", "你个痴呆汉休来赶我。", "(陈季卿赶上扯住科，云)大仙，只望你普度慈悲，指引弟子长生之路。", "(做拜科)(正未唱)则间你捣蒜似街头拜怎摸？俺是个穷贫道，住山阿，怎将你儒生度脱。"]'),
('yuanqu-2096','陈季卿误上竹叶舟・滚绣球','杨梓','元','元曲','yuanqu','','[]','你道俺驾扁舟泛碧波，执渔竿披绿蓑，这就是仙家使作，你可也争些儿暴虎凭河。',213,'元曲/yuanqu.json','["你道俺驾扁舟泛碧波，执渔竿披绿蓑，这就是仙家使作，你可也争些儿暴虎凭河。", "(陈季卿云)师父，你既肯度脱弟子成仙了道，怎生又要把我掉在大江之中，险丧性命？你好促掏也。", "(正末做指列御寇科，唱)俺若不是打这讹，怎生着众仙真收这科？俺们交游还有弟兄七个，(陈季卿云)师父，你这上八界洞府，却在那里？(正末做手指科，唱)问洞府还隔的蓬岭嵯峨。", "(带云)要舞呵，(唱)自有霓裳羽袖纤腰舞，(带云)要歌呵，(唱)自有绛树、青琴皓齿歌，莫更蹉跎。"]'),
('yuanqu-2097','陈季卿误上竹叶舟・叨叨令','杨梓','元','元曲','yuanqu','','[]','俺那里有苍松偃蹇蛟龙卧，有青山高耸烟岚泼。',63,'元曲/yuanqu.json','["俺那里有苍松偃蹇蛟龙卧，有青山高耸烟岚泼。", "香风不动松华落，洞门深闭无人锁。", "俺和你去来也么哥，俺和你去来也么哥，修真共上蓬莱阁。"]'),
('yuanqu-2098','陈季卿误上竹叶舟・十二月','杨梓','元','元曲','yuanqu','','[]','这一个倒骑驴疾如下坡，(陈季卿云)元来是张果大仙。',198,'元曲/yuanqu.json','["这一个倒骑驴疾如下坡，(陈季卿云)元来是张果大仙。", "(做拜科)(正末指徐科唱)这一个吹铁笛韵美声和。", "(陈季卿云)是徐神翁大仙。", "(做拜科)(正未指何科唱)这一个貌娉婷笊篱手把，(陈季卿云)是何仙姑大仙。", "(做拜科)(正夫指李科唱)这一个蓬松铁拐横拖。", "(陈季卿云)是李铁拐大仙。", "(做拜科)(正末指韩科唱)这一个篮关前将文公度脱，(陈季卿云)是韩湘子大仙。", "(做拜科)(正末指蓝科，唱)这一个绿罗衫拍板高歌。"]'),
('yuanqu-2099','陈季卿误上竹叶舟・尧民歌','杨梓','元','元曲','yuanqu','','[]','主尘-个是双丫髻常吃的醉颜酡，(陈季卿云)是汉钟离大仙。',307,'元曲/yuanqu.json','["主尘-个是双丫髻常吃的醉颜酡，(陈季卿云)是汉钟离大仙。", "(做拜科，云)敢问师父姓甚名谁？(正末云)呆汉，俺不说来。", "(唱)则俺曾梦黄粱一晌滚汤锅，觉来时蚤五十载暗消磨，(陈季卿云)师父已曾说过，弟子真个忒愚迷。", "(做拜科，云)今日可也拜的着哩。", "(正末唱)才知道吕纯阳是俺正非他。", "(云)呆汉，只怕你也做梦哩。", "(陈季卿云)弟子如今委实省悟，不是做梦了也。", "(正末唱)你自去评跋评也波跋，休教咱冷笑呵，只要你觑的那名利场做些娘大。", "(东华帝君云)奉上帝敕旨，陈季卿既有神仙之分，做吕纯阳弟子，可着群仙引领西去，共赴蟠桃宴者。", "(词云)西望瑶池集众真，东来紫气彻天门。", "从今王母琼筵上，共献蟠桃增一人。", "(陈季卿同众共拜科)(正未唱)。"]'),
('yuanqu-2100','陈季卿误上竹叶舟・煞尾','杨梓','元','元曲','yuanqu','','[]','会瑶池庆赏蟠桃果，满捧在金盘献大罗，增俺仙家福寿多，保俺仙家永快活。',85,'元曲/yuanqu.json','["会瑶池庆赏蟠桃果，满捧在金盘献大罗，增俺仙家福寿多，保俺仙家永快活。", "你将这鹤氅乌巾手自摩，葛履环绦整顿过，音色骡儿便撒和驾一片祥云俺同坐。", "便有那十万里鹏程，怕甚么海天阔。"]'),
('yuanqu-2101','双调・蟾宫曲','盍志学','元','元曲','yuanqu','','[]','陶渊明自不合时，采菊东篱，为赋新诗。',72,'元曲/yuanqu.json','["陶渊明自不合时，采菊东篱，为赋新诗。", "独对南山，泛秋香有酒盈卮。", "一个小颗颗彭泽县儿，五斗米懒折腰肢。", "乐以琴诗，畅会寻思。", "万古流传，赋《归去来辞》。"]'),
('yuanqu-2102','黄钟・人月圆卜居外家东园','元好问','元','元曲','yuanqu','','[]','重冈已隔红尘断，村落更年丰。',118,'元曲/yuanqu.json','["重冈已隔红尘断，村落更年丰。", "移居要就，窗中远岫，舍后长松。", "十年种木，一年种谷，都付儿童。", "老夫惟有，醒来明月，醉后清风。", "玄都观里桃千树，花落水空流。", "凭君莫问，清泾浊渭，去马来牛。", "谢公扶病，羊昙挥涕，一醉都休。", "古今几度，生存华屋，零落山丘。"]'),
('yuanqu-2103','仙吕・后庭花破子','元好问','元','元曲','yuanqu','','[]','玉树后庭前，瑶华妆镜边。',78,'元曲/yuanqu.json','["玉树后庭前，瑶华妆镜边。", "去年花不老，今年月又圆。", "莫教偏，和花和月，大家长少年。", "夜夜璧月圆，朝朝琼树新。", "贵人三阁上，罗衣拂绣茵。", "后庭人，和花和月，共分今夜春。"]'),
('yuanqu-2104','中吕・喜春来春宴','元好问','元','元曲','yuanqu','','[]','春盘宜剪三生菜，春燕斜簪七宝钗，春风春酝透人怀。',136,'元曲/yuanqu.json','["春盘宜剪三生菜，春燕斜簪七宝钗，春风春酝透人怀。", "春宴排，齐唱喜春来。", "梅残玉靥香犹在，柳破金梢眼未开，东风和气满楼台。", "桃杏折，宜唱喜春来。", "梅擎残雪芳心奈，柳倚东风望眼开，温柔樽俎小楼台。", "红袖绕，低唱喜春来。", "携将玉友寻花寨，看褪梅妆等杏腮，休随刘阮到天台。", "仙洞窄，且唱喜春来。"]'),
('yuanqu-2105','双调・骤雨打新荷','元好问','元','元曲','yuanqu','','[]','绿叶阴浓，遍池塘水阁，偏趁凉多。',114,'元曲/yuanqu.json','["绿叶阴浓，遍池塘水阁，偏趁凉多。", "海榴初绽，妖艳喷香罗。", "老燕携雏弄语，有高柳鸣蝉相和。", "骤雨过，珍珠乱糁，打遍新荷。", "人生有几，念良辰美景，一梦初过。", "穷通前定，何用苦张罗？命友邀宾玩赏，对芳樽浅酌低歌。", "且酩酊，任他两轮日月，来往如梭。"]'),
('yuanqu-2106','南吕・骂玉郎过感皇恩采茶歌夏目','顾德润','元','元曲','yuanqu','','[]','衔泥燕子穿帘幕，早池塘贴新荷，庭槐堤柳鸣蝉和。',336,'元曲/yuanqu.json','["衔泥燕子穿帘幕，早池塘贴新荷，庭槐堤柳鸣蝉和。", "扇影罗，巾岸葛，花盈座。", "暑气无多，雨声初过。", "倚东床，开北牖，梦南柯。", "灯前恣舞，醉后狂歌。", "书慵注，琴倦抚，剑羞磨。", "挂青蓑，钓沧波，世尘不到小行窝。", "笑拥青蛾娇无那，年来放我且婆娑。", "述怀蛛丝满甑尘生釜，浩然气尚吞吴，并州每恨无亲故。", "三匝乌，千里驹，中原鹿。", "走遍长途，反下乔木。", "若立朝班，乘骢马，驾高车。", "常怀卞玉，敢引辛裾。", "羞归去，休进取，任揶揄。", "暗投珠，叹无鱼，十年窗下万言书。", "欲赋生来惊人语，必须苦下死工夫。", "人生傀儡棚中过，叹乌兔似飞梭，消磨岁月新工课。", "尚父蓑，元亮歌，灵均些。", "安乐行窝，风流花磨。", "闲呵诹，歪嗑牙，发乔科。", "山花袅娜，老子婆娑。", "心犹倦，时未来，志将何！爱风魔，怕风波，识人多处是非多。", "适兴吟哦无不可，得磨跎处且磨跎。"]'),
('yuanqu-2107','中吕・醉高歌过喜春来宿西湖梅花飘雪漫山，杨柳和烟放眼。画船稳系东风岸，金缕朱弦象板。','顾德润','元','元曲','yuanqu','','[]','春融南浦冰澌散，酒醒西楼月影悭，一天星斗水云寒。',35,'元曲/yuanqu.json','["春融南浦冰澌散，酒醒西楼月影悭，一天星斗水云寒。", "名利难，诗酒债且填还。"]'),
('yuanqu-2108','中吕・醉高歌过摊破喜春来旅中','顾德润','元','元曲','yuanqu','','[]','长江远映青山，回首难穷望眼。',82,'元曲/yuanqu.json','["长江远映青山，回首难穷望眼。", "扁舟来往蒹葭岸，人憔悴云林又晚。", "篱边黄菊经霜暗，囊底青蚨逐日悭。", "破清思晚砧鸣，断愁肠檐马韵，惊客梦晓钟寒。", "归去难，修一缄，回两字寄平安。"]'),
('yuanqu-2109','越调・黄蔷薇过庆元贞御水流','顾德润','元','元曲','yuanqu','','[]','红叶步秋香径晚，怨翠阁衾寒。',130,'元曲/yuanqu.json','["红叶步秋香径晚，怨翠阁衾寒。", "笑把霜枫叶拣，写罢衷情兴懒。", "几年月冷倚阑干，半生花落盼天颜，九重云锁隔巫山。", "休看作等闲，好去到人间。", "又止观光上国，近守御宫闱。", "霜染丹枫散绮，叶坠金沟泛水。", "凤城春色醉玻璃，龙香墨迹璨珠玑，鸾交天配选簪笄。", "宫妃直恁痴，题怨寄他谁。", "套数。"]'),
('yuanqu-2110','黄钟・愿成双忆别','顾德润','元','元曲','yuanqu','','[]','梅脸退，柳眼肥，雨丝丝开到荼コ。',32,'元曲/yuanqu.json','["梅脸退，柳眼肥，雨丝丝开到荼コ。", "一春常是盼佳期，不觉的香消玉体。"]'),
('yuanqu-2111','幺・忒风流姝媚忒聪慧，怎生般信绝音稀？叮宁杜宇那人行啼，冷落了秋','顾德润','元','元曲','yuanqu','','[]','千月底。',4,'元曲/yuanqu.json','["千月底。"]'),
('yuanqu-2112','出队子・科场不第，出落着个三不归。长安花酒价如泥，不信敲才主仗得，','顾德润','元','元曲','yuanqu','','[]','似恁般情怀说向谁？。',10,'元曲/yuanqu.json','["似恁般情怀说向谁？。"]'),
('yuanqu-2113','幺・到中秋左右还相会，见他时擘破面皮。紫泥宣于我甚便宜，青楼梦因','顾德润','元','元曲','yuanqu','','[]','谁没鉴识，且受回禁持悔甚的。',14,'元曲/yuanqu.json','["谁没鉴识，且受回禁持悔甚的。"]'),
('yuanqu-2114','尾・海神行忘不了些乔盟誓，多年前曾活取了个王魁，传槽病这些时敢轮','顾德润','元','元曲','yuanqu','','[]','到你。',3,'元曲/yuanqu.json','["到你。"]'),
('yuanqu-2115','仙吕・点绛唇四友争春','顾德润','元','元曲','yuanqu','','[]','四海飘篷，半生歌咏。',25,'元曲/yuanqu.json','["四海飘篷，半生歌咏。", "嗟尘冗，世事匆匆，苦被年光送。"]'),
('yuanqu-2116','混江龙・眼前青供，玉人降谪笑相逢。敲金击玉，咏月嘲风。三峡泉鸣新','顾德润','元','元曲','yuanqu','','[]','咳唾，千章诗著旧题封。',63,'元曲/yuanqu.json','["咳唾，千章诗著旧题封。", "春风杨柳，秋水芙蓉。", "温柔典雅，剔透玲珑。", "销人魂梦广寒宫，迷人踪迹桃源洞。", "友朋每如兄如弟，亲眷每非虎非熊。"]'),
('yuanqu-2117','油葫芦・天下湖山风月珑，这一伙作业种，莺俦燕侣不相容。锦心绣腹亲','顾德润','元','元曲','yuanqu','','[]','陪奉，月眉星眼情搬弄。',45,'元曲/yuanqu.json','["陪奉，月眉星眼情搬弄。", "茶供过三两巡，涎割到五六桶。", "攒下些高谈阔论成何用，端的是风月两无功。"]'),
('yuanqu-2118','天下乐・几曾见翠袖殷勤捧玉钟，三冬，节序穷，老廉颇岂堪施会勇。桑','顾德润','元','元曲','yuanqu','','[]','些柴弓悬臂间，纸糊锹逼手中，每日价干和哄。',21,'元曲/yuanqu.json','["些柴弓悬臂间，纸糊锹逼手中，每日价干和哄。"]'),
('yuanqu-2119','那吒令・江湖上量洪，谁强似孔融；天地间德行，怎学得仲弓；翠红乡钞','顾德润','元','元曲','yuanqu','','[]','猛，都不如邓通。',22,'元曲/yuanqu.json','["猛，都不如邓通。", "假老实，乔尊重，买做了先锋。"]'),
('yuanqu-2120','鹊踏枝・探花人气如虹，状元郎怒填胸，榜眼哥哥，尚自冲冲。你也哝恩','顾德润','元','元曲','yuanqu','','[]','多爱浓，想从前错怨了天公。',13,'元曲/yuanqu.json','["多爱浓，想从前错怨了天公。"]'),
('yuanqu-2121','寄生草・大厮家包藏得险，友朋每讲论得同。双生虽俊风声众，苏卿缺镘','顾德润','元','元曲','yuanqu','','[]','情肠痛，冯魁不语机谋中。',28,'元曲/yuanqu.json','["情肠痛，冯魁不语机谋中。", "风流浪子怎教贫？孤寒壮士愁难共。"]'),
('yuanqu-2122','梁州・他为我画阁中倦拈针指，我因他在绿窗前懒看诗书。这些时不由我','徐琰','元','元曲','yuanqu','','[]','心忧虑。',147,'元曲/yuanqu.json','["心忧虑。", "这些时琴闲了雁足，歌歇骊珠。", "则我这身心恍惚，鬼病揶揄。", "望夕阳对景嗟吁，倚危楼朝夜踌蹰。", "我、我、我，觑不的小池中一来一住交颈鸳鸯，听不的疏林外一递一声啼红杜宇，看不的画檐间一上一下斗巧蜘蛛。", "景物，态度。", "蛛蛛丝一丝丝又被风吹去，杜宇声一声声唤不住，鸳鸯对一对对分飞不趁逐，感起我一弄儿嗟吁。"]'),
('yuanqu-2123','尾声・再几时能够那柔条儿再接上连枝树，再几时能够那暖水儿重温活比','徐琰','元','元曲','yuanqu','','[]','目鱼，那的是着人断肠处。',36,'元曲/yuanqu.json','["目鱼，那的是着人断肠处。", "窗儿外夜雨，枕边厢泪珠，和我这一点芳心做不的主。"]'),
('yuanqu-2124','正宫・小梁州湖上分韵得玉字','任昱','元','元曲','yuanqu','','[]','波涵玉镜浸晴晖，鸣玉船移。',31,'元曲/yuanqu.json','["波涵玉镜浸晴晖，鸣玉船移。", "玉箫吹过画桥西，玉泉内，玉树锦云迷。"]'),
('yuanqu-2125','・玉楼帘幕香风细，玉阑干杨柳依依。飞玉觞，留玉佩；玉阑人沉醉，花外玉骢','任昱','元','元曲','yuanqu','','[]','幺嘶。',36,'元曲/yuanqu.json','["幺嘶。", "闲居结庐移石动云根，不受红尘。", "落花流水绕柴门，桃源近，犹有避秦人。"]'),
('yuanqu-2126','・草堂时共渔樵论：笔儿曹富贵浮云。椰子瓢，松花酝；山中风韵，乐道岂忧贫？春怀','任昱','元','元曲','yuanqu','','[]','幺落花无数满汀洲，转眼春休。',32,'元曲/yuanqu.json','["幺落花无数满汀洲，转眼春休。", "绿阴枝上杜鹃愁，空拖逗，白了少年头。"]'),
('yuanqu-2128','南吕・金字经湖上僧寺','任昱','元','元曲','yuanqu','','[]','竹雨侵窗润，松风吹面寒，云母屏开非世间。',163,'元曲/yuanqu.json','["竹雨侵窗润，松风吹面寒，云母屏开非世间。", "闲，不知名利难。", "凭阑看，夕阳山外山。", "重到湖上碧水寺边寺，绿杨楼外楼，闲看青山云去留。", "鸥，飘飘随钓舟。", "今非旧，对花一醉休。", "秋宵宴坐秋夜凉如水，天河白似银，风露清清湿簟纹。", "论，半生名利奔。", "窥吟鬓，江清月近人。", "书所见胜概三吴地，美人一梦云，花落黄昏空闭门。", "因，青鸾宝鉴分。", "天涯近，思君不见君。"]'),
('yuanqu-2129','中吕・上小楼题情','任昱','元','元曲','yuanqu','','[]','团圆未成，婵娟空病。',94,'元曲/yuanqu.json','["团圆未成，婵娟空病。", "桂子虚庭，翠羽围屏，雁足寒檠。", "巴到明，空自省，青楼薄幸，恨分开凤钗鸾镜。", "隐居荆棘满途，蓬莱闲住。", "诸葛茅庐，隐令松菊，张翰居鲈。", "不顺俗，不妄图，清高风度，任年年落花飞絮。"]'),
('yuanqu-2130','中吕・朝天子村居','任昱','元','元曲','yuanqu','','[]','杜门，守贫，知有归田分。',227,'元曲/yuanqu.json','["杜门，守贫，知有归田分。", "春风渐入小洼樽，勤饮姜芽嫩。", "乡党朱陈，讴歌尧舜，向东皋植杖耘。", "子孙，更淳，闲把诗书训。", "信笔九霄，早朝，曾赴金门诏。", "珠玉在挥毫，胸次谁同调？谈笑枚皋，风流温峤，恣疏狂直到老。", "尽教，醉了，走马长安道。", "道院翠峰，锦宫，香霭丹霞洞。", "来寻采药鹿皮翁，煮茗为清供。", "静听松风，闲吟《橘颂》，碧天凉月正中。", "九重，赐宠，一觉黄粱梦。", "题情渭城，雨晴，柳不系黄金镫。", "梨花小院又清明，误了寻芳兴。", "香减吴绫，尘蒙秦镜，碧纱窗和闷扃。", "柴荆，晓莺，巧语无心听。"]'),
('yuanqu-2131','中吕・满庭芳寄友','任昱','元','元曲','yuanqu','','[]','香笼锦帏，歌讴白苎，人比红梅。',120,'元曲/yuanqu.json','["香笼锦帏，歌讴白苎，人比红梅。", "风流杜牧新诗意，字字珠玑。", "桑落酒朝开绮席，杜陵花夜宿春衣。", "陶然醉，金勒马嘶，归路柳边迷。", "春暮云扃睡起，香销宝鼎，暧试罗衣。", "甫能宴罢兰亭会，又见春归。", "花片片翻成燕泥，柳依依也锁蛾眉。", "重门闭，绿阴树底，怕听杜鹃啼。"]'),
('yuanqu-2132','中吕・红绣鞋湖上','任昱','元','元曲','yuanqu','','[]','新亭馆相迎相送，古云山宜淡宜浓，画船归去有渔篷。',221,'元曲/yuanqu.json','["新亭馆相迎相送，古云山宜淡宜浓，画船归去有渔篷。", "随人松岭月，醒酒柳桥风，索新诗红袖拥。", "春情暗朱箔雨寒风峭，试罗衣玉减香销，落花时节怨良宵。", "银台灯影淡，绣枕泪痕交，团圆春梦少。", "重到吴门槐市歌阑酒散，枫桥雨霁秋残。", "旧题犹在画楼间。", "泛湖赊看月，寻寺强登山。", "比陶朱心更懒。", "芳草岸能言鸭睡，荻花洲供馔鲈肥，天平山翠近金杯。", "水多寒气早，野阔暮空低，隔秋云渔唱起。", "和友人韵茅屋秋风吹破，桂丛夜月空过，淮南招隐故情多。", "无心登虎帐，有梦到渔蓑，不归来等甚么？。"]'),
('yuanqu-2133','中吕・普天乐吴门客中','任昱','元','元曲','yuanqu','','[]','九秋天，三吴地，江空寒早，天远书迟。',251,'元曲/yuanqu.json','["九秋天，三吴地，江空寒早，天远书迟。", "黄菊开，丹枫坠。", "流水行云无拘系，好光阴枉自驱驰。", "尘心自洗，清风绿绮，明月金杯。", "湖上浣花溪，方壶地，呼猿领鹤，问柳寻梅。", "行厨白玉盘，进酒青楼妓。", "惊起沙头鸳鸯睡，棹红云乘兴而回。", "冰壶影里，笙歌远近，水榭高低。", "花园改道院锦江滨，红尘外，王孙去后，仙子归来。", "寒梅不改香，舞榭今何在？富贵浮云流光快，得清闲便是蓬莱。", "门迎野客，茶香石鼎，鹤守茅斋。", "暮春即事被诗魔，将花探，春深渭北，绿满江南。", "残红鱼浪香，接叶莺巢暗。", "古往今来无心勘，习家池日日春酣。", "人生易感，青铜似月，白发盈簪。"]'),
('yuanqu-2134','越调・小桃红','任昱','元','元曲','yuanqu','','[]','山林钟鼎未谋身，不觉生秋鬓。',256,'元曲/yuanqu.json','["山林钟鼎未谋身，不觉生秋鬓。", "汉水秦关古今恨，谩劳神，何须斗大黄金印。", "渔樵近邻，田园随分，甘作武陵人。", "东邻西舍酒频沽，拄杖穿花去。", "长笑功名草头露，且狂疏，醉如刘阮犹迟暮。", "鸡翁问余，鹿门深处，真作野人居。", "宴席桃花扇底楚天秋，恰恰莺声溜。", "络臂珍珠翠罗袖，捧金瓯，纤纤十指春葱瘦。", "移花旁酒，张灯如昼，重酌更风流。", "指甲桃腮轻托玉纤微，有恨弹珠泪。", "曾整金钗动春意，数归期，等闲掐损阑干翠。", "拈花露湿，剖橙香腻，宜捧紫霞杯。", "春情深沉院落牡丹残，懒揭珠帘看，青杏园林管弦散。", "翠阴间，数声黄鸟伤春叹。", "离怀未安，相思不惯，独倚小阑干。"]'),
('yuanqu-2135','越调・寨儿令湖上','任昱','元','元曲','yuanqu','','[]','锦制屏，镜涵冰，浓脂淡粉如故情。',138,'元曲/yuanqu.json','["锦制屏，镜涵冰，浓脂淡粉如故情。", "酒量长鲸，歌韵雏莺，醉眼看丹青。", "养花天云淡风轻，胜桃源水秀山明。", "赋诗题下竺，携友过西泠。", "撑，船向柳边行。", "书所见眉黛浅，鬓云偏，羞颜落色谁爱怜？种玉无缘，掷果徒然，回首叹芳年。", "碧波不寄鱼笺，翠衾寒犹带龙涎。", "飞花残雨后，新月小窗前。", "天，斗帐恨孤眠。"]'),
('yuanqu-2136','双调・水仙子书所见','任昱','元','元曲','yuanqu','','[]','闲开翠牖近沧州，忽见蛾眉出舵楼，来陪燕席翻红袖。',233,'元曲/yuanqu.json','["闲开翠牖近沧州，忽见蛾眉出舵楼，来陪燕席翻红袖。", "舞春风宜佐酒，匆匆催去难留。", "解湘水烟中佩，驾浔阳江上舟，瘦损风流。", "泛舟牙樯绵缆过沙汀，皓齿青蛾捧玉觥，银塘绿水磨铜镜。", "船如天上行，人传李郭仙名。", "水晶寒瓜初破，藕花香洒易醒，无限诗情。", "友人席上绛罗为帐护寒轻，银甲弹筝带醉听，玉奴捧砚催诗赠。", "写青楼一片情，尽疏狂席上风生。", "红锦缠头罢，金钗剪烛明，有酒如渑。", "幽居小堂不闭野云封，隔岸时闻涧水舂，比邻分得山田种。", "宦情薄归兴浓，想从前错怨天公。", "食禄黄齑瓮，忘忧绿酒钟。", "未必全穷。"]'),
('yuanqu-2137','双调・庆东原','任昱','元','元曲','yuanqu','','[]','香衾剩，春梦窄，仙山消息遥天外。',101,'元曲/yuanqu.json','["香衾剩，春梦窄，仙山消息遥天外。", "愁欺酒杯，羞临镜台，泪湿香腮。", "金屋燕归来，玉佩人何在？题武陵友人别邺城南即事寻幽处，读古书，似韩符昔日城南住。", "口亭傍竹，藩篱带菊，池沼栽鱼。", "非是辋川图，堪作郊居赋。", "套数。"]'),
('yuanqu-2138','南吕・一枝花题东湖纤云曳晓红，远树团晴翠。好山如凤凰，新水似琉璃，巧画屏帏。','任昱','元','元曲','yuanqu','','[]','壮观蓬莱地，东湖景最奇。',28,'元曲/yuanqu.json','["壮观蓬莱地，东湖景最奇。", "两三行鸥鹭清闲，七十二峰峦秀美。"]'),
('yuanqu-2139','梁州・露屿寺僧吟翠微，月波楼客宴金杯，宝华台殿松阴蔽。赤栏桥畔，','任昱','元','元曲','yuanqu','','[]','想像瑶池；金沙路上，胜却苏堤。',90,'元曲/yuanqu.json','["想像瑶池；金沙路上，胜却苏堤。", "若东坡来此游历，向西湖懒把诗题。", "学士庙绀宇朱扉，观音洞金堂玉室，宰相家翠竹清溪。", "会稽，鉴水。", "贺知章谩奖多佳致，放船去在天际。", "杨柳风轻生浪迟，漾动玻璃。"]'),
('yuanqu-2140','迷青琐倩女离魂・仙吕/赏花时','郑光祖','元','元曲','yuanqu','','[]','他是个矫帽轻衫小小郎，我是个绣帔香车楚楚娘，恰才貌正相当。',46,'元曲/yuanqu.json','["他是个矫帽轻衫小小郎，我是个绣帔香车楚楚娘，恰才貌正相当。", "俺娘向阳台路上，高筑起一堵雨云墙。"]'),
('yuanqu-2141','迷青琐倩女离魂・幺篇','郑光祖','元','元曲','yuanqu','','[]','可待要隔断巫山窈窕娘，怨女鳏男各自伤。',58,'元曲/yuanqu.json','["可待要隔断巫山窈窕娘，怨女鳏男各自伤。", "不争你左使着一片黑心肠，你不拘箝我倒不想，你把我越间阻。", "越思量。", "（同梅香下）。"]'),
('yuanqu-2142','迷青琐倩女离魂・仙吕/点绛唇','郑光祖','元','元曲','yuanqu','','[]','捱彻凉宵，疯然惊觉，纱窗晓。',25,'元曲/yuanqu.json','["捱彻凉宵，疯然惊觉，纱窗晓。", "落叶萧萧，满地无人扫。"]'),
('yuanqu-2143','迷青琐倩女离魂・混江龙','郑光祖','元','元曲','yuanqu','','[]','可正是暮秋天道，尽收拾心事上眉梢，镜台儿何曾览照，绣针儿不待拈着。',146,'元曲/yuanqu.json','["可正是暮秋天道，尽收拾心事上眉梢，镜台儿何曾览照，绣针儿不待拈着。", "常夜坐窗前烛影昏，一任晚妆楼上月儿高。", "俺本是乘鸾艳质，他须有中雀丰标。", "苦被煞尊堂间阻，争把俺情义轻抛。", "空误了幽期密约，虚过了月夕花朝。", "无缘配合，有分煎熬。", "情默默难解自无聊，病恹恹则怕知道。", "窥之远，天宽地窄；染之重，梦断魂劳！。"]'),
('yuanqu-2144','迷青琐倩女离魂・油葫芦','郑光祖','元','元曲','yuanqu','','[]','他不病倒，我猜着敢消瘦了。',141,'元曲/yuanqu.json','["他不病倒，我猜着敢消瘦了。", "被拘箝的不忿心，教他怎动脚？虽不是路迢迢，早情随着云渺渺，泪洒做雨潇潇。", "不能勾榜阑干数曲湖山靠，恰便似望天涯一点青山小。", "（带云）秀才他寄来的诗，也埋怨俺娘哩。", "（唱）他多管是意不平，自发扬，心不遂，闲缀作，十分的卖风骚，显秀丽，夸才调。", "我这里详句法，看挥毫。"]'),
('yuanqu-2145','迷青琐倩女离魂・天下乐','郑光祖','元','元曲','yuanqu','','[]','只道读书人志气高，元来这凄凉，甚日了。',65,'元曲/yuanqu.json','["只道读书人志气高，元来这凄凉，甚日了。", "想俺这孤男寡女忒命薄。", "我安排着鸳鸯宿，锦被香；他盼望着鸾凤鸣，琴瑟调；怎做得蝴蝶飞，锦树绕。"]'),
('yuanqu-2146','迷青琐倩女离魂・那吒令','郑光祖','元','元曲','yuanqu','','[]','我一年一日过了，团圆日子较少；三十三天觑了，离恨天最高；四百四病害了，相思病怎熬。',80,'元曲/yuanqu.json','["我一年一日过了，团圆日子较少；三十三天觑了，离恨天最高；四百四病害了，相思病怎熬。", "（带云）他如今待应举去呵！（唱）千里将凤阙攀，一举把龙门跳，接丝鞭，总是娇娆。"]'),
('yuanqu-2147','迷青琐倩女离魂・鹊踏枝','郑光祖','元','元曲','yuanqu','','[]','据胸次，那英豪；论人品，更清高。',51,'元曲/yuanqu.json','["据胸次，那英豪；论人品，更清高。", "他管跳出黄尘，走上青霄。", "又不比闹清晓，茅檐燕雀；他是掣风涛，混海鲸鳌。"]'),
('yuanqu-2148','迷青琐倩女离魂・寄生草','郑光祖','元','元曲','yuanqu','','[]','他拂索楮，鹅溪茧，蘸中山玉免毫。',74,'元曲/yuanqu.json','["他拂索楮，鹅溪茧，蘸中山玉免毫。", "不弱如骆宾王夜作论天表，也不让李太白醉写平蛮稿，也不比汉相如病受征贤诏。", "他辛勤十年书剑洛阳城，决峥嵘一朝冠盖长安道。"]'),
('yuanqu-2149','迷青琐倩女离魂・村里迓鼓','郑光祖','元','元曲','yuanqu','','[]','则他这渭城朝雨，洛阳残照。',114,'元曲/yuanqu.json','["则他这渭城朝雨，洛阳残照。", "虽不唱阳关曲本，今日来祖送长安年少，兀的不取次弃舍，等闲抛掉，因而零落！（做叹科，云）哥哥！（唱）恰楚泽深，秦关杳，秦华高。", "叹人生，离多会少！（正末云）小姐，我若为了官呵，你就是夫人县君也。", "（正旦唱）。"]'),
('yuanqu-2150','迷青琐倩女离魂・元和令','郑光祖','元','元曲','yuanqu','','[]','杯中酒，和泪酌；心间事，对伊道。',52,'元曲/yuanqu.json','["杯中酒，和泪酌；心间事，对伊道。", "似长亭折柳赠柔条，哥哥，你休有上梢没下梢。", "从今虚度可怜宵，奈离愁不了！。"]'),
('yuanqu-2151','迷青琐倩女离魂・上马娇','郑光祖','元','元曲','yuanqu','','[]','竹窗外响翠梢，苔砌下深绿草，书舍顿萧条，故园悄悄无人到。',39,'元曲/yuanqu.json','["竹窗外响翠梢，苔砌下深绿草，书舍顿萧条，故园悄悄无人到。", "恨怎消，此际最难煞！。"]'),
('yuanqu-2152','迷青琐倩女离魂・游四门','郑光祖','元','元曲','yuanqu','','[]','抵多少彩云声断紫鸾箫，今夕何处系兰桡。',44,'元曲/yuanqu.json','["抵多少彩云声断紫鸾箫，今夕何处系兰桡。", "片帆休遮，西风恶，雪卷浪淘淘。", "岸影高，千里水云飘。"]'),
('yuanqu-2153','迷青琐倩女离魂・胜葫芦','郑光祖','元','元曲','yuanqu','','[]','你是必休做了冥鸿惜羽毛。',49,'元曲/yuanqu.json','["你是必休做了冥鸿惜羽毛。", "常言道：好事不坚牢。", "你身去休教心去了。", "对郎君低告，恰梅香报道，恐怕母亲焦。"]'),
('yuanqu-2154','迷青琐倩女离魂・赚煞','郑光祖','元','元曲','yuanqu','','[]','从今后只合题恨写芭蕉，不索占梦揲蓍草。',188,'元曲/yuanqu.json','["从今后只合题恨写芭蕉，不索占梦揲蓍草。", "有甚心肠，更珠围以饶。", "我这一点真情魂缥渺，他去后，不离了前后周遭。", "厮随着司马题桥，也不指望驷马高车显荣耀。", "不争把琼姬弃却，比及盼子高来到，早辜负了碧桃花下凤鸾交。", "（同梅香下）（正末云）你孩儿则今日拜别了母亲，便索长行也。", "左右，将马来，则今日进取功名，走一遭去。", "（下）（夫人云）王秀才去了也，等他得了官回来，成就这门亲事，未为迟哩。", "（下）。"]'),
('yuanqu-2155','迷青琐倩女离魂・越调/斗鹌鹑','郑光祖','元','元曲','yuanqu','','[]','人去阳台，云归楚峡。',63,'元曲/yuanqu.json','["人去阳台，云归楚峡。", "不争他江渚停舟，几时得门庭过马？悄悄冥冥，潇潇洒洒。", "我这里踏岸沙，步月华；我觑这万水千山，都只在一时半霎。"]'),
('yuanqu-2156','迷青琐倩女离魂・紫花儿序','郑光祖','元','元曲','yuanqu','','[]','想倩女心间离恨，赶王生柳外兰舟，似盼张骞天上浮槎。',111,'元曲/yuanqu.json','["想倩女心间离恨，赶王生柳外兰舟，似盼张骞天上浮槎。", "汗溶溶琼珠莹脸，乱松松云髻堆鸦，走的我筋力疲乏。", "你莫不夜泊秦淮卖酒家？向断桥西下，疏剌剌秋水菰蒲，冷清清明月芦花。", "（云）走了半日，来到江边，听的人语喧闹，我试觑咱。", "（唱）。"]'),
('yuanqu-2157','迷青琐倩女离魂・小桃红','郑光祖','元','元曲','yuanqu','','[]','我蓦听得马嘶人语喧哗，掩映在垂杨下，唬的我心头丕丕那惊怕，原来是响王吉王吉榔板捕鱼虾。',84,'元曲/yuanqu.json','["我蓦听得马嘶人语喧哗，掩映在垂杨下，唬的我心头丕丕那惊怕，原来是响王吉王吉榔板捕鱼虾。", "我这里须风悄悄听沉罢，趁着这厌厌露华，对着这澄澄月下，惊的那呀、呀、呀寒雁起平沙。"]'),
('yuanqu-2158','迷青琐倩女离魂・调笑令','郑光祖','元','元曲','yuanqu','','[]','向沙堤款踏，莎草带霜滑；掠湿湘裙翡翠纱，抵多少苍苔露冷凌波袜。',56,'元曲/yuanqu.json','["向沙堤款踏，莎草带霜滑；掠湿湘裙翡翠纱，抵多少苍苔露冷凌波袜。", "看江上晚来堪画，玩冰壶潋滟天上下，似一片碧玉无瑕。"]'),
('yuanqu-2159','迷青琐倩女离魂・圣药王','郑光祖','元','元曲','yuanqu','','[]','近蓼洼，缆钓槎，有折蒲衰柳老蒹葭；傍水凹，折藕芽，见烟笼寒水月笼沙，茅舍两三家。',40,'元曲/yuanqu.json','["近蓼洼，缆钓槎，有折蒲衰柳老蒹葭；傍水凹，折藕芽，见烟笼寒水月笼沙，茅舍两三家。"]'),
('yuanqu-2160','迷青琐倩女离魂・麻郎儿','郑光祖','元','元曲','yuanqu','','[]','你好是舒心的伯牙，我做了没路的浑家。',60,'元曲/yuanqu.json','["你好是舒心的伯牙，我做了没路的浑家。", "你道我为甚么私离绣榻，待和伊同走天涯。", "（正末云）小姐是车儿来，是马儿来？（魂旦唱）。"]'),
('yuanqu-2161','迷青琐倩女离魂・幺','郑光祖','元','元曲','yuanqu','','[]','把、咱家、走乏，比及你远赴京华。',32,'元曲/yuanqu.json','["把、咱家、走乏，比及你远赴京华。", "薄命妾为伊牵挂，思量心几时撇下。"]'),
('yuanqu-2162','迷青琐倩女离魂・络丝娘','郑光祖','元','元曲','yuanqu','','[]','你抛闪咱，比及见咱，我不瘦杀，多应害杀。',135,'元曲/yuanqu.json','["你抛闪咱，比及见咱，我不瘦杀，多应害杀。", "（正末云）若老夫人知道怎了也？（魂旦唱）他若是赶上咱，待怎么？常言道：做着不怕。", "（正末做怒科，云）古人云：聘则为妻，奔则为妾。", "老夫人许了亲事，待小生得官回来，谐两姓之好，却不名正言须！你袅私自赶来，有玷风化，是何道理？（魂旦唱）。"]'),
('yuanqu-2163','迷青琐倩女离魂・紫花儿序','郑光祖','元','元曲','yuanqu','','[]','只道你急煎煎趱登程路，元来是闷沉沉困倚琴书，怎不教我痛煞煞泪湿湿琵琶。',133,'元曲/yuanqu.json','["只道你急煎煎趱登程路，元来是闷沉沉困倚琴书，怎不教我痛煞煞泪湿湿琵琶。", "有甚心着雾鬓轻笼蝉翅，双眉淡扫宫鸦，以落絮飞花。", "谁待问出外争如只在家，更无多话，愿秋风驾百尺高帆，尽春光付一树铅华。", "（云）王秀才，赶你不为别，我只防你一件。", "（正末云）小姐防我那一件来？（魂旦唱）。"]'),
('yuanqu-2164','迷青琐倩女离魂・东原乐','郑光祖','元','元曲','yuanqu','','[]','你若是赴御宴琼林罢，媒人每拦住马，高挑起染渲佳人丹青画，卖弄他生长在王侯宰相家。',58,'元曲/yuanqu.json','["你若是赴御宴琼林罢，媒人每拦住马，高挑起染渲佳人丹青画，卖弄他生长在王侯宰相家。", "你恋着那奢华，你敢新婚燕尔在他门下。"]'),
('yuanqu-2165','迷青琐倩女离魂・绵搭絮','郑光祖','元','元曲','yuanqu','','[]','你做了贵门娇客，一样矜夸；那相府荣华，锦绣堆压，你还想飞入寻常百姓家？那时节似钱跃龙门播海涯，饮御酒插宫花。',68,'元曲/yuanqu.json','["你做了贵门娇客，一样矜夸；那相府荣华，锦绣堆压，你还想飞入寻常百姓家？那时节似钱跃龙门播海涯，饮御酒插宫花。", "那其间占鳌头，占鳌头登上甲。"]'),
('yuanqu-2166','迷青琐倩女离魂・幺篇','郑光祖','元','元曲','yuanqu','','[]','把梢公快唤咱，恐家中厮捉拿，只见远寒鸦，岸草汀沙，满目黄花，几缕残霞。',102,'元曲/yuanqu.json','["把梢公快唤咱，恐家中厮捉拿，只见远寒鸦，岸草汀沙，满目黄花，几缕残霞。", "快先把云帆高挂，月明直下；便东风刮，莫消停，疾进发。", "（正末云）小姐，则今日同我上京应举去来。", "我若得了官，你便是夫人县君也。", "（魂旦唱）。"]'),
('yuanqu-2167','迷青琐倩女离魂・收尾','郑光祖','元','元曲','yuanqu','','[]','各剌剌向长安道上把车儿驾，但愿得文苑客当时奋发。',54,'元曲/yuanqu.json','["各剌剌向长安道上把车儿驾，但愿得文苑客当时奋发。", "则我这临邛市沽酒卓文君，甘休侍你濯锦江题桥汉司马。", "（同下）。"]'),
('yuanqu-2168','迷青琐倩女离魂・中吕/粉堞儿','郑光祖','元','元曲','yuanqu','','[]','自执手临歧，空留下这场憔悴，想人生最苦别离。',61,'元曲/yuanqu.json','["自执手临歧，空留下这场憔悴，想人生最苦别离。", "说话处少精神，睡卧处无颠倒，茶饭不知滋味。", "似这般废寝忘食，折挫得一日瘦如一日。"]'),
('yuanqu-2169','迷青琐倩女离魂・红绣鞋','郑光祖','元','元曲','yuanqu','','[]','去时节杨柳西风秋日，如今又过了梨花暮雨寒食。',78,'元曲/yuanqu.json','["去时节杨柳西风秋日，如今又过了梨花暮雨寒食。", "（梅香云）姐姐，你可曾卜一卦么？（正旦唱）则兀那龟儿卦无定准，枉央及；喜蛛儿难凭信，灵鹊儿不诚实，灯花儿何太喜。"]'),
('yuanqu-2170','迷青琐倩女离魂・普天乐','郑光祖','元','元曲','yuanqu','','[]','想鬼病最关心，似宿酒迷春睡。',116,'元曲/yuanqu.json','["想鬼病最关心，似宿酒迷春睡。", "绕晴雪杨花陌上，趁东风燕子楼西。", "抛闪杀我年少人，辜负子这韶华日。", "早是离愁添萦系，更那堪景物狼籍。", "愁心惊一声鸟啼，薄命趁一春事已，香魂逐一片花飞。", "(正旦昏科)(夫人云)孩儿，你挣挫些儿！(正旦醒科)(唱)。"]'),
('yuanqu-2171','迷青琐倩女离魂・石榴花','郑光祖','元','元曲','yuanqu','','[]','早是俺抱沉疴添新病发昏迷，也则是死限紧相催逼，膏盲针灸不能及。',151,'元曲/yuanqu.json','["早是俺抱沉疴添新病发昏迷，也则是死限紧相催逼，膏盲针灸不能及。", "(夫人云)我请个良医来调治你。", "(正旦唱)若是他来到这里，煞强如请扁鹊卢医。", "(夫人云)我如今着人请王生去。", "(正旦唱)把似请他时便许做东床婿，到如今悔后应迟。", "(夫人云)王生去了，再无音信寄来。", "(正旦唱)他不寄个报喜的信息缘何意，有两件事我先知。"]'),
('yuanqu-2172','迷青琐倩女离魂・斗鹌鹑','郑光祖','元','元曲','yuanqu','','[]','他得了官别就新婚，剥落呵羞归故里。',116,'元曲/yuanqu.json','["他得了官别就新婚，剥落呵羞归故里。", "(夫人云)孩儿休过虑，且将息自己。", "(正旦唱)眼见的千死千休，折倒的半人半鬼。", "为甚这思竭损的枯肠不害饥，苦恹恹一肚皮。", "(夫人云)孩儿吃些汤粥。", "(正旦云)母亲，(唱)若肯成就了燕尔新婚，强如吃龙肝凤髓。"]'),
('yuanqu-2173','迷青琐倩女离魂・上小楼','郑光祖','元','元曲','yuanqu','','[]','则道你辜恩负德，你原来得官及第。',55,'元曲/yuanqu.json','["则道你辜恩负德，你原来得官及第。", "你直叩丹墀，夺得朝章，换却白衣。", "觑画仪，比向日、相别之际，更有三千丈五陵豪气。"]'),
('yuanqu-2174','迷青琐倩女离魂・幺篇','郑光祖','元','元曲','yuanqu','','[]','空疑惑了大一会，恰分明这搭里。',100,'元曲/yuanqu.json','["空疑惑了大一会，恰分明这搭里。", "俺淘写相思，叙问寒温，诉说真实。", "他紧摘离，我猛跳起。", "早难寻难觅．只见这冷清清半竿残日。", "(梅香上，云)姐姐，为何大惊小怪的？(正旦云)我恰才梦见王生，说他得了官也。", "(唱)。"]'),
('yuanqu-2175','迷青琐倩女离魂・十二月','郑光祖','元','元曲','yuanqu','','[]','元来是一枕南柯梦里，和二三子义翰相知。',55,'元曲/yuanqu.json','["元来是一枕南柯梦里，和二三子义翰相知。", "他访叫科习五常典礼。", "通六艺有七步才识，凭八韵赋纵横大笔，九人上得遂风雷。"]'),
('yuanqu-2176','迷青琐倩女离魂・尧民歌','郑光祖','元','元曲','yuanqu','','[]','想十年身刮凤凰池，和九卿相八元辅劝余杯。',68,'元曲/yuanqu.json','["想十年身刮凤凰池，和九卿相八元辅劝余杯。", "则他那七言诗六合里少人及。", "端的个五福全四气备占伦魁，震三月春雷。", "双亲行先报喜，都为这一纸蹬科记。"]'),
('yuanqu-2177','迷青琐倩女离魂・哨遍','郑光祖','元','元曲','yuanqu','','[]','将往事从头思忆，百年情只落得一口长吁气。',125,'元曲/yuanqu.json','["将往事从头思忆，百年情只落得一口长吁气。", "为甚么把婚聘礼不曾题，恐少年堕落了春闱。", "想当日在竹边书舍，柳外离亭，有多少徘徊意。", "争奈匆匆去急，再不见音容潇洒，空留下这词翰清奇。", "把巫山错认做望夫石，将小简帖联做《断肠集》。", "恰微雨初阴，早皓月穿窗，使行云易飞。"]'),
('yuanqu-2178','迷青琐倩女离魂・耍孩儿','郑光祖','元','元曲','yuanqu','','[]','俺娘把冰绡剪破鸳鸯只，不忍别远送出阳关数里。',87,'元曲/yuanqu.json','["俺娘把冰绡剪破鸳鸯只，不忍别远送出阳关数里。", "此时无计住雕鞍，奈离愁与心事相随。", "愁萦遍垂杨占驿丝千缕，泪添满落日长亭酒一杯。", "从此去孤辰限凄凉日，忆乡关愁云阻隔，着床枕鬼病禁持。"]'),
('yuanqu-2179','迷青琐倩女离魂・四煞','郑光祖','元','元曲','yuanqu','','[]','都做了一春鱼雁无消息，不甫能一纸音书盼得。',87,'元曲/yuanqu.json','["都做了一春鱼雁无消息，不甫能一纸音书盼得。", "我则道春心满纸墨淋漓，原来比休书多了个封皮。", "气的我痛如泪血流难尽，争些魂逐东风吹不回。", "秀才每心肠黑，一个个贫儿乍富，一个个饱病难医。"]'),
('yuanqu-2180','迷青琐倩女离魂・二煞','郑光祖','元','元曲','yuanqu','','[]','情女呵病缠身则愿的天可怜，梅香呵我心事则除是你尽知。',79,'元曲/yuanqu.json','["情女呵病缠身则愿的天可怜，梅香呵我心事则除是你尽知。", "望他来表白我真诚意。", "半年甘分耽疾病，镇日无心扫黛眉。", "不甫能挨得到今日，头直上打一轮皂盖，马头前列两行朱衣。"]'),
('yuanqu-2181','迷青琐倩女离魂・尾煞','郑光祖','元','元曲','yuanqu','','[]','并不闻琴边续断弦，倒做了山间滚磨旗。',50,'元曲/yuanqu.json','["并不闻琴边续断弦，倒做了山间滚磨旗。", "划地接丝鞭别娶了新妻室。", "这是我弃死忘生落来的。", "(梅香扶正旦下)。"]'),
('yuanqu-2182','迷青琐倩女离魂・黄钟/醉花阴','郑光祖','元','元曲','yuanqu','','[]','行李萧萧倦修整，甘岁月淹留帝京。',59,'元曲/yuanqu.json','["行李萧萧倦修整，甘岁月淹留帝京。", "只听的花外杜鹃声，催起归程。", "将往事，从头省，我心坎上犹自不惺惺，做了场弃业抛家恶梦境。"]'),
('yuanqu-2183','迷青琐倩女离魂・喜迁莺','郑光祖','元','元曲','yuanqu','','[]','据才郎心性，莫不是向天公买拨来的聪明？那史内才外才相称，-见了不由人不动情。',81,'元曲/yuanqu.json','["据才郎心性，莫不是向天公买拨来的聪明？那史内才外才相称，-见了不由人不动情。", "忒志诚，兀的不倾了人性命？引了人魂灵？(正末云)小姐，兜住马慢慢地行将去。", "(魂旦唱)。"]'),
('yuanqu-2184','迷青琐倩女离魂・出队子','郑光祖','元','元曲','yuanqu','','[]','骑一匹龙驹，畅好口硬。',65,'元曲/yuanqu.json','["骑一匹龙驹，畅好口硬。", "恰便似驮张纸，不恁般轻。", "腾腾腾收不住玉勒，常是虚惊；火火火坐不稳雕鞍，划地眼生；撒撒撒挽不定丝僵，则待撺行。"]'),
('yuanqu-2185','迷青琐倩女离魂・刮地风','郑光祖','元','元曲','yuanqu','','[]','行了些这没撒和的长途有十数程，越恁的骨瘦蹄轻。',92,'元曲/yuanqu.json','["行了些这没撒和的长途有十数程，越恁的骨瘦蹄轻。", "暮春天景物撩人兴，更见景留情。", "怪的是满路花生，一攒攒绿杨红杏，一双权紫燕黄莺，一对蜂，一对蝶，各相比并，想大公知他是怎生，不肯教恶了人情。"]'),
('yuanqu-2186','迷青琐倩女离魂・四门子','郑光祖','元','元曲','yuanqu','','[]','中间里列一道红芳径，教俺美夫妻并马儿行。',82,'元曲/yuanqu.json','["中间里列一道红芳径，教俺美夫妻并马儿行。", "咱如今富贵还乡井，方信道耀门间昼锦荣。", "若见俺娘，那一会惊，刚道来的话儿不中听。", "是这等门厮当，户厮撑，怎教咱做妹妹哥哥答应？。"]'),
('yuanqu-2187','迷青琐倩女离魂・古寨儿令','郑光祖','元','元曲','yuanqu','','[]','可怜我伶仃，也那伶仃，阁不住两泪盈盈，手拍着胸脯自招承。',44,'元曲/yuanqu.json','["可怜我伶仃，也那伶仃，阁不住两泪盈盈，手拍着胸脯自招承。", "自感叹，自伤情，自懊悔，自由性。"]'),
('yuanqu-2188','迷青琐倩女离魂・古神仗儿','郑光祖','元','元曲','yuanqu','','[]','俺娘他毒害的有名，全无那子母面情。',65,'元曲/yuanqu.json','["俺娘他毒害的有名，全无那子母面情。", "则被他将一个痴小冤家，送的来离乡背井。", "每日价烦烦恼恼，孤孤另另。", "少不得厌煎成病，断送了，泼残生。"]'),
('yuanqu-2189','迷青琐倩女离魂・幺篇','郑光祖','元','元曲','yuanqu','','[]','没揣的一声狠似雷霆，猛可里唬一惊，丢了魂灵。',73,'元曲/yuanqu.json','["没揣的一声狠似雷霆，猛可里唬一惊，丢了魂灵。", "这的是俺娘的弊病，要打灭丑声，佯做个呓挣。", "妖精也甚精？男儿也，看我这旧恩情，你且放我去，与人人亲折证。"]'),
('yuanqu-2190','迷青琐倩女离魂・挂金索','郑光祖','元','元曲','yuanqu','','[]','蓦入门庭，则教我立不稳，行不正。',63,'元曲/yuanqu.json','["蓦入门庭，则教我立不稳，行不正。", "望见首饰妆奁，志不宁，心不定。", "见几个年少丫鬟，口不住，手不停；拥着个半死佳人，唤不醒，呼不应。"]'),
('yuanqu-2191','迷青琐倩女离魂・尾声','郑光祖','元','元曲','yuanqu','','[]','猛地回身宋合并，床儿畔一盏孤灯。',42,'元曲/yuanqu.json','["猛地回身宋合并，床儿畔一盏孤灯。", "兀良，早则照不见伴人清瘦影。", "(魂旦附正旦体科，下)。"]'),
('yuanqu-2192','迷青琐倩女离魂・侧砖儿','郑光祖','元','元曲','yuanqu','','[]','哎！你个辜恩负德王学士，今日也有称心时。',39,'元曲/yuanqu.json','["哎！你个辜恩负德王学士，今日也有称心时。", "不甫能盼得音书至，倒揣与我个闷弓儿！。"]'),
('yuanqu-2193','迷青琐倩女离魂・竹枝歌','郑光祖','元','元曲','yuanqu','','[]','打听为官折了桂枝，别取了新婚甚意思？着妹妹日下恨难支，把哥哥闲传示。',53,'元曲/yuanqu.json','["打听为官折了桂枝，别取了新婚甚意思？着妹妹日下恨难支，把哥哥闲传示。", "则问这小妮子，被我都扌蚩的扯做纸条儿。"]'),
('yuanqu-2194','迷青琐倩女离魂・水仙子','郑光祖','元','元曲','yuanqu','','[]','想当日暂停征棹饮离尊，生恐怕千里关山劳梦频。',77,'元曲/yuanqu.json','["想当日暂停征棹饮离尊，生恐怕千里关山劳梦频。", "没揣的灵犀一点潜相引，便一似生个身外身，一般般两个佳人。", "那一个跟他取应，这一个淹煎病损，母亲，则这是倩女离魂。"]'),
('yuanqu-2195','苏子瞻风雪贬黄州・仙吕/点绛唇','费唐臣','元','元曲','yuanqu','','[]','万顷潇湘，九天星象，长江浪，吸入诗肠，都变做豪气三千丈。',28,'元曲/yuanqu.json','["万顷潇湘，九天星象，长江浪，吸入诗肠，都变做豪气三千丈。"]'),
('yuanqu-2196','苏子瞻风雪贬黄州・混江龙','费唐臣','元','元曲','yuanqu','','[]','想着那丝纶阁上，常则是紫薇花对紫薇郎。',94,'元曲/yuanqu.json','["想着那丝纶阁上，常则是紫薇花对紫薇郎。", "步九重春色，拂两袖天香。", "万里云烟挥翰墨，一天星斗焕文章。", "翰林风月，京洛山川，洞庭烟雨，金谷莺花，怎能彀一轮皂盖飞头上。", "诗吟的神嚎鬼哭，文惊的地老天荒。"]'),
('yuanqu-2197','苏子瞻风雪贬黄州・油葫芦','费唐臣','元','元曲','yuanqu','','[]','想月满西楼夜未央，蒙君恩宿建章。',76,'元曲/yuanqu.json','["想月满西楼夜未央，蒙君恩宿建章。", "不比长安三月荔枝香，翠鬟拥出芙蓉帐。", "又不是醉鞭误入平康巷，笙歌几处闻，净鞭三下响。", "没揣地半张鸾驾从天降，举首仿佛见君正。"]'),
('yuanqu-2198','苏子瞻风雪贬黄州・那吒令','费唐臣','元','元曲','yuanqu','','[]','我立一身纪纲，守箪瓢陋巷。',53,'元曲/yuanqu.json','["我立一身纪纲，守箪瓢陋巷。", "显一身气象，步金马玉堂。", "上一封谏章，入天罗地网。", "锦绣肠，江湖量，都分付水国江乡。"]'),
('yuanqu-2199','苏子瞻风雪贬黄州・鹊踏枝','费唐臣','元','元曲','yuanqu','','[]','万言策上君王，一骑马度衡阳。',53,'元曲/yuanqu.json','["万言策上君王，一骑马度衡阳。", "索离了三岛蓬莱，直走遍九曲沧浪。", "学不的李太白逍遥在醉乡，参破了韩昌黎夕贬潮阳。"]'),
('yuanqu-2200','苏子瞻风雪贬黄州・寄生草','费唐臣','元','元曲','yuanqu','','[]','臣则待居蛮貊，再谁想立庙堂。',67,'元曲/yuanqu.json','["臣则待居蛮貊，再谁想立庙堂。", "今日有曾参难免投梭诳，今日有周公难免流言讲，有仲尼难免狐裘谤。", "本是个长门献赋汉相如，怎做的东篱赏菊陶元亮。"]'),
('yuanqu-2201','苏子瞻风雪贬黄州・幺篇','费唐臣','元','元曲','yuanqu','','[]','臣折么流儋耳，臣折么贬夜郎。',64,'元曲/yuanqu.json','["臣折么流儋耳，臣折么贬夜郎。", "一个因书贾谊长沙放，一个因诗杜甫江边葬，一个因文李白波心丧。", "臣觑屈原千载汨罗江，便是禹门三月桃花浪。"]'),
('yuanqu-2202','苏子瞻风雪贬黄州・金盏儿','费唐臣','元','元曲','yuanqu','','[]','不荒唐，不颠狂，折末云阳枭首高竿上，也要将碧天风月两平章。',90,'元曲/yuanqu.json','["不荒唐，不颠狂，折末云阳枭首高竿上，也要将碧天风月两平章。", "拚着梦魂游故国，想像赴高堂。", "则今日伤心游海岛，携手上河梁。", "(末云)罢、罢，则今日拜辞了圣驾，别了丞相，只索长行也。", "(唱)。"]'),
('yuanqu-2203','苏子瞻风雪贬黄州・赚煞','费唐臣','元','元曲','yuanqu','','[]','则为不入虎狼群，躲离鲸鲵浪，直贬过淘淘大江，不信行人不断肠。',95,'元曲/yuanqu.json','["则为不入虎狼群，躲离鲸鲵浪，直贬过淘淘大江，不信行人不断肠。", "赤紧的接天隅烟水茫茫，助凄凉衰草斜阳，休想我筑起高台望故乡。", "这里有当途虎狼，那里有拍天风浪。", "我要过水云乡，则是跳出是非场。", "(下)。"]'),
('yuanqu-2204','苏子瞻风雪贬黄州・正宫/端正好','费唐臣','元','元曲','yuanqu','','[]','道德五千言，礼乐三十卷。',39,'元曲/yuanqu.json','["道德五千言，礼乐三十卷。", "本待经纶就舜日尧天，只因两角蜗蛮战，贬得我日近长安远。"]'),
('yuanqu-2205','苏子瞻风雪贬黄州・幺篇','费唐臣','元','元曲','yuanqu','','[]','瑶台昨夜蛟龙战，玉鳞甲飞满山川。',43,'元曲/yuanqu.json','["瑶台昨夜蛟龙战，玉鳞甲飞满山川。", "冯夷饮罢琼林宴，醉把鲛绡剪。", "(云)好大雪也呵。", "(唱)。"]'),
('yuanqu-2206','苏子瞻风雪贬黄州・滚绣球','费唐臣','元','元曲','yuanqu','','[]','泼墨云垂四野，铸银河插半天。',91,'元曲/yuanqu.json','["泼墨云垂四野，铸银河插半天。", "把人间番做了广寒宫殿，有一千顷玉界琼田。", "这其间骚客迁，朝士贬。", "五云乡杳然不见，止不过隔蓬莱弱水三千。", "不能彀风吹章表随龙去，可做了雪拥蓝关马不前，哽咽无言。"]'),
('yuanqu-2207','苏子瞻风雪贬黄州・倘秀才','费唐臣','元','元曲','yuanqu','','[]','早是水杳山长路远，那更雪冻风寒云卷。',131,'元曲/yuanqu.json','["早是水杳山长路远，那更雪冻风寒云卷。", "(云)你道我行的慢呵，可知可知(唱)我可甚为爱青山懒赠鞭！呵冻手，从双肩。", "我只索向前。", "(童云)老爹，人都说你好才学，却怎生遭贬，到不知老爹与上古贤人君子，那几个相似！(末云)这小的虽小倒也省事。", "你既问我，你听我与你说。", "(唱)。"]'),
('yuanqu-2208','苏子瞻风雪贬黄州・滚绣球','费唐臣','元','元曲','yuanqu','','[]','我怕不文章似韩退之史，笔如司马迁。',90,'元曲/yuanqu.json','["我怕不文章似韩退之史，笔如司马迁。", "英俊如仲宣子建，豪迈如居易宗元。", "风骚如杜少陵，疏狂如李谪仙。", "高洁如谢安李愿。", "德行如闵子颜渊。", "为不学乘桴浮海鸱夷子，生扭做踏雪寻梅孟浩然。", "困煞英贤。"]'),
('yuanqu-2209','苏子瞻风雪贬黄州・倘秀才','费唐臣','元','元曲','yuanqu','','[]','脱离了长安市廛，须捱到黄州地面，更狠似夕贬潮阳路八千。',44,'元曲/yuanqu.json','["脱离了长安市廛，须捱到黄州地面，更狠似夕贬潮阳路八千。", "往常师往圣，友前贤，到如今怎展！。"]'),
('yuanqu-2210','苏子瞻风雪贬黄州・滚绣球','费唐臣','元','元曲','yuanqu','','[]','我也曾写珠玑一万联，判莺花三百篇，扫千军笔端鏖战，但行处天子三宣。',91,'元曲/yuanqu.json','["我也曾写珠玑一万联，判莺花三百篇，扫千军笔端鏖战，但行处天子三宣。", "结平生诗酒缘，掌中天风月权。", "不是将帝王埋怨，为甚把苏轼似贾谊南迁。", "如今一牧童子随驴后，可甚两行朱衣到马前。", "四野萧然。"]'),
('yuanqu-2211','苏子瞻风雪贬黄州・呆骨朵','费唐臣','元','元曲','yuanqu','','[]','见黄童白叟把香醪劝，怕不透彻了酒兴诗颠。',166,'元曲/yuanqu.json','["见黄童白叟把香醪劝，怕不透彻了酒兴诗颠。", "(马云)老夫久闻大才，敢求佳作见教。", "(末云)大人饮酒则饮酒。", "再休言诗。", "(马云)诗酒乃吾生分内事。", "大人此行，与诗酒何干。", "(末唱)我须不是为酒忘家，见如今因诗受贬。", "酒债是寻常事，诗病是平生愿。", "我为甚远流身万里，因此上怕吟诗百篇。", "(马云)苏大人高才重望，正宜居朝佐主，以治太平。", "岂宜放逐！(末唱)。"]'),
('yuanqu-2212','苏子瞻风雪贬黄州・五煞','费唐臣','元','元曲','yuanqu','','[]','我情愿闲居村落攻经典，谁想闷向秦楼列管弦。',70,'元曲/yuanqu.json','["我情愿闲居村落攻经典，谁想闷向秦楼列管弦。", "枕碧水千寻，对青山一带，趁白云万顷，尽茅屋三间草舍蓬窗，苜蓿盘中，老瓦盆边，乐于贫贱，灯火对床眠。"]'),
('yuanqu-2213','苏子瞻风雪贬黄州・四煞','费唐臣','元','元曲','yuanqu','','[]','从教头上青天鉴，不愿腰间金印悬。',67,'元曲/yuanqu.json','["从教头上青天鉴，不愿腰间金印悬。", "受他冷冷清清，多多少少，避是是非非，万万千千。", "或向林皋声里，舴艋舟中，霍索溪边。", "一壶村酒，白眼望青天。"]'),
('yuanqu-2214','苏子瞻风雪贬黄州・三煞','费唐臣','元','元曲','yuanqu','','[]','紫袍金带无心恋，两笠烟蓑有意穿。',68,'元曲/yuanqu.json','["紫袍金带无心恋，两笠烟蓑有意穿。", "或向新妇矶头，鸥鹭乡中，儿女浦口，鹦鹉洲边。", "涨一竿春水，带一抹寒烟，掉一只渔舡。", "黑甜一枕睡，灯火对愁眠。"]'),
('yuanqu-2215','苏子瞻风雪贬黄州・二煞','费唐臣','元','元曲','yuanqu','','[]','佳音不托云间犬，老计惟凭阳羡田。',66,'元曲/yuanqu.json','["佳音不托云间犬，老计惟凭阳羡田。", "对橘绿橙黄，山高月小，听南枝惊鹊，衰柳鸣蝉。", "不愁远害，不陷危机，不纳高轩。", "那里人离乡贱甚日是归年！。"]'),
('yuanqu-2216','苏子瞻风雪贬黄州・煞尾','费唐臣','元','元曲','yuanqu','','[]','从教臣子一身贬，留得高名万古传。',45,'元曲/yuanqu.json','["从教臣子一身贬，留得高名万古传。", "但使歌低酒浅。", "卧雨眠烟，席地幕天，一任长安路儿远。", "(下)。"]'),
('yuanqu-2217','苏子瞻风雪贬黄州・越调/斗鹌鹑','费唐臣','元','元曲','yuanqu','','[]','湖海三年，家乡万里。',51,'元曲/yuanqu.json','["湖海三年，家乡万里。", "志气如神，形容似鬼。", "瘴气才收，蛮烟又起。", "空叹息，人未归，望不见落叶长安，西风渭水。"]'),
('yuanqu-2219','苏子瞻风雪贬黄州・小桃红','费唐臣','元','元曲','yuanqu','','[]','想西湖风月绕苏堤，尚觉王孙贵，银烛高烧照珠翠。',55,'元曲/yuanqu.json','["想西湖风月绕苏堤，尚觉王孙贵，银烛高烧照珠翠。", "如今百事成非，江山不管春憔悴。", "想金勒马嘶，玉楼人醉，依旧画桥西。"]'),
('yuanqu-2220','苏子瞻风雪贬黄州・鬼三台','费唐臣','元','元曲','yuanqu','','[]','怕不待闲争气，赤紧的难存济。',74,'元曲/yuanqu.json','["怕不待闲争气，赤紧的难存济。", "我则索折腰为米，更怕甚心急马行迟！你只是婆娘家见识。", "陶元亮见此不见彼，公孙弘救宽不救急。", "便做他志若元龙，赤紧的才过子美。"]'),
('yuanqu-2221','苏子瞻风雪贬黄州・紫花儿序','费唐臣','元','元曲','yuanqu','','[]','本待昂昂而已，特地远远而来，怎教快快而回！世无君子，你家有贤妻，休提。',66,'元曲/yuanqu.json','["本待昂昂而已，特地远远而来，怎教快快而回！世无君子，你家有贤妻，休提。", "拚著个拨尽寒炉一夜灰，但得些粝食粗衣，免得冬暖号寒，年稔啼饥。"]'),
('yuanqu-2222','苏子瞻风雪贬黄州・金蕉叶','费唐臣','元','元曲','yuanqu','','[]','恨唾手功名未遂，被衮衮儿曹见欺。',65,'元曲/yuanqu.json','["恨唾手功名未遂，被衮衮儿曹见欺。", "似这等十谒朱门九闭，又不是一鹗西风万里。", "(祗候云)为你打了我一顿，你还缠甚么？快走快走。", "(末唱)。"]'),
('yuanqu-2223','苏子瞻风雪贬黄州・圣药王','费唐臣','元','元曲','yuanqu','','[]','你教我快疾回，莫疑迟，可甚踏花归去马如飞。',44,'元曲/yuanqu.json','["你教我快疾回，莫疑迟，可甚踏花归去马如飞。", "没道理，不做美。", "我满舡空载月明归，犹自说兵机。"]'),
('yuanqu-2224','苏子瞻风雪贬黄州・鬼三台','费唐臣','元','元曲','yuanqu','','[]','他把贤门闭，英雄弃，莫那孟尝君是你？畅好人面逐高低。',72,'元曲/yuanqu.json','["他把贤门闭，英雄弃，莫那孟尝君是你？畅好人面逐高低。", "今日羞归去。", "呵，思量可知，可知那经天纬地孔仲尼，遇着轻贤重色柳盗跖。", "不争富贵骄人，小人喻利。"]'),
('yuanqu-2225','苏子瞻风雪贬黄州・紫花儿序','费唐臣','元','元曲','yuanqu','','[]','仰望死圣人贤思相，量起怪友狂朋，凄凉杀稚子山妻。',75,'元曲/yuanqu.json','["仰望死圣人贤思相，量起怪友狂朋，凄凉杀稚子山妻。", "胸中有物，肚里无食，堪悲，虎病山前被犬欺。", "我觑杨太守这厮，好管仲之器，觑我为粪土之墙，你却是疥癣之疾。"]'),
('yuanqu-2226','苏子瞻风雪贬黄州・绵搭絮','费唐臣','元','元曲','yuanqu','','[]','凭着我文如游夏，有一日君胜唐尧，宣的我依旧抽毫侍禁闱。',43,'元曲/yuanqu.json','["凭着我文如游夏，有一日君胜唐尧，宣的我依旧抽毫侍禁闱。", "似禹门平地一声雷，把蛰龙重振起。"]'),
('yuanqu-2227','苏子瞻风雪贬黄州・幺篇','费唐臣','元','元曲','yuanqu','','[]','对盘龙飞风椅，赋裁冰剪雾诗。',61,'元曲/yuanqu.json','["对盘龙飞风椅，赋裁冰剪雾诗。", "虎遁狼驰，鱼跃鸢飞。", "那一日强如今日。", "沛作云霓，宴罢瑶池，出入向宫闱，拜舞向丹墀，那其间强似你。"]'),
('yuanqu-2228','苏子瞻风雪贬黄州・尾声','费唐臣','元','元曲','yuanqu','','[]','无端四海苍生辈，都不识男儿未济。',41,'元曲/yuanqu.json','["无端四海苍生辈，都不识男儿未济。", "我止望周人之急紧如金，君子之交淡如水。", "(下)楔子。"]'),
('yuanqu-2229','苏子瞻风雪贬黄州・双调/新水令','费唐臣','元','元曲','yuanqu','','[]','一身流落楚江滨，少年心等闲灰尽。',40,'元曲/yuanqu.json','["一身流落楚江滨，少年心等闲灰尽。", "爱君非爱己，忧道不忧贫。", "富贵浮云，真堪笑又堪恨。"]'),
('yuanqu-2230','苏子瞻风雪贬黄州・驻马听','费唐臣','元','元曲','yuanqu','','[]','造化通神，镜里功名梦驻身。',56,'元曲/yuanqu.json','["造化通神，镜里功名梦驻身。", "无常忽近，一分流水二分尘。", "名流蜗角几时分，尘随马足何年尽。", "白发鬓边新，如其用我从先进。"]'),
('yuanqu-2231','苏子瞻风雪贬黄州・落梅花','费唐臣','元','元曲','yuanqu','','[]','陛下既从头问，微臣怎敢隐？这数年间一言难尽。',42,'元曲/yuanqu.json','["陛下既从头问，微臣怎敢隐？这数年间一言难尽。", "臣也会望烟波渺然思至尊，恨天涯有家难奔。"]'),
('yuanqu-2232','苏子瞻风雪贬黄州・水仙子','费唐臣','元','元曲','yuanqu','','[]','臣也曾远无亲戚近无邻，臣也曾釜有蛛丝甑有尘。',124,'元曲/yuanqu.json','["臣也曾远无亲戚近无邻，臣也曾釜有蛛丝甑有尘。", "臣则为归家懒睹妻儿问，到如今布袍上有泪痕。", "(驾云)闻知卿几遍被州官窘辱，卿是达者，如何苦苦干求于人。", "(末云)陛下臣非得已，实出于无奈也。", "(唱)臣放着急煎妻骂儿嗔，便做到达人知命，君子务本，也则索十谒朱门。"]'),
('yuanqu-2233','苏子瞻风雪贬黄州・甜水令','费唐臣','元','元曲','yuanqu','','[]','折末乐府离骚，长篇短韵，陛下待重与细论文，免陛下丁宁。',66,'元曲/yuanqu.json','["折末乐府离骚，长篇短韵，陛下待重与细论文，免陛下丁宁。", "非臣不逊，其实难效殷勤。", "(驾云)卿不肯对朕赋诗，卿在黄州，岂无吟咏！(末唱)。"]'),
('yuanqu-2234','苏子瞻风雪贬黄州・折桂令','费唐臣','元','元曲','yuanqu','','[]','怕不待闲吟些白雪阳春，本是个咏月嘲风，翻做了罔上欺君。',173,'元曲/yuanqu.json','["怕不待闲吟些白雪阳春，本是个咏月嘲风，翻做了罔上欺君。", "(驾云)朕当初一时之误，卿对此莺花景物，正好陶情写兴也。", "(末唱)陛下教吟彻莺花，这番敢走遍乾坤。", "(驾云)想当日卿夜对便殿，诏赐金莲，宫嫔簇拜，卿也曾赋〔满庭芳词〕。", "今日对朕再做一篇，有何不可。", "(末唱)见如今御史台威风凛凛，怎敢向翰林院文质彬彬，则一句吓杀微臣。", "则为这采女嫔妃，送了俺骚客诗人。"]'),
('yuanqu-2235','苏子瞻风雪贬黄州・川拨棹','费唐臣','元','元曲','yuanqu','','[]','这世里欠田文，都是些吃敲的石季伦。',45,'元曲/yuanqu.json','["这世里欠田文，都是些吃敲的石季伦。", "屋也似金银，山也似珠珍。", "有一千个为富不仁，傲贫人谄富人。"]'),
('yuanqu-2236','苏子瞻风雪贬黄州・七弟兄','费唐臣','元','元曲','yuanqu','','[]','清浊不分，仁义不存。',47,'元曲/yuanqu.json','["清浊不分，仁义不存。", "只理会得自推尊，饥寒壮士无人问。", "似昌黎重作《送穷文》，鲁褒再作《钱神论》。"]'),
('yuanqu-2237','苏子瞻风雪贬黄州・梅花酒','费唐臣','元','元曲','yuanqu','','[]','这厮每世不闻，倚主欺宾，仗富欺贫，倚势欺人。',100,'元曲/yuanqu.json','["这厮每世不闻，倚主欺宾，仗富欺贫，倚势欺人。", "富而骄贫而谄，贫无义富无恩。", "富无恩，岂是人？岂是人？类飞禽。", "类飞禽，颇曾论。", "颇曾论，处人伦。", "处人伦，傲饥贫。", "傲饥贫，莫生嗔。", "莫生嗔，闭贤门。", "闭贤门，使牛人。"]'),
('yuanqu-2238','苏子瞻风雪贬黄州・收江南','费唐臣','元','元曲','yuanqu','','[]','使牛人怎做孟尝君？似仲尼不遇叹麒麟。',41,'元曲/yuanqu.json','["使牛人怎做孟尝君？似仲尼不遇叹麒麟。", "对清风明月两闲人，折末受窘，也强如骑马傍人门。"]'),
('yuanqu-2239','苏子瞻风雪贬黄州・雁儿落','费唐臣','元','元曲','yuanqu','','[]','臣宁可闲居原宪贫，不受梦笔江淹闷。',35,'元曲/yuanqu.json','["臣宁可闲居原宪贫，不受梦笔江淹闷。", "乐陶陶三杯元亮酒，黑娄娄一枕陈抟困。"]'),
('yuanqu-2240','苏子瞻风雪贬黄州・得胜令','费唐臣','元','元曲','yuanqu','','[]','则愿做白发老参军，怎消得天子重儒臣。',62,'元曲/yuanqu.json','["则愿做白发老参军，怎消得天子重儒臣。", "那里显骚客骚人俊，到不如农夫妇蠢。", "绕流水孤村，听罢渔樵论，闭草户柴门，做一个清闲自在人。"]'),
('yuanqu-2241','中吕・粉蝶儿题情','季子安','元','元曲','yuanqu','','[]','这些时意懒心慵，闷恹恹似痴如梦。',53,'元曲/yuanqu.json','["这些时意懒心慵，闷恹恹似痴如梦。", "想当初倚翠偎红，我风流，他俊雅，恩深情重。", "他生的剔透玲珑，语融和言谈出众。"]'),
('yuanqu-2242','醉春风・他生的粉脸似秋莲，春纤如玉葱。鞋弓袜小步轻盈，能歌善咏，','季子安','元','元曲','yuanqu','','[]','雁柱轻移，冰弦款拨，便是那铁石人也情动。',20,'元曲/yuanqu.json','["雁柱轻移，冰弦款拨，便是那铁石人也情动。"]'),
('yuanqu-2243','红绣鞋・指望待要巫山畔乘鸾跨凤，谁承望阳台上云雨无踪，则我这口中','季子安','元','元曲','yuanqu','','[]','言都当做耳边风。',35,'元曲/yuanqu.json','["言都当做耳边风。", "冷落了蜂媒蝶使，稀疏了燕侣莺朋，多应是搅闲人将话儿哄。"]'),
('yuanqu-2244','剔银灯・俏冤家风流万种，他也待学七擒七纵。把我似勤儿般推磨相调弄，','季子安','元','元曲','yuanqu','','[]','我这里假妆痴件件依从。',33,'元曲/yuanqu.json','["我这里假妆痴件件依从。", "又则怕伤了和气、皱了美容，假和真你心里自懂。"]'),
('yuanqu-2245','蔓菁菜・你常好是不知轻重，动不动皱了眉峰，冰霜般面容。若是个村纣','季子安','元','元曲','yuanqu','','[]','的和你两个乍相逢，他把你那半世里清名送。',20,'元曲/yuanqu.json','["的和你两个乍相逢，他把你那半世里清名送。"]'),
('yuanqu-2246','柳青娘・这些时稀疏了诗宾和这酒朋，闷来时与谁同？一任教花红和这柳','季子安','元','元曲','yuanqu','','[]','浓，有何心恋芳丛？，则这诗书礼乐不待攻，端溪砚尘埋墨朦，紫霜毫乾燥了尖峰。',57,'元曲/yuanqu.json','["浓，有何心恋芳丛？，则这诗书礼乐不待攻，端溪砚尘埋墨朦，紫霜毫乾燥了尖峰。", "赤紧的缺了鸾笺无了香翰，无香翰怎题红？。"]'),
('yuanqu-2247','关张双赴西蜀梦・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','织履编席，能勾做大蜀皇帝，非容易。',30,'元曲/yuanqu.json','["织履编席，能勾做大蜀皇帝，非容易。", "官里旦暮朝夕，闷似三江水。"]'),
('yuanqu-2248','关张双赴西蜀梦・混江龙','关汉卿','元','元曲','yuanqu','','[]','唤了声关、张二弟，无言低首泪双垂；一会家眼前活现，一会家口内掂提。',75,'元曲/yuanqu.json','["唤了声关、张二弟，无言低首泪双垂；一会家眼前活现，一会家口内掂提。", "急煎煎御手频捶飞凤椅，扑籁籁痛泪常淹衮龙衣。", "每日家独上龙楼上，望荆州感叹，阆州伤悲。"]'),
('yuanqu-2249','关张双赴西蜀梦・油葫芦','关汉卿','元','元曲','yuanqu','','[]','每日家作念煞关云长、张翼德，委得俺宣限急。',85,'元曲/yuanqu.json','["每日家作念煞关云长、张翼德，委得俺宣限急。", "西川途路受驱驰，每日知他过几重深山谷，不曾行十里平田地。", "恨征马宛四只蹄，不这般插翅般疾；踊虎躯纵彻黄金辔，果然道\"心急马行迟\"。"]'),
('yuanqu-2250','关张双赴西蜀梦・醉扶归','关汉卿','元','元曲','yuanqu','','[]','若到荆州内，半米儿不宜迟，发送的关云长向北归。',54,'元曲/yuanqu.json','["若到荆州内，半米儿不宜迟，发送的关云长向北归。", "然后向阆州路上转驰驿，把关、张分付在君王手里，教他龙虎风云会。"]'),
('yuanqu-2251','关张双赴西蜀梦・金盏儿','关汉卿','元','元曲','yuanqu','','[]','关将军但相持，无一个敢欺敌。',69,'元曲/yuanqu.json','["关将军但相持，无一个敢欺敌。", "素衣匹马单刀会，觑敌军如儿戏，不若土和泥。", "杀曹仁十万军，刺颜良万丈威。", "今日被坏人将你算，畅则为你大胆上落便宜。"]'),
('yuanqu-2252','关张双赴西蜀梦・醉中天','关汉卿','元','元曲','yuanqu','','[]','义赦了严颜罪，鞭打的督邮死，当阳桥喝回个曹孟德。',52,'元曲/yuanqu.json','["义赦了严颜罪，鞭打的督邮死，当阳桥喝回个曹孟德。", "倒大个张车骑。", "今日被人死羊儿般剁了首级，全不见石亭驿！。"]'),
('yuanqu-2253','关张双赴西蜀梦・金盏儿','关汉卿','元','元曲','yuanqu','','[]','鞍马上不曾离，谁敢松动满身衣？恰离朝两个月零十日，劳而无役枉驱驰！一个鞭挑魂魄去，一个人和的哭声回。',67,'元曲/yuanqu.json','["鞍马上不曾离，谁敢松动满身衣？恰离朝两个月零十日，劳而无役枉驱驰！一个鞭挑魂魄去，一个人和的哭声回。", "宣的个孝堂里关美髯，纸幡上汉张飞。"]'),
('yuanqu-2254','关张双赴西蜀梦・赚煞','关汉卿','元','元曲','yuanqu','','[]','杀的那东吴家死尸骸堰住江心水，下溜头淋流着血汁。',91,'元曲/yuanqu.json','["杀的那东吴家死尸骸堰住江心水，下溜头淋流着血汁。", "我教的茸茸蓑衣浑染的赤，变做了通红狮子毛衣。", "杀的他敢血淋漓，交吴越托推，一霎儿番为做太湖鬼。", "青鸦鸦岸儿，黄壤壤田地，马蹄儿踏做捣椒泥。"]'),
('yuanqu-2255','关张双赴西蜀梦・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','早晨间占《易》理，夜后观乾象。',59,'元曲/yuanqu.json','["早晨间占《易》理，夜后观乾象。", "据贼星增焰彩，将星短光芒。", "朝野内度量。", "正俺南边上，白虹贯日光。", "低首参详，怎有这场景象？。"]'),
('yuanqu-2256','关张双赴西蜀梦・梁州','关汉卿','元','元曲','yuanqu','','[]','单注着东吴国一员骁将，砍折俺西蜀家两条金梁。',138,'元曲/yuanqu.json','["单注着东吴国一员骁将，砍折俺西蜀家两条金梁。", "这一场苦痛谁承望？再靠谁挟人捉将？再靠谁展土开疆？做宰相几曾做卿相，做君王那个做君王？布衣间昆仲心肠。", "再不看官渡口剑刺颜良，古城下刀诛蔡阳，石亭驿手挎袁襄！殿下帝王，行思坐想，正南下望，知祸起自天降。", "宣到我朝下若问当，着甚话声扬？。"]'),
('yuanqu-2257','关张双赴西蜀梦・隔尾','关汉卿','元','元曲','yuanqu','','[]','这南阳耕臾村诸亮，辅佐着洪福齐天汉帝主，一自为臣不曾把君诳。',48,'元曲/yuanqu.json','["这南阳耕臾村诸亮，辅佐着洪福齐天汉帝主，一自为臣不曾把君诳。", "这场勾当，不由我索向君王行酝酿个谎。"]'),
('yuanqu-2258','关张双赴西蜀梦・牧羊关','关汉卿','元','元曲','yuanqu','','[]','张达那贼禽兽，有甚早难近傍？不走了糜竺、糜芳！咱西蜀家威风，俺敢将东吴家灭相。',76,'元曲/yuanqu.json','["张达那贼禽兽，有甚早难近傍？不走了糜竺、糜芳！咱西蜀家威风，俺敢将东吴家灭相。", "我直教金鼓震、倾人胆，土雨溅的日无光；马蹄儿踏碎金陵府，鞭梢儿蘸干扬子江。"]'),
('yuanqu-2259','关张双赴西蜀梦・贺新郎','关汉卿','元','元曲','yuanqu','','[]','官里行行坐坐则是关、张，常则是挑在舌尖，不离了心上。',95,'元曲/yuanqu.json','["官里行行坐坐则是关、张，常则是挑在舌尖，不离了心上。", "每日家作念的如心痒，没日不心劳意攘，常则是心绪悲伤。", "白昼间频作念，到晚后越思量，方信道\"梦是心头想\"；但合眼早逢着翼德，才做梦可早见云长。"]'),
('yuanqu-2260','关张双赴西蜀梦・牧羊关','关汉卿','元','元曲','yuanqu','','[]','板筑的商傅说，钓鱼儿姜吕望，这两个梦善感动历代君王。',65,'元曲/yuanqu.json','["板筑的商傅说，钓鱼儿姜吕望，这两个梦善感动历代君王。", "这梦先应先知，臣则是误打误撞。", "蝴蝶迷庄子，宋玉赴高唐，世事云千变，浮生梦一场。"]'),
('yuanqu-2261','关张双赴西蜀梦・收尾','关汉卿','元','元曲','yuanqu','','[]','不能勾侵天松柏长千丈，则落的盖世功名纸半张！关将军美形状，张将军猛势况，再何时得相访？英雄归九泉壤，则落的河边堤土坡上、钉下个缆桩。',83,'元曲/yuanqu.json','["不能勾侵天松柏长千丈，则落的盖世功名纸半张！关将军美形状，张将军猛势况，再何时得相访？英雄归九泉壤，则落的河边堤土坡上、钉下个缆桩。", "坐着条担杖，则落的村酒渔樵话儿讲。"]'),
('yuanqu-2262','关张双赴西蜀梦・中吕/粉蝶儿','关汉卿','元','元曲','yuanqu','','[]','运去时过，谁承望有这场丧身灾祸？忆当年铁马金戈，自桃园初结义，把尊兄辅佐。',55,'元曲/yuanqu.json','["运去时过，谁承望有这场丧身灾祸？忆当年铁马金戈，自桃园初结义，把尊兄辅佐。", "共敌军擂鼓鸣锣，谁不怕俺弟兄三个！。"]'),
('yuanqu-2263','关张双赴西蜀梦・醉春风','关汉卿','元','元曲','yuanqu','','[]','安喜县把督邮鞭，当阳桥将曹操喝，共吕温侯配战九十合，那其间也是我、我！壮志消磨，暮年折挫，今日向匹夫行伏落。',54,'元曲/yuanqu.json','["安喜县把督邮鞭，当阳桥将曹操喝，共吕温侯配战九十合，那其间也是我、我！壮志消磨，暮年折挫，今日向匹夫行伏落。"]'),
('yuanqu-2264','关张双赴西蜀梦・红绣鞋','关汉卿','元','元曲','yuanqu','','[]','九尺躯阴云里偌大，三缕髯把玉带垂过，正是俺荆州里的二哥哥。',50,'元曲/yuanqu.json','["九尺躯阴云里偌大，三缕髯把玉带垂过，正是俺荆州里的二哥哥。", "咱是阴鬼，怎敢陷他，唬的我向阴云中无处躲。"]'),
('yuanqu-2265','关张双赴西蜀梦・迎仙客','关汉卿','元','元曲','yuanqu','','[]','居在人间世，则合把路上经过。',49,'元曲/yuanqu.json','["居在人间世，则合把路上经过。", "向阴云中步行因甚么？在常爪关西把他围绕合，今日小校无多，一部从十余个。"]'),
('yuanqu-2266','关张双赴西蜀梦・石榴花','关汉卿','元','元曲','yuanqu','','[]','往常开怀常是笑呵呵，绛云也似丹脸若频婆；今日卧蚕眉瞅定面没罗，却是为何？雨泪如梭，割舍了向前先搀过，见咱呵恐怕收罗。',76,'元曲/yuanqu.json','["往常开怀常是笑呵呵，绛云也似丹脸若频婆；今日卧蚕眉瞅定面没罗，却是为何？雨泪如梭，割舍了向前先搀过，见咱呵恐怕收罗。", "行行里恐惧明闻破，省可里倒把虎躯挪。"]'),
('yuanqu-2267','关张双赴西蜀梦・斗鹌鹑','关汉卿','元','元曲','yuanqu','','[]','哥哥道你是阴魂，兄弟是甚么？用舍行藏，尽言始末：则为帐下张达那厮厮嗔喝，兄弟更性似火；我本意待侑他，谁想他兴心坏我！。',59,'元曲/yuanqu.json','["哥哥道你是阴魂，兄弟是甚么？用舍行藏，尽言始末：则为帐下张达那厮厮嗔喝，兄弟更性似火；我本意待侑他，谁想他兴心坏我！。"]'),
('yuanqu-2268','关张双赴西蜀梦・上小楼','关汉卿','元','元曲','yuanqu','','[]','则为咱当年勇过，将人折挫，石亭驿上袁襄怎生结未？恼犯我，拿住他，天灵摔破，亏图了他怎生饶过！。',47,'元曲/yuanqu.json','["则为咱当年勇过，将人折挫，石亭驿上袁襄怎生结未？恼犯我，拿住他，天灵摔破，亏图了他怎生饶过！。"]'),
('yuanqu-2269','关张双赴西蜀梦・幺篇','关汉卿','元','元曲','yuanqu','','[]','哥哥你自暗约，这事非小可。',56,'元曲/yuanqu.json','["哥哥你自暗约，这事非小可。", "投至的曹操、孙权，鼎足三分，社稷山河。", "筋厮锁，俺三个，同行同坐，怎先亡了咱弟兄两个？。"]'),
('yuanqu-2270','关张双赴西蜀梦・哨遍','关汉卿','元','元曲','yuanqu','','[]','提起来把荆州摔破，争奈小兄弟也向壕中卧！云雾里自评薄，刘封那厮于礼如何？把那厮碎剐割！糜芳、糜竺、帐下张达，显见的东吴躲。',114,'元曲/yuanqu.json','["提起来把荆州摔破，争奈小兄弟也向壕中卧！云雾里自评薄，刘封那厮于礼如何？把那厮碎剐割！糜芳、糜竺、帐下张达，显见的东吴躲。", "先惊觉与军师诸葛，后入宫庭，托梦与哥哥。", "军临汉上马嘶风，尸堰满江心血流波；休想逃亡，没处潜藏，怎生的躲？。"]'),
('yuanqu-2271','关张双赴西蜀梦・耍孩儿','关汉卿','元','元曲','yuanqu','','[]','西蜀家气势威风大，助鬼兵全无坎坷；糜芳、糜竺共张达，待奔波怎地奔波？直取了汉上才还国，不杀了贼臣不讲和！若是都拿了，好生的将护，省可里拖磨。',70,'元曲/yuanqu.json','["西蜀家气势威风大，助鬼兵全无坎坷；糜芳、糜竺共张达，待奔波怎地奔波？直取了汉上才还国，不杀了贼臣不讲和！若是都拿了，好生的将护，省可里拖磨。"]'),
('yuanqu-2272','关张双赴西蜀梦・三煞','关汉卿','元','元曲','yuanqu','','[]','君王索怀痛忧，报了仇也快活。',65,'元曲/yuanqu.json','["君王索怀痛忧，报了仇也快活。", "除了刘封，槛车里囚着三个。", "并无喜况敲金镫，有甚心情和凯歌？若是将贼臣破，君王将咱祭奠，也不用道场锣钹。"]'),
('yuanqu-2273','关张双赴西蜀梦・收尾','关汉卿','元','元曲','yuanqu','','[]','也不用香共灯、酒共果，但得那腔子里的热血往空泼，超度了哥哥发奠我。',33,'元曲/yuanqu.json','["也不用香共灯、酒共果，但得那腔子里的热血往空泼，超度了哥哥发奠我。"]'),
('yuanqu-2274','关张双赴西蜀梦・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','任劬劳，空生爱，死魂儿有国难投！横亡在三个贼臣手，无一个亲人救。',32,'元曲/yuanqu.json','["任劬劳，空生爱，死魂儿有国难投！横亡在三个贼臣手，无一个亲人救。"]'),
('yuanqu-2275','关张双赴西蜀梦・滚绣球','关汉卿','元','元曲','yuanqu','','[]','俺哥哥丹凤之目，兄弟虎豹头，中他人机彀，死的来不如个虾蟹泥鳅！我也曾鞭督邮，俺哥哥诛文丑，暗灭了车胄，虎牢关酣战温侯。',85,'元曲/yuanqu.json','["俺哥哥丹凤之目，兄弟虎豹头，中他人机彀，死的来不如个虾蟹泥鳅！我也曾鞭督邮，俺哥哥诛文丑，暗灭了车胄，虎牢关酣战温侯。", "咱人\"三寸气在千般用，一日无常万事休\"，壮志难酬！。"]'),
('yuanqu-2276','关张双赴西蜀梦・倘秀才','关汉卿','元','元曲','yuanqu','','[]','往常真户尉见咱当胸叉手，今日见纸判官趋前退后，元来这做鬼的比阳人不自由！立在丹墀内，不由我泪交流，不见一班儿故友。',57,'元曲/yuanqu.json','["往常真户尉见咱当胸叉手，今日见纸判官趋前退后，元来这做鬼的比阳人不自由！立在丹墀内，不由我泪交流，不见一班儿故友。"]'),
('yuanqu-2277','关张双赴西蜀梦・滚绣球','关汉卿','元','元曲','yuanqu','','[]','那其间正暮秋，九月九，正是帝王的天寿。',81,'元曲/yuanqu.json','["那其间正暮秋，九月九，正是帝王的天寿。", "列丹墀宰相王侯，攘的我奉玉瓯进御酒，一齐山寿，官里回言道臣宰千秋。", "往常摆满宫彩女在阶基下，今日驾一片愁云在殿角头，痛泪交流。"]'),
('yuanqu-2278','关张双赴西蜀梦・倘秀才','关汉卿','元','元曲','yuanqu','','[]','官里身躯在龙楼凤楼，魂魄赴荆州、阆州，争知两座砖城换做土丘！天曹不受，地府难收，无一个去就！。',47,'元曲/yuanqu.json','["官里身躯在龙楼凤楼，魂魄赴荆州、阆州，争知两座砖城换做土丘！天曹不受，地府难收，无一个去就！。"]'),
('yuanqu-2279','关张双赴西蜀梦・滚绣球','关汉卿','元','元曲','yuanqu','','[]','官里恨不休，怨不休，更怕俺不知你那勤厚，为甚俺死魂儿全不相瞅？叙故旧，厮问候，想那说来的前咒书，桃园中宰白马乌牛。',79,'元曲/yuanqu.json','["官里恨不休，怨不休，更怕俺不知你那勤厚，为甚俺死魂儿全不相瞅？叙故旧，厮问候，想那说来的前咒书，桃园中宰白马乌牛。", "结交兄长存终始，俺伏侍君王不到头，心绪悠悠。"]'),
('yuanqu-2280','关张双赴西蜀梦・三煞','关汉卿','元','元曲','yuanqu','','[]','来日教诸葛将二愚男将引，丁宁奏，两行泪才那不断头。',88,'元曲/yuanqu.json','["来日教诸葛将二愚男将引，丁宁奏，两行泪才那不断头。", "官里紧紧的相留，怕不待慢慢的等候，怎禁那滴滴铜壶，点点更筹。", "久停久住，频去频来，添闷添愁！来时节玉蟾出东海，去时节残月下西楼。"]'),
('yuanqu-2281','关张双赴西蜀梦・煞尾','关汉卿','元','元曲','yuanqu','','[]','饱谙世事慵开口，会尽人间只点头。',89,'元曲/yuanqu.json','["饱谙世事慵开口，会尽人间只点头。", "火速的驱军校戈矛，驻马向长江雪浪流。", "活拿住糜芳共糜竺，阆州里张达槛车内囚。", "杵尖上挑定四颗头，腔子内血向成都闹市里流，强如与俺一千小盏黄封头祭酒！。"]'),
('yuanqu-2282','正宫・塞鸿秋','郑光祖','元','元曲','yuanqu','','[]','门前五柳江侵路，庄儿紧靠白苹渡。',165,'元曲/yuanqu.json','["门前五柳江侵路，庄儿紧靠白苹渡。", "除彭泽县令无心做，渊明老子达时务。", "频将浊酒沽，识破兴亡数，醉时节笑捻着黄花去。", "雨余梨雪开香玉，风和柳线摇新绿。", "日融桃锦堆红树，烟迷苔色铺青褥。", "王维旧画图，杜甫新诗句。", "怎相逢不饮空归去。", "金谷园那得三生富，铁门限枉作千年妒。", "汨罗江空把三闾污，北邙山谁是千钟禄？想应陶令杯，不到刘伶墓。", "怎相逢不饮空归去。"]'),
('yuanqu-2283','南吕・梧桐树南题情','郑光祖','元','元曲','yuanqu','','[]','相思借酒消，酒醒相思到，月夕花朝，容易伤怀抱。',54,'元曲/yuanqu.json','["相思借酒消，酒醒相思到，月夕花朝，容易伤怀抱。", "恹恹病转深，未否他知道。", "要得重生，除是他医疗。", "他行自有灵丹药。"]'),
('yuanqu-2284','骂玉郎北・无端掘下相思窖，那里是蜂蝶阵、燕莺巢。痴心枉作千年调。','郑光祖','元','元曲','yuanqu','','[]','不札实似风竹摇，无投奔似风絮飘，没出活似风花落。',24,'元曲/yuanqu.json','["不札实似风竹摇，无投奔似风絮飘，没出活似风花落。"]'),
('yuanqu-2285','东瓯令南・情山远，意波遥，咫尺妆楼天样高。月圆苦被阴云罩，偏不把','郑光祖','元','元曲','yuanqu','','[]','离愁照。',19,'元曲/yuanqu.json','["离愁照。", "玉人何处教吹箫，辜负了这良宵。"]'),
('yuanqu-2286','感皇恩北・呀，那些个投以木桃，报以琼瑶？我便似日影内捕金乌、月轮','郑光祖','元','元曲','yuanqu','','[]','中擒玉兔、云端里觅黄鹤。',37,'元曲/yuanqu.json','["中擒玉兔、云端里觅黄鹤。", "心肠枉费，伎俩徒劳。", "也是我恩情尽、时运乖、分缘薄。"]'),
('yuanqu-2287','浣溪沙南・我自招，随人笑，自古今好物难牢。我做了谒浆崔护违前约，','郑光祖','元','元曲','yuanqu','','[]','采药刘郎没下梢，心懊恼。',30,'元曲/yuanqu.json','["采药刘郎没下梢，心懊恼。", "再休想画堂中、绮筵前，夜将红烛高烧。"]'),
('yuanqu-2288','采茶歌北・疼热话向谁学？机密事把谁托？那里是浔阳江上不能潮？有一','郑光祖','元','元曲','yuanqu','','[]','日相逢酬旧好，我把这相思两字细推敲。',18,'元曲/yuanqu.json','["日相逢酬旧好，我把这相思两字细推敲。"]'),
('yuanqu-2290','双调・驻马听近秋闺','郑光祖','元','元曲','yuanqu','','[]','财叶将残，雨霁风高摧木杪；江乡潇洒，数株衰柳罩平桥。',54,'元曲/yuanqu.json','["财叶将残，雨霁风高摧木杪；江乡潇洒，数株衰柳罩平桥。", "露寒波冷翠荷凋，雾浓霜重丹枫老。", "暮云收，晴虹散，落霞飘。"]'),
('yuanqu-2291','幺・雨过池塘肥水面，云归岩谷瘦山腰。横空几行塞鸿高，茂林千点昏鸦','郑光祖','元','元曲','yuanqu','','[]','日衔山，船舣岸，鸟寻巢。',12,'元曲/yuanqu.json','["日衔山，船舣岸，鸟寻巢。"]'),
('yuanqu-2292','驻马听・闷入孤帏，静掩重门情似烧；文窗寂静，画屏冷落暗魂消。倦闻','郑光祖','元','元曲','yuanqu','','[]','近砌竹相敲，忍听邻院砧声捣。',26,'元曲/yuanqu.json','["近砌竹相敲，忍听邻院砧声捣。", "景无聊，闲阶落叶从风扫。"]'),
('yuanqu-2293','尾・一点来不够身躯小，响喉咙针眼里应难到。煎聒的离人，斗来合噪。','郑光祖','元','元曲','yuanqu','','[]','草虫之中无你般薄劣把人焦。',30,'元曲/yuanqu.json','["草虫之中无你般薄劣把人焦。", "急睡着，急惊觉，紧截定阳台路儿叫。"]'),
('yuanqu-2294','朱砂担滴水浮沤记・仙吕/端正好','无名氏','元','元曲','yuanqu','','[]','躲非灾，离乡故，相别罢便践程途。',67,'元曲/yuanqu.json','["躲非灾，离乡故，相别罢便践程途。", "(旦儿云)王文用，今日分别，好生凄凉也。", "(正末唱)方信道人生唯有别离苦，眼看着向那海角天涯去。", "(下)。"]'),
('yuanqu-2295','朱砂担滴水浮沤记・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','带月披星，忍寒受冷，离乡井。',34,'元曲/yuanqu.json','["带月披星，忍寒受冷，离乡井。", "过于些芳草长亭，再不曾半霎儿得这脚头定。"]'),
('yuanqu-2296','朱砂担滴水浮沤记・混江龙','无名氏','元','元曲','yuanqu','','[]','你看那人间百姓，在红尘中部要干营生，两下里行船走马，各要夺利争名。',443,'元曲/yuanqu.json','["你看那人间百姓，在红尘中部要干营生，两下里行船走马，各要夺利争名。", "船尾分开横水绿，马蹄踏破乱山青。", "则他这摇鞭举棹可便也休相竞，多则为两匙儿羹粥干忙了那一世，落的这前程。", "(云)天色晓了也，我在这店肆中觅个宵宿咱。", "小二哥，开门，开门。", "(店小二云)有人唤门哩，我开开这门来。", "(见科，云)我道谁，原来是老客。", "隔的两个月不见，一发吃的好了。", "老客，如今未做甚么？(正末云)我来你这店里，觅一个宿，我与你二百文房钱。", "(店小二云)勾了，勾了。", "老客请进里面来。", "用些甚么茶饭？(正末云)茶饭都不用。", "你只与我点一盏灯来。", "(店小二云)理会的。", "灯在此。", "(正末云)小二哥，你把房钱收去，我明日五更前后，早起便行，我也不辞你了。", "(店小二云)哦，你明日不辞我，天明就去。", "既然如此，你歇息罢。", "我自家睡去。", "(下)(正末云)我关上这门。", "走的我身子困倦了，我歇息咱。", "(做睡、打梦科)(云)王文用也，甚睡儿到的我这眼里？我开开这门，我来这里，下了两遭，倒不曾细看。", "可怎生这里有一个小角门儿？我开开这门，元来是一所花园。", "是好花也。"]'),
('yuanqu-2297','朱砂担滴水浮沤记・醉中天','无名氏','元','元曲','yuanqu','','[]','我则见牡丹花堪人赏宜人敬，可人意动人情。',124,'元曲/yuanqu.json','["我则见牡丹花堪人赏宜人敬，可人意动人情。", "又则见青芍药白蔷薇红锦樱，又则见紫纹桃间着那黄花杏。", "(云)是好花也，我待折一朵儿咱。", "(唱)不由我心中自警，百般的把拿不定。", "(云)这所在也无人，我便折一朵儿怕做甚么？(做惊科)(唱)呀，可怎生扑簌簌枝叶凋零？。"]'),
('yuanqu-2298','朱砂担滴水浮沤记・青歌儿','无名氏','元','元曲','yuanqu','','[]','天也。',145,'元曲/yuanqu.json','["天也。", "好着我又不敢问他、问他名姓，早则是打了个浑身痴挣。", "(做杀正末，打推下)(正末做醒科，云)有杀人贼也，呸！(唱)我恰才哄的觉来忽的醒。", "(云)好个恶梦也。", "我开了这门。", "(唱)我才出门程，向花苑闲行。", "见风弄残灯，正月白三更。", "亲见个妖精，待把我欺凌。", "只一拳险送了这泼残生，天也，兀的不忧成我病。"]'),
('yuanqu-2299','朱砂担滴水浮沤记・醉扶归','无名氏','元','元曲','yuanqu','','[]','我则见那野水穿花径，村犬吠柴扃。',152,'元曲/yuanqu.json','["我则见那野水穿花径，村犬吠柴扃。", "合剌剌辘轳响，可正和着各琅琅的捣碓声，更那堪绿柳相遮映。", "(做见店小二科，云)这是一个小酒务儿，小二哥，有酒么？(店小二云)有酒、有酒。", "(正末云)小二哥，打二百文长钱的酒来。", "(店小二云)酒在此。", "你有量尽着你吃，只不要撒酒风。", "(正末唱)则你这醇糯酒浑如靛青。", "我且饮一盏消闲兴。"]'),
('yuanqu-2300','朱砂担滴水浮沤记・金盏儿','无名氏','元','元曲','yuanqu','','[]','忙浇奠谢神明，凭买卖做经营，大古来贫穷富贵皆前定。',215,'元曲/yuanqu.json','["忙浇奠谢神明，凭买卖做经营，大古来贫穷富贵皆前定。", "(邦老云)那壁角子里有人说话。", "我试听他说甚么。", "(正末做浇奠酒科，云)一点酒入地，愿万民安乐。", "两点酒入地，愿五谷丰登。", "三点酒入地，愿好人相逢，恶人远避。", "(邦老拍卓科，云)兀那村弟子孩儿，那恶人恼着你甚么来？(店小二云)老权，不要打破了我的卓子。", "(正末唱)我这里扭回脖颈，他那里闪双睛。", "(邦老云)这厮好无礼也。", "(正末唱)我见他忽的眉剔竖，秃的眼圆睁。", "唬的我腾的撒了抬盏，哄的丢了魂灵。"]'),
('yuanqu-2301','朱砂担滴水浮沤记・赚煞尾','无名氏','元','元曲','yuanqu','','[]','他觑我似炉畔弄冬凌，他觑我似碗里拿蒸饼。',105,'元曲/yuanqu.json','["他觑我似炉畔弄冬凌，他觑我似碗里拿蒸饼。", "若不是灌的来十分酩酊，怎按住他一场火气性。", "我如今在虎口逃生，急腾腾，再不消停，抵多少遥指空中雁做羹。", "比及那贼徒酒醒，我已自家胆正，遮莫他赶将来我与你先走了两三程。", "(下)。"]'),
('yuanqu-2302','朱砂担滴水浮沤记・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','那厮他入门来便紧瞅了咱这小本的装，则被我买下子些新槽的酒。',97,'元曲/yuanqu.json','["那厮他入门来便紧瞅了咱这小本的装，则被我买下子些新槽的酒。", "连珠儿灌到有五六碗，他承兴饮吃到有两三瓯，尽醉方休。", "那好饮的也是天生就，一会儿直灌的那厮瓠子头。", "他和衣儿稳睡安眠，怎知我悄声儿逃席便走。"]'),
('yuanqu-2303','朱砂担滴水浮沤记・梁州第七','无名氏','元','元曲','yuanqu','','[]','若不是我使见识一杯也那一跪，天那！可不将我这泼残生早做了千死千休！我从那早辰间直走到申时候。',167,'元曲/yuanqu.json','["若不是我使见识一杯也那一跪，天那！可不将我这泼残生早做了千死千休！我从那早辰间直走到申时候。", "过了些青山隐隐，绿水悠悠。", "荒祠古庙，沙岸汀洲。", "七林林低陇高丘，急旋旋浅涧深沟。", "刚抹过另巍巍这座层峦，还隔着碧遥遥几重远岫，又接上白茫茫一带平畴。", "巴的到绿杨渡口，早则是云迷雾锁黄昏后，我去那野店上觅一宿。", "这的便是东海鳌鱼脱钓钩，我可也再不回头。"]'),
('yuanqu-2304','朱砂担滴水浮沤记・牧羊关','无名氏','元','元曲','yuanqu','','[]','我将这灯吹灭，身倒抽，唬的我浑身上冷汗交流。',73,'元曲/yuanqu.json','["我将这灯吹灭，身倒抽，唬的我浑身上冷汗交流。", "莫是取命的阎王，杀人的领袖？唬的我呆打颏空张着口，惊急力怕抬头。", "恰待要睁开两个眼，可早则软塌了一对手。"]'),
('yuanqu-2305','朱砂担滴水浮沤记・隔尾','无名氏','元','元曲','yuanqu','','[]','一领布衫我与你刚刚的扣，八答麻鞋款款的兜。',95,'元曲/yuanqu.json','["一领布衫我与你刚刚的扣，八答麻鞋款款的兜。", "我又不敢高声大咳嗽，我将这厮左瞅，右瞅。", "哎！天也！怎的他一阵儿昏迷稳放我走。", "(云)行李衣服都摸着了也，且喜那厮正睡着哩。", "此时不走，更待何时！(唱)。"]'),
('yuanqu-2306','朱砂担滴水浮沤记・牧羊关','无名氏','元','元曲','yuanqu','','[]','只道他猛翻身，睡觉秋，且喜得眼朦胧又打鼻勾鼻勾。',76,'元曲/yuanqu.json','["只道他猛翻身，睡觉秋，且喜得眼朦胧又打鼻勾鼻勾。", "他土鲁鲁嗓内涎潮，我也急煎煎心下刀抽。", "有如秋夜雨，一点一声愁。", "正待要展开脚忙移步，百忙里腿转筋甚腌证候。"]'),
('yuanqu-2307','朱砂担滴水浮沤记・黄钟尾','无名氏','元','元曲','yuanqu','','[]','罢、罢、罢，我这性命呵，似半轮残月三更后，一日无常万事休。',94,'元曲/yuanqu.json','["罢、罢、罢，我这性命呵，似半轮残月三更后，一日无常万事休。", "苦奔波，枉生受，有谁人，肯搭救，单只被几颗朱砂，送了我头。", "拚的向阎罗告究，着铁幡竿等候。", "遮莫你板门似手掌儿，也掩不得俺这叫屈的口。"]'),
('yuanqu-2308','朱砂担滴水浮沤记・滚绣球','无名氏','元','元曲','yuanqu','','[]','你道为甚么森森的透骨寒？却元来是茫茫的云雾繁，遮断著红尘无限，刚则见衰草斑斑，兀的不是地府间、黑水湾？早来到这奈河两岸，兀的不是剑树刀山？两只眼紧把冤魂来觑，一',96,'元曲/yuanqu.json','["你道为甚么森森的透骨寒？却元来是茫茫的云雾繁，遮断著红尘无限，刚则见衰草斑斑，兀的不是地府间、黑水湾？早来到这奈河两岸，兀的不是剑树刀山？两只眼紧把冤魂来觑，一只手轻将他鬼力扌班，何处也蹒跚。"]'),
('yuanqu-2309','朱砂担滴水浮沤记・倘秀才','无名氏','元','元曲','yuanqu','','[]','见地曹手捧着温良玉盏，我这里忙擎起花纹象简，(净云)上圣，许久不会了也。',68,'元曲/yuanqu.json','["见地曹手捧着温良玉盏，我这里忙擎起花纹象简，(净云)上圣，许久不会了也。", "(正末唱)我和你间别来早已数载间。", "绝音信，少平安，今日得见面颜。"]'),
('yuanqu-2310','朱砂担滴水浮沤记・煞尾','无名氏','元','元曲','yuanqu','','[]','则我这硬邦邦指爪将那厮头稍来挽，粗滚滚麻绳将那厮脖项来拴。',88,'元曲/yuanqu.json','["则我这硬邦邦指爪将那厮头稍来挽，粗滚滚麻绳将那厮脖项来拴。", "丢天灵剪子腕，着凌迟受磨难，那怕他泼顽皮绰号做铁幡竿。", "只消我这一对儿拦关，把那厮死狗也似拖将来我直着见了您眼。", "(下)。"]'),
('yuanqu-2311','朱砂担滴水浮沤记・幺篇','无名氏','元','元曲','yuanqu','','[]','我将这厮琅琅铁索把那厮肩膀绑，沉点点铁棍将那厮臂膊搪。',89,'元曲/yuanqu.json','["我将这厮琅琅铁索把那厮肩膀绑，沉点点铁棍将那厮臂膊搪。", "打碎天灵共眼眶，踢折蛮腰和脑浆。", "(做嘴脸科)(鬼力云)怎么做这个嘴脸？(净唱)把那厮直拿到酆都那边，着他慢慢的想。", "(同下)。"]'),
('yuanqu-2312','朱砂担滴水浮沤记・双调/新水令','无名氏','元','元曲','yuanqu','','[]','正黄昏庭院景凄凄，哎哟天那！走的我软兀剌一丝两气。',119,'元曲/yuanqu.json','["正黄昏庭院景凄凄，哎哟天那！走的我软兀剌一丝两气。", "淅零零的山路冷，昏惨惨的晚风吹。", "脚步儿刚移，一步步行到枉死地。", "(做行科，云)来到这个所在，是十字坡口儿上酒店，正是我当初遇着那贼处。", "他见着我甚些动静，便起这点狠心？所算的我好苦也。", "(唱)。"]'),
('yuanqu-2313','朱砂担滴水浮沤记・沉醉东风','无名氏','元','元曲','yuanqu','','[]','若不是我失时落势，怎生的便揽祸招危。',66,'元曲/yuanqu.json','["若不是我失时落势，怎生的便揽祸招危。", "我和他这搭儿才相见，平日里又不相识。", "刚道个一声儿恶人回避，早激的他恶哏哏闹是非，那里也见财起意。"]'),
('yuanqu-2314','朱砂担滴水浮沤记・乔牌儿','无名氏','元','元曲','yuanqu','','[]','我既是抽身儿悄脱离，又何苦直赶上这田地？我和他又没甚杀爷娘抢道路深仇隙，可怎便舍残生做到底？。',47,'元曲/yuanqu.json','["我既是抽身儿悄脱离，又何苦直赶上这田地？我和他又没甚杀爷娘抢道路深仇隙，可怎便舍残生做到底？。"]'),
('yuanqu-2315','朱砂担滴水浮沤记・甜水令','无名氏','元','元曲','yuanqu','','[]','我只合紧闭房门，吹残灯火，且图安睡，怎好去一颗颗数着这东西。',180,'元曲/yuanqu.json','["我只合紧闭房门，吹残灯火，且图安睡，怎好去一颗颗数着这东西。", "早被他识咱行藏，听咱声响，见咱踪迹，可不是自落的便宜。", "(做行科，云)这所在是东岳太尉庙。", "那贼汉好狠也，我把一担儿朱砂都送了你，只要留俺的性命，你怎么还要将我杀了？我记的临死时曾指滴水浮沤为证。", "我如今冤魂不散，少不的和你索命。", "太尉爷爷，你是个掌生死的活神道，须与我屈死的王文用做主咱。", "(做拜科)(唱)。"]'),
('yuanqu-2316','朱砂担滴水浮沤记・折桂令','无名氏','元','元曲','yuanqu','','[]','我忙合手顶礼神祗，现掌着死生文簿，何曾错善恶毫厘。',145,'元曲/yuanqu.json','["我忙合手顶礼神祗，现掌着死生文簿，何曾错善恶毫厘。", "(做再拜科，云)太尉爷爷，(唱)你怎不怜见我屈死的冤魂？放过了他行凶的泼贼，待强夺了俺无主的娇妻。", "我亲指着滴檐前浮沤为记，难道你坐殿上神圣无知？(做再拜科)(唱)只愿你检验轮回，速显灵威，将那厮直押送十八层地狱阿鼻，才见的你百千年天性忠直。"]'),
('yuanqu-2317','朱砂担滴水浮沤记・落梅风','无名氏','元','元曲','yuanqu','','[]','我只道你灵性归天上，却元来幽魂沉井底，总便是铁石人也见了心碎。',53,'元曲/yuanqu.json','["我只道你灵性归天上，却元来幽魂沉井底，总便是铁石人也见了心碎。", "我和他这冤仇结的来甚尽期，只除非各一家天地。"]'),
('yuanqu-2318','朱砂担滴水浮沤记・沽美酒','无名氏','元','元曲','yuanqu','','[]','并不曾见烈纸钱将咱祭，倒去熬粥汤送他吃，元来你个水性婆娘易转移。',51,'元曲/yuanqu.json','["并不曾见烈纸钱将咱祭，倒去熬粥汤送他吃，元来你个水性婆娘易转移。", "干着我生受了半世，眼睁睁看你做歹人妻。"]'),
('yuanqu-2319','朱砂担滴水浮沤记・太平令','无名氏','元','元曲','yuanqu','','[]','我痴心想望贞洁，你做事忒杀非为，铁幡竿满怀得济，王文用手稍儿着地。',57,'元曲/yuanqu.json','["我痴心想望贞洁，你做事忒杀非为，铁幡竿满怀得济，王文用手稍儿着地。", "你这个泼贼，就里，落可便下的，白占了俺家缘家计。"]'),
('yuanqu-2320','朱砂担滴水浮沤记・收尾','无名氏','元','元曲','yuanqu','','[]','死生难遏我心头气，冤仇有似檐间水。',45,'元曲/yuanqu.json','["死生难遏我心头气，冤仇有似檐间水。", "哎，你个图财致命的狠心贼，也少不得做个落堑拖坑的没头鬼。"]'),
('yuanqu-2321','越调・斗鹌鹑冬景','苏彦文','元','元曲','yuanqu','','[]','地冷天寒，阴风乱刮；岁久冬深，严霜遍撒；夜永更长，寒浸卧榻。',48,'元曲/yuanqu.json','["地冷天寒，阴风乱刮；岁久冬深，严霜遍撒；夜永更长，寒浸卧榻。", "梦不成，愁转加。", "杳杳冥冥，潇潇洒洒。"]'),
('yuanqu-2322','秃厮儿・这天晴不得一时半霎，寒凛冽走石飞沙。阴云黯淡闭日华，布四','苏彦文','元','元曲','yuanqu','','[]','野，满长空，天涯。',9,'元曲/yuanqu.json','["野，满长空，天涯。"]'),
('yuanqu-2323','圣药王・脚又滑，手又麻，乱纷纷瑞雪舞梨花。情绪杂，囊箧乏。若老天','苏彦文','元','元曲','yuanqu','','[]','全不可怜咱，冻钦钦怎行踏？。',14,'元曲/yuanqu.json','["全不可怜咱，冻钦钦怎行踏？。"]'),
('yuanqu-2324','紫花儿序・这雪袁安难卧，蒙正回窑，买臣还家，退之不爱，浩然休夸。','苏彦文','元','元曲','yuanqu','','[]','真佳，江上渔翁罢了钓槎。',37,'元曲/yuanqu.json','["真佳，江上渔翁罢了钓槎。", "便休题晚来堪画，休强呵映雪读书，且免了这扫雪烹茶。"]'),
('yuanqu-2325','尾声・最怕的是檐前头倒把冰锥挂，喜端午愁逢腊八。巧手匠雪狮儿一千','苏彦文','元','元曲','yuanqu','','[]','般成，我盼的是泥牛儿四九里打。',15,'元曲/yuanqu.json','["般成，我盼的是泥牛儿四九里打。"]'),
('yuanqu-2326','仙吕/点绛唇','杨景贤','元','元曲','yuanqu','','[]','宝殿生香，美人扶向，瑶阶上。',26,'元曲/yuanqu.json','["宝殿生香，美人扶向，瑶阶上。", "列七宝旌幢，端坐泥金亢。"]'),
('yuanqu-2327','混江龙','杨景贤','元','元曲','yuanqu','','[]','我怕不似嫦娥模样，将一座广寒宫移下五云乡。',111,'元曲/yuanqu.json','["我怕不似嫦娥模样，将一座广寒宫移下五云乡。", "两般比谕，一样凄凉。", "嫦娥夜夜孤眠居月窟，我朝朝独自守家邦。", "虽无那强文壮武，宰相朝郎，列两行脂粉，无四野刀枪。", "千年只照井泉生，平生不识男儿像。", "见一幅画来的也情动，见一个泥塑的也心伤。"]'),
('yuanqu-2328','油葫芦','杨景贤','元','元曲','yuanqu','','[]','说他几载其间离了大唐，来到俺地方，安排香案快疾忙。',85,'元曲/yuanqu.json','["说他几载其间离了大唐，来到俺地方，安排香案快疾忙。", "今日取经直过俺金阶上，抵多少醉鞭误入平康巷。", "我是一个聪明女，他是一个少年郎。", "谁着他不明白抢入我花罗网，准备着金殿锁鸳鸯。"]'),
('yuanqu-2329','天下乐','杨景贤','元','元曲','yuanqu','','[]','稳情取和气春风满画堂，宰下肥羊，安排的五味香，与俺那菜馒头的老兄腾了肚肠。',64,'元曲/yuanqu.json','["稳情取和气春风满画堂，宰下肥羊，安排的五味香，与俺那菜馒头的老兄腾了肚肠。", "陪妆奁留他做丈夫，舍身躯与他做正房，可知道男儿当自强。"]'),
('yuanqu-2330','那叱令','杨景贤','元','元曲','yuanqu','','[]','身才儿俊长，加持得鬼王；容貌儿善良，修持得梵正；胸襟儿纪纲，扶持得帝王。',56,'元曲/yuanqu.json','["身才儿俊长，加持得鬼王；容貌儿善良，修持得梵正；胸襟儿纪纲，扶持得帝王。", "头如蓝靛青，语似春雷壮，这和尚端的非常。"]'),
('yuanqu-2331','鹊踏枝','杨景贤','元','元曲','yuanqu','','[]','执方尊泻琼浆，露春葱捧瑶觞。',77,'元曲/yuanqu.json','["执方尊泻琼浆，露春葱捧瑶觞。", "(唐僧云)娘娘，及早修业，无常有限者。", "(女王唱)但能勾两意多情，尽教他一日无常。", "天魔女邪施伎俩，敢是你个释迦佛，也按不住心肠。"]'),
('yuanqu-2332','寄生草','杨景贤','元','元曲','yuanqu','','[]','直裰上胭脂污，袈裟上腻粉香。',76,'元曲/yuanqu.json','["直裰上胭脂污，袈裟上腻粉香。", "似魔腾伽把阿难摄在淫山上，若鬼子母将如来围定在灵山上，巫枝祗把张僧拿住在龟山上。", "不是我魔王苦苦害真僧，如今佳人个个要寻和尚。"]'),
('yuanqu-2333','幺','杨景贤','元','元曲','yuanqu','','[]','徒弟每诸般劝，师父独自慌。',193,'元曲/yuanqu.json','["徒弟每诸般劝，师父独自慌。", "俺女兵不用猴为将，女王岂用猪为相？如今女娘都爱唐三藏。", "你休痴迷修行今世有来生，我则待长江后浪催前浪。", "(女王做扯唐僧科)这正殿上不是说话的去处，俺两个后殿里去来。", "(唐僧云)孙悟空救我。", "(下)(行者云)我自也顾不得。", "(诸女做捉番孙、猪、沙发科)(下)(女王扯唐僧上，云)唐僧，我和你成其夫妇，你则今日就做国王，如何？(唐僧云)善哉！我要取经哩。", "(发科)(女王唱)。"]'),
('yuanqu-2334','六幺序','杨景贤','元','元曲','yuanqu','','[]','香馥郁销金帐，光灿烂白象床，俺两个破题儿待弄玉偷香。',114,'元曲/yuanqu.json','["香馥郁销金帐，光灿烂白象床，俺两个破题儿待弄玉偷香。", "听得说天地阴阳，自有纲常，人伦上下，不可孤孀。", "俺这里天生阴地无阳长，你何辜不近好婆娘？浮屠尽把三纲丧。", "(唐僧云)佛教自是一家。", "(女王云)说你那佛怎么？孔夫子文章贯世，天下传扬。"]'),
('yuanqu-2335','幺','杨景贤','元','元曲','yuanqu','','[]','你虽奉唐王，不看文章。',135,'元曲/yuanqu.json','["你虽奉唐王，不看文章。", "舜娶娥皇，不告爷娘。", "后代度量，孟子参详。", "他父母非良，兄弟参商，告废了人伦大纲，因此上自上张。", "你非比俗辈儿郎，没来由独锁空房。", "不从咱除是飞在天上，箭射下来也待成双。", "你若不肯呵，锁你在冷房子里，枉熬煎得你镜中白发三千丈。", "成就了一宵恩爱，索强似百世流芳。"]'),
('yuanqu-2336','金盏儿','杨景贤','元','元曲','yuanqu','','[]','披金甲貌堂堂，持宝杵气昂昂。',137,'元曲/yuanqu.json','["披金甲貌堂堂，持宝杵气昂昂。", "莫不是淹蓝桥烧祆庙的腌神将？比唐僧模样更非常。", "(韦云)吾神三十老，完为童子身。", "特来护法来。", "(女王云)又是个柳下惠、颜叔子。", "焦则么那村柳舍？叫则么那口吞颜郎？你整村了三十载，他干过了二十霜。", "(韦云)若不送师父出来，一杵打你做泥尘。", "(女王做放手科)。"]'),
('yuanqu-2337','尾','杨景贤','元','元曲','yuanqu','','[]','我无缘保的他无恙，闹炒起花烛洞房。',90,'元曲/yuanqu.json','["我无缘保的他无恙，闹炒起花烛洞房。", "怕甚么深院沉沉秋夜长，决撒了帽儿光光。", "恨韦郎，不做周方，我不道的恼乱苏州刺史肠。", "我如今去，我这里收拾下画堂，埋伏下兵将，等回来拿住再商量。", "(下)。"]'),
('yuanqu-2339','南吕/玉交枝','杨景贤','元','元曲','yuanqu','','[]','贪杯无厌，每日价汛流霞潋滟。',122,'元曲/yuanqu.json','["贪杯无厌，每日价汛流霞潋滟。", "子云嘲谑防微渐，托鸱夷彩笔拈。", "季鹰好饮豪兴添，忆莼鲈只为葡萄酽。", "倒玉山恁般瑕玷，又不是周晏相沾。", "糟腌着葛仙翁，曲埋那张孝廉。", "恣狂情，谁与砭？英雄尽你夸，富贵饶他占，则这黄垆畔有祸殃，玉缸边多危险，酒呵，播声名天下嫌。"]'),
('yuanqu-2340','幺','杨景贤','元','元曲','yuanqu','','[]','富豪的偏俭，奢华的无过是聚敛。',121,'元曲/yuanqu.json','["富豪的偏俭，奢华的无过是聚敛。", "王戎、郭况心无厌，拥金穴握牙签。", "可知道分金鲍叔廉，煞强如牢把铜山占。", "晋和峤也多褒贬，恰便是朱方聚歼。", "有齿的焚身，多财的要谦。", "斗量珠，树系缣，刑伤为美姝，杀伐因求剑。", "空有那万贯钱，到底来亡沟堑。", "财呵，播声名天下嫌。"]'),
('yuanqu-2341','醉乡春','杨景贤','元','元曲','yuanqu','','[]','打渔鼓高歌兴添，采灵芝快乐无厌。',48,'元曲/yuanqu.json','["打渔鼓高歌兴添，采灵芝快乐无厌。", "大叫高呼，前遮后掩。", "远量度，近观瞻，谨廉礼谦，休猜我做避世陶潜。"]'),
('yuanqu-2342','碧玉霄','杨景贤','元','元曲','yuanqu','','[]','瀑布签寒，涧落水帘，木绕山尖，猿啸虎张髯。',65,'元曲/yuanqu.json','["瀑布签寒，涧落水帘，木绕山尖，猿啸虎张髯。", "仗法力则可行，无神通休强参。", "将山色来瞻，似碧玉无瑕玷。", "苦辛不厌，大发慈悲念。", "师父趱行者。"]'),
('yuanqu-2343','随尾','杨景贤','元','元曲','yuanqu','','[]','玉鞭紧紧催金革占，火焰山千难万险。',37,'元曲/yuanqu.json','["玉鞭紧紧催金革占，火焰山千难万险。", "早求法力到西天，莫把残躯葬山崦。", "(下)。"]'),
('yuanqu-2344','正宫/端正好','杨景贤','元','元曲','yuanqu','','[]','我在巽宫里居，离宫里过，我直滚沙石撼动娑婆。',38,'元曲/yuanqu.json','["我在巽宫里居，离宫里过，我直滚沙石撼动娑婆。", "天长地久谁煞得我？把世界都参破。"]'),
('yuanqu-2345','滚绣球','杨景贤','元','元曲','yuanqu','','[]','孟婆是我教成，风神是我正果。',120,'元曲/yuanqu.json','["孟婆是我教成，风神是我正果。", "我和骊山老母是姊妹两个，我通风他通火。", "角木蛟、井木犴是叔伯亲，斗木獬、奎木狼是舅姑哥。", "当日宴蟠桃惹起这场灾祸，西王母道他金能欺风木催槎。", "当日个酒逢知己千钟少，话不投机一句多，死也待如何？俺这里铁嵯峰，好景致也呵。"]'),
('yuanqu-2346','倘秀才','杨景贤','元','元曲','yuanqu','','[]','明月照疏林花果，寒露滴空山薜萝。',42,'元曲/yuanqu.json','["明月照疏林花果，寒露滴空山薜萝。", "四面青山紧围裹，松梢闻鹤唳，洞门看猿过，与凡尘间阔。"]');
